        write_str(1, "     7.89%  [kernel]           timer_interrupt\n");
        write_str(1, "     6.34%  [kernel]           copy_to_user\n");
        write_str(1, "     5.12%  [kernel]           vfs_read\n");
        write_str(1, "     4.01%  [kernel]           kmalloc\n");
        write_str(1, "     3.28%  [kernel]           vfs_write\n");
