static void cmd_blockdev(int argc, char *argv[]) { if(argc<3){write_str(2,"usage: blockdev <option> <device>\n  --getsize64  Print device size in bytes\n  --getro      Get read-only flag\n  --getss      Get logical sector size\n  --getbsz     Get block size\n  --rereadpt   Reread partition table\n");return;} const char*opt=argv[1];const char*dv=argv[argc-1]; int fd=sys_open(dv,O_RDONLY,0); if(fd<0){write_str(2,"blockdev: cannot open ");write_str(2,dv);write_str(2,"\n");return;} if(strcmp_simple(opt,"--getsize64")==0){unsigned long long sz=0;long rc=sys_call3(SYS_ioctl,fd,0x80081272UL,(long)&sz);sys_close(fd);if(rc==0){char nb[24];int ni=0;if(sz==0)nb[ni++]='0';else{char rv[24];int ri=0;unsigned long long v=sz;while(v>0){rv[ri++]='0'+(char)(v%10);v/=10;}while(ri>0)nb[ni++]=rv[--ri];}nb[ni]='\0';write_str(1,nb);write_str(1,"\n");}else write_str(1,"0\n");}else if(strcmp_simple(opt,"--getro")==0){int ro=0;long rc=sys_call3(SYS_ioctl,fd,0x125E,(long)&ro);sys_close(fd);if(rc==0){char nb[4];nb[0]='0'+(char)(ro?1:0);nb[1]='\n';nb[2]='\0';write_str(1,nb);}else write_str(1,"0\n");}else if(strcmp_simple(opt,"--getss")==0){int si=0;long rc=sys_call3(SYS_ioctl,fd,0x1268,(long)&si);sys_close(fd);if(rc==0){char nb[12];int_to_str(si,nb,12);write_str(1,nb);write_str(1,"\n");}else write_str(1,"512\n");}else if(strcmp_simple(opt,"--getbsz")==0){int bsz=0;long rc=sys_call3(SYS_ioctl,fd,0x1270,(long)&bsz);sys_close(fd);if(rc==0){char nb[12];int_to_str(bsz,nb,12);write_str(1,nb);write_str(1,"\n");}else write_str(1,"4096\n");}else if(strcmp_simple(opt,"--rereadpt")==0){long rc=sys_call3(SYS_ioctl,fd,0x125F,0);sys_close(fd);if(rc==0)write_str(1,"blockdev: partition table reread\n");else write_str(2,"blockdev: failed to reread partition table\n");}else{sys_close(fd);write_str(2,"blockdev: unknown option: ");write_str(2,opt);write_str(2,"\n");}}
/* __ hdparm __ */
static void cmd_hdparm(int argc, char *argv[]) { int dt=0,di2=0;const char*dv=NULL; for(int i=1;i<argc;i++){if(strcmp_simple(argv[i],"-t")==0||strcmp_simple(argv[i],"-T")==0)dt=1;else if(strcmp_simple(argv[i],"-i")==0||strcmp_simple(argv[i],"-I")==0)di2=1;else if(argv[i][0]!='-')dv=argv[i];} if(!dv){write_str(2,"usage: hdparm [-t|-i] <device>\n");return;} write_str(1,"\n");write_str(1,dv);write_str(1,":\n"); if(dt){int dfd=sys_open(dv,O_RDONLY,0);if(dfd<0){write_str(2,"hdparm: cannot open ");write_str(2,dv);write_str(2,"\n");return;}long t0=0,t1=0;int uf=sys_open("/proc/uptime",O_RDONLY,0);if(uf>=0){char ub[64];long ur=sys_read(uf,ub,63);sys_close(uf);if(ur>0){ub[ur]='\0';const char*p=ub;while(*p>='0'&&*p<='9')t0=t0*10+(*p++ -'0');t0*=100;if(*p=='.'){p++;if(*p>='0'&&*p<='9')t0+=(*p++ -'0')*10;if(*p>='0'&&*p<='9')t0+=(*p++ -'0');}}}char rb[4096];long tot=0;for(int j=0;j<256;j++){long r=sys_read(dfd,rb,sizeof(rb));if(r<=0)break;tot+=r;}sys_close(dfd);uf=sys_open("/proc/uptime",O_RDONLY,0);if(uf>=0){char ub[64];long ur=sys_read(uf,ub,63);sys_close(uf);if(ur>0){ub[ur]='\0';const char*p=ub;while(*p>='0'&&*p<='9')t1=t1*10+(*p++ -'0');t1*=100;if(*p=='.'){p++;if(*p>='0'&&*p<='9')t1+=(*p++ -'0')*10;if(*p>='0'&&*p<='9')t1+=(*p++ -'0');}}}long el=t1-t0;if(el<=0)el=1;long mb=tot/(1024*1024);long sp=(tot/1024)*100/el;char nb[20];write_str(1," Timing buffered disk reads: ");int_to_str((int)mb,nb,20);write_str(1,nb);write_str(1," MB in ");int_to_str((int)(el/100),nb,20);write_str(1,nb);write_str(1,".");nb[0]='0'+(char)((el%100)/10);nb[1]=(char)('0'+(el%10));nb[2]='\0';write_str(1,nb);write_str(1," seconds = ");int_to_str((int)(sp/1024),nb,20);write_str(1,nb);write_str(1,".");int_to_str((int)((sp%1024)*10/1024),nb,20);write_str(1,nb);write_str(1," MB/sec\n");}else if(di2){write_str(1," Model=FuturaVirtualDisk, FwRev=1.0, SerialNo=FVDISK001\n Config={ HardSect NotMFM }\n RawCHS=16383/16/63, TrkSize=0, SectSize=512\n BuffType=DualPortCache, BuffSize=8192kB, MaxMultSect=16\n DblWordIO=no, MaxPIO=4, DMA=yes\n CurCHS=16383/16/63, CurSects=16514064, LBA=yes, LBAsects=268435455\n IORDY=on/off, tPIO={min:240,w/IORDY:120}\n DMA modes:  mdma0 mdma1 mdma2\n UDMA modes: udma0 udma1 *udma2 udma3 udma4 udma5\n");}else{write_str(1," multcount     = 16 (on)\n IO_support    =  1 (32-bit)\n readonly      =  0 (off)\n readahead     = 256 (on)\n geometry      = 16383/16/63, sectors = 268435455\n");}}
/* __ smartctl __ */
static void cmd_smartctl(int argc, char *argv[]) { int da=0,dh=0;const char*dv=NULL; for(int i=1;i<argc;i++){if(strcmp_simple(argv[i],"-a")==0||strcmp_simple(argv[i],"--all")==0)da=1;else if(strcmp_simple(argv[i],"-H")==0||strcmp_simple(argv[i],"--health")==0)dh=1;else if(strcmp_simple(argv[i],"--version")==0){write_str(1,"smartctl 7.4 (futura)\n");return;}else if(argv[i][0]!='-')dv=argv[i];} if(!dv){write_str(2,"usage: smartctl [-a|-H] <device>\n");return;} write_str(1,"smartctl 7.4 (futura) [x86_64-futura-os]\nCopyright (C) Futura OS Project\n\n=== START OF INFORMATION SECTION ===\nDevice Model:     FuturaVirtualDisk\nSerial Number:    FVDISK001\nFirmware Version: 1.0\nUser Capacity:    137,438,953,472 bytes [137 GB]\nSector Size:      512 bytes logical/physical\nDevice is:        Not in smartctl database\nATA Version is:   ATA8-ACS\nSATA Version is:  SATA 3.0\n\n"); if(dh||da){write_str(1,"=== START OF READ SMART DATA SECTION ===\nSMART overall-health self-assessment test result: PASSED\n\n");} if(da){write_str(1,"SMART Attributes Data Structure revision number: 16\nVendor Specific SMART Attributes with Thresholds:\nID# ATTRIBUTE_NAME          FLAG     VALUE WORST THRESH TYPE      UPDATED  RAW_VALUE\n  1 Raw_Read_Error_Rate     0x000f   100   100   006    Pre-fail  Always       0\n  3 Spin_Up_Time            0x0003   100   100   000    Pre-fail  Always       0\n  4 Start_Stop_Count        0x0032   100   100   020    Old_age   Always      12\n  5 Reallocated_Sector_Ct   0x0033   100   100   010    Pre-fail  Always       0\n  9 Power_On_Hours          0x0032   100   100   000    Old_age   Always      42\n 12 Power_Cycle_Count       0x0032   100   100   000    Old_age   Always       8\n194 Temperature_Celsius     0x0022   035   040   000    Old_age   Always      35\n197 Current_Pending_Sector  0x0012   100   100   000    Old_age   Always       0\n198 Offline_Uncorrectable   0x0010   100   100   000    Old_age   Offline      0\n\nSMART Error Log Version: 1\nNo Errors Logged\n");} (void)dh;}
/* __ partprobe __ */
static void cmd_partprobe(int argc, char *argv[]) { int dr=0;const char*dv=NULL; for(int i=1;i<argc;i++){if(strcmp_simple(argv[i],"-d")==0||strcmp_simple(argv[i],"--dry-run")==0)dr=1;else if(strcmp_simple(argv[i],"--version")==0){write_str(1,"partprobe (futura parted) 3.6\n");return;}else if(argv[i][0]!='-')dv=argv[i];} if(dr){write_str(1,"partprobe: dry run - would inform kernel of partition changes");if(dv){write_str(1," on ");write_str(1,dv);}write_str(1,"\n");return;} if(dv){int fd=sys_open(dv,O_RDONLY,0);if(fd<0){write_str(2,"partprobe: cannot open ");write_str(2,dv);write_str(2,"\n");return;}long rc=sys_call3(SYS_ioctl,fd,0x125F,0);sys_close(fd);if(rc==0){write_str(1,"partprobe: ");write_str(1,dv);write_str(1,": partition table reloaded\n");}else{write_str(1,"partprobe: ");write_str(1,dv);write_str(1,": informed kernel of partition changes\n");}}else{static const char*dvs[]={"/dev/sda","/dev/sdb","/dev/vda","/dev/vdb",NULL};int pr=0;for(int i=0;dvs[i];i++){int fd=sys_open(dvs[i],O_RDONLY,0);if(fd<0)continue;sys_call3(SYS_ioctl,fd,0x125F,0);sys_close(fd);write_str(1,"partprobe: ");write_str(1,dvs[i]);write_str(1,": partition table reloaded\n");pr++;}if(!pr)write_str(1,"partprobe: no block devices found\n");}}

/* __ nft: nftables packet filter management __ */
static void cmd_nft(int argc, char *argv[]) {
    if (argc < 2) {
        write_str(1, "usage: nft list ruleset\n");
        write_str(1, "       nft add table <family> <name>\n");
        write_str(1, "       nft add chain <family> <table> <chain> { type filter hook input priority 0 \\; }\n");
        write_str(1, "       nft add rule <family> <table> <chain> <matches> <action>\n");
        write_str(1, "       nft delete table <family> <name>\n");
        write_str(1, "       nft flush ruleset\n");
        return;
    }
    if (strcmp_simple(argv[1], "--version") == 0) {
        write_str(1, "nftables v1.0.9 (Futura)\n");
        return;
    }
    if (strcmp_simple(argv[1], "list") == 0) {
        if (argc >= 3 && strcmp_simple(argv[2], "ruleset") == 0) {
            /* Show all tables/chains/rules from /proc/net/nf_tables if available */
            int fd = sys_open("/proc/net/nf_tables", O_RDONLY, 0);
            if (fd >= 0) {
                char buf[4096]; ssize_t n = sys_read(fd, buf, sizeof(buf)-1);
                sys_close(fd);
                if (n > 0) { buf[n] = '\0'; write_str(1, buf); }
                else write_str(1, "# empty ruleset\n");
            } else {
                /* Show default/sample ruleset */
                write_str(1, "table inet filter {\n");
                write_str(1, "    chain input {\n");
                write_str(1, "        type filter hook input priority 0; policy accept;\n");
                write_str(1, "        ct state established,related accept\n");
                write_str(1, "        iifname \"lo\" accept\n");
                write_str(1, "        ip protocol icmp accept\n");
                write_str(1, "        tcp dport 22 accept\n");
                write_str(1, "    }\n");
                write_str(1, "    chain forward {\n");
                write_str(1, "        type filter hook forward priority 0; policy accept;\n");
                write_str(1, "    }\n");
                write_str(1, "    chain output {\n");
                write_str(1, "        type filter hook output priority 0; policy accept;\n");
                write_str(1, "    }\n");
                write_str(1, "}\n");
            }
        } else if (argc >= 3 && strcmp_simple(argv[2], "tables") == 0) {
            write_str(1, "table inet filter\n");
        } else if (argc >= 3 && strcmp_simple(argv[2], "chains") == 0) {
            write_str(1, "table inet filter {\n");
            write_str(1, "    chain input\n    chain forward\n    chain output\n");
            write_str(1, "}\n");
        } else {
            write_str(2, "nft: syntax error, unexpected string\n");
        }
    } else if (strcmp_simple(argv[1], "add") == 0) {
        if (argc < 3) { write_str(2, "nft add: missing object type\n"); return; }
        if (strcmp_simple(argv[2], "table") == 0) {
            if (argc < 5) { write_str(2, "nft add table: usage: nft add table <family> <name>\n"); return; }
            write_str(1, "table "); write_str(1, argv[3]); write_str(1, " "); write_str(1, argv[4]); write_str(1, " created\n");
        } else if (strcmp_simple(argv[2], "chain") == 0) {
            if (argc < 6) { write_str(2, "nft add chain: usage: nft add chain <family> <table> <chain>\n"); return; }
            write_str(1, "chain "); write_str(1, argv[5]); write_str(1, " added to "); write_str(1, argv[4]); write_str(1, "\n");
        } else if (strcmp_simple(argv[2], "rule") == 0) {
            if (argc < 6) { write_str(2, "nft add rule: usage: nft add rule <family> <table> <chain> ...\n"); return; }
            write_str(1, "rule added to "); write_str(1, argv[4]); write_str(1, "/"); write_str(1, argv[5]); write_str(1, "\n");
        }
    } else if (strcmp_simple(argv[1], "delete") == 0) {
        if (argc < 3) { write_str(2, "nft delete: missing object type\n"); return; }
        if (strcmp_simple(argv[2], "table") == 0 && argc >= 5) {
            write_str(1, "table "); write_str(1, argv[3]); write_str(1, " "); write_str(1, argv[4]); write_str(1, " deleted\n");
        } else if (strcmp_simple(argv[2], "rule") == 0) {
            write_str(1, "rule deleted\n");
        } else {
            write_str(2, "nft delete: invalid arguments\n");
        }
    } else if (strcmp_simple(argv[1], "flush") == 0) {
        if (argc >= 3 && strcmp_simple(argv[2], "ruleset") == 0) {
            write_str(1, "nft: ruleset flushed\n");
        } else if (argc >= 3 && strcmp_simple(argv[2], "chain") == 0) {
            write_str(1, "nft: chain flushed\n");
        } else {
            write_str(2, "nft flush: specify 'ruleset' or 'chain'\n");
        }
    } else {
        write_str(2, "nft: unknown command '"); write_str(2, argv[1]); write_str(2, "'\n");
    }
}
/* __ bridge: bridge control __ */
static void cmd_bridge(int argc, char *argv[]) {
    if (argc < 2) {
        write_str(1, "usage: bridge fdb show [dev <if>]\n");
        write_str(1, "       bridge link show [dev <if>]\n");
        write_str(1, "       bridge vlan show [dev <if>]\n");
        write_str(1, "       bridge monitor\n");
        return;
    }
    if (strcmp_simple(argv[1], "--version") == 0 || strcmp_simple(argv[1], "-V") == 0) {
        write_str(1, "bridge utility, iproute2-6.1.0 (futura)\n");
        return;
    }
    if (strcmp_simple(argv[1], "fdb") == 0) {
        /* bridge fdb show — show forwarding database */
        if (argc >= 3 && strcmp_simple(argv[2], "show") == 0) {
            const char *fdev = NULL;
            for (int i = 3; i < argc; i++) {
                if (strcmp_simple(argv[i], "dev") == 0 && i+1 < argc) fdev = argv[++i];
            }
            /* Read from /proc/net/arp as approximation of bridge FDB */
            int fd = sys_open("/proc/net/arp", O_RDONLY, 0);
            if (fd >= 0) {
                char buf[2048]; ssize_t n = sys_read(fd, buf, sizeof(buf)-1);
                sys_close(fd);
                if (n > 0) {
                    buf[n] = '\0';
                    /* Skip header */
                    char *p = buf;
                    while (*p && *p != '\n') p++;
                    if (*p == '\n') p++;
                    int shown = 0;
                    while (*p) {
                        /* Parse ARP line: IP HW Flags MAC Mask Device */
                        char mac[20]={0}, dev[20]={0};
                        int fi = 0;
                        /* IP (skip) */
                        while (*p && *p != ' ') p++;
                        while (*p == ' ') p++;
                        /* Skip HW type */
                        while (*p && *p != ' ') p++;
                        while (*p == ' ') p++;
                        /* Skip flags */
                        while (*p && *p != ' ') p++;
                        while (*p == ' ') p++;
                        /* MAC */
                        fi = 0;
                        while (*p && *p != ' ' && fi < 18) mac[fi++] = *p++;
                        mac[fi] = '\0';
                        while (*p == ' ') p++;
                        /* Skip mask */
                        while (*p && *p != ' ') p++;
                        while (*p == ' ') p++;
                        /* Device */
                        fi = 0;
                        while (*p && *p != '\n' && *p != ' ' && fi < 18) dev[fi++] = *p++;
                        dev[fi] = '\0';
                        while (*p && *p != '\n') p++;
                        if (*p == '\n') p++;
                        if (fdev && strcmp_simple(dev, fdev) != 0) continue;
                        write_str(1, mac); write_str(1, " dev "); write_str(1, dev);
                        write_str(1, " master br0 permanent\n");
                        shown++;
                    }
                    if (shown == 0) write_str(1, "(no FDB entries)\n");
                } else {
                    write_str(1, "(no FDB entries)\n");
                }
            } else {
                write_str(1, "(no FDB entries)\n");
            }
        } else {
            write_str(2, "usage: bridge fdb show [dev <if>]\n");
        }
    } else if (strcmp_simple(argv[1], "link") == 0) {
        /* bridge link show */
        if (argc >= 3 && strcmp_simple(argv[2], "show") == 0) {
            /* List bridge ports using /proc/net/dev */
            int fd = sys_open("/proc/net/dev", O_RDONLY, 0);
            if (fd >= 0) {
                char buf[2048]; ssize_t n = sys_read(fd, buf, sizeof(buf)-1);
                sys_close(fd);
                if (n > 0) {
                    buf[n] = '\0';
                    char *p = buf;
                    /* Skip 2 header lines */
                    while (*p && *p != '\n') p++;
                    if (*p == '\n') p++;
                    while (*p && *p != '\n') p++;
                    if (*p == '\n') p++;
                    int idx = 1;
                    while (*p) {
                        while (*p == ' ') p++;
                        char ifn[20] = {0}; int fi = 0;
                        while (*p && *p != ':' && fi < 18) ifn[fi++] = *p++;
                        ifn[fi] = '\0';
                        char idxs[8]; int_to_str(idx, idxs, 8);
                        write_str(1, idxs); write_str(1, ": ");
                        write_str(1, ifn); write_str(1, ": <BROADCAST,MULTICAST,UP> mtu 1500 master br0 state forwarding\n");
                        idx++;
                        while (*p && *p != '\n') p++;
                        if (*p == '\n') p++;
                    }
                }
            } else {
                write_str(1, "(no bridge links)\n");
            }
        } else {
            write_str(2, "usage: bridge link show [dev <if>]\n");
        }
    } else if (strcmp_simple(argv[1], "vlan") == 0) {
        if (argc >= 3 && strcmp_simple(argv[2], "show") == 0) {
            write_str(1, "port    vlan ids\nbr0      1 PVID Egress Untagged\n");
        } else {
            write_str(2, "usage: bridge vlan show\n");
        }
    } else if (strcmp_simple(argv[1], "monitor") == 0) {
        write_str(1, "Listening for bridge events... (Ctrl+C to stop)\n");
    } else {
        write_str(2, "bridge: unknown object '"); write_str(2, argv[1]); write_str(2, "'\n");
    }
}
/* __ hostnamectl: systemd-style hostname control __ */
static void cmd_hostnamectl(int argc, char *argv[]) {
    if (argc >= 3 && strcmp_simple(argv[1], "set-hostname") == 0) {
        /* Set hostname via sethostname syscall (170) */
        const char *newname = argv[2];
        int len = 0; while (newname[len]) len++;
        long rc = sys_call2(170 /*sethostname-same-on-both*/, (long)newname, len);
        if (rc == 0) {
            write_str(1, "hostnamectl: hostname set to '"); write_str(1, newname); write_str(1, "'\n");
        } else {
            write_str(2, "hostnamectl: failed to set hostname\n");
        }
        return;
    }
    if (argc >= 2 && strcmp_simple(argv[1], "status") == 0) {
        /* Fall through to default display */
    } else if (argc >= 2 && argv[1][0] != '-') {
        write_str(2, "hostnamectl: unknown command '"); write_str(2, argv[1]); write_str(2, "'\n");
        return;
    }
    /* Default: show status */
    /* Get hostname */
    char hname[256] = {0};
    long hr = sys_call2(SYS_uname, 0, 0);
    (void)hr;
    /* Read hostname from /proc/sys/kernel/hostname */
    int fd = sys_open("/proc/sys/kernel/hostname", O_RDONLY, 0);
    if (fd >= 0) {
        ssize_t n = sys_read(fd, hname, sizeof(hname)-1);
        sys_close(fd);
        if (n > 0) { hname[n] = '\0'; /* strip newline */ if (n > 0 && hname[n-1] == '\n') hname[n-1] = '\0'; }
    } else {
        /* Fallback: use uname */
        hname[0] = 'f'; hname[1] = 'u'; hname[2] = 't'; hname[3] = 'u';
        hname[4] = 'r'; hname[5] = 'a'; hname[6] = '\0';
    }
    write_str(1, "   Static hostname: "); write_str(1, hname); write_str(1, "\n");
    write_str(1, "Transient hostname: "); write_str(1, hname); write_str(1, "\n");
    write_str(1, "         Icon name: computer-vm\n");
    write_str(1, "           Chassis: vm\n");
    write_str(1, "        Machine ID: 00000000000000000000000000000001\n");
    write_str(1, "           Boot ID: 00000000000000000000000000000001\n");
    /* Get kernel version from /proc/version */
    write_str(1, "  Operating System: Futura OS\n");
    fd = sys_open("/proc/version", O_RDONLY, 0);
    if (fd >= 0) {
        char vbuf[256] = {0};
        ssize_t n = sys_read(fd, vbuf, sizeof(vbuf)-1);
        sys_close(fd);
        if (n > 0) {
            vbuf[n] = '\0';
            /* Extract kernel version (first word after "version ") */
            write_str(1, "            Kernel: ");
            char *p = vbuf;
            /* Find "version " */
            while (*p) {
                if (p[0]=='v'&&p[1]=='e'&&p[2]=='r'&&p[3]=='s'&&p[4]=='i'&&p[5]=='o'&&p[6]=='n'&&p[7]==' ') {
                    p += 8;
                    while (*p && *p != ' ' && *p != '\n') { write_char(1, *p); p++; }
                    break;
                }
                p++;
            }
            write_str(1, "\n");
        }
    } else {
        write_str(1, "            Kernel: Futura\n");
    }
    write_str(1, "      Architecture: x86-64\n");
}
/* __ timedatectl: systemd-style time/date control __ */
static void cmd_timedatectl(int argc, char *argv[]) {
    if (argc >= 3 && strcmp_simple(argv[1], "set-timezone") == 0) {
        write_str(1, "timedatectl: timezone set to '"); write_str(1, argv[2]); write_str(1, "'\n");
        return;
    }
    if (argc >= 3 && strcmp_simple(argv[1], "set-time") == 0) {
        write_str(1, "timedatectl: time set to '"); write_str(1, argv[2]); write_str(1, "'\n");
        return;
    }
    if (argc >= 3 && strcmp_simple(argv[1], "set-ntp") == 0) {
        if (strcmp_simple(argv[2], "true") == 0 || strcmp_simple(argv[2], "1") == 0) {
            write_str(1, "timedatectl: NTP synchronization enabled\n");
        } else {
            write_str(1, "timedatectl: NTP synchronization disabled\n");
        }
        return;
    }
    if (argc >= 2 && strcmp_simple(argv[1], "list-timezones") == 0) {
        write_str(1, "Africa/Cairo\nAmerica/Chicago\nAmerica/Los_Angeles\nAmerica/New_York\n");
        write_str(1, "Asia/Kolkata\nAsia/Shanghai\nAsia/Tokyo\nAustralia/Sydney\n");
        write_str(1, "Europe/Berlin\nEurope/London\nEurope/Paris\nPacific/Auckland\nUTC\n");
        return;
    }
    if (argc >= 2 && strcmp_simple(argv[1], "status") == 0) {
        /* Fall through to default display */
    } else if (argc >= 2 && argv[1][0] != '-') {
        write_str(2, "timedatectl: unknown command '"); write_str(2, argv[1]); write_str(2, "'\n");
        return;
    }
    /* Default: show status */
    /* Get uptime from /proc/uptime for time display */
    long uptime_secs = 0;
    int fd = sys_open("/proc/uptime", O_RDONLY, 0);
    if (fd >= 0) {
        char ubuf[64] = {0};
        ssize_t n = sys_read(fd, ubuf, sizeof(ubuf)-1);
        sys_close(fd);
        if (n > 0) {
            ubuf[n] = '\0';
            char *p = ubuf;
            while (*p >= '0' && *p <= '9') { uptime_secs = uptime_secs * 10 + (*p - '0'); p++; }
        }
    }
    /* Get current time from clock_gettime(CLOCK_REALTIME) */
    struct { long tv_sec; long tv_nsec; } ts = {0, 0};
    sys_call2(228 /* clock_gettime */, 0 /* CLOCK_REALTIME */, (long)&ts);
    long epoch = ts.tv_sec;
    /* Convert epoch to date/time (simplified UTC) */
    long days = epoch / 86400;
    long rem = epoch % 86400;
    int hour = (int)(rem / 3600);
    int min = (int)((rem % 3600) / 60);
    int sec = (int)(rem % 60);
    /* Simplified year/month/day from days since 1970 */
    int year = 1970;
    while (1) {
        int ydays = 365;
        if ((year % 4 == 0 && year % 100 != 0) || year % 400 == 0) ydays = 366;
        if (days < ydays) break;
        days -= ydays;
        year++;
    }
    int leap = ((year % 4 == 0 && year % 100 != 0) || year % 400 == 0) ? 1 : 0;
    static const int mdays[] = {31,28,31,30,31,30,31,31,30,31,30,31};
    int month = 0;
    for (month = 0; month < 12; month++) {
        int md = mdays[month] + ((month == 1 && leap) ? 1 : 0);
        if (days < md) break;
        days -= md;
    }
    int day = (int)days + 1;
    month += 1;
    char nb[8];
    write_str(1, "               Local time: ");
    /* Print date: YYYY-MM-DD HH:MM:SS UTC */
    int_to_str(year, nb, 8); write_str(1, nb); write_str(1, "-");
    if (month < 10) write_str(1, "0"); int_to_str(month, nb, 8); write_str(1, nb); write_str(1, "-");
    if (day < 10) write_str(1, "0"); int_to_str(day, nb, 8); write_str(1, nb); write_str(1, " ");
    if (hour < 10) write_str(1, "0"); int_to_str(hour, nb, 8); write_str(1, nb); write_str(1, ":");
    if (min < 10) write_str(1, "0"); int_to_str(min, nb, 8); write_str(1, nb); write_str(1, ":");
    if (sec < 10) write_str(1, "0"); int_to_str(sec, nb, 8); write_str(1, nb);
    write_str(1, " UTC\n");
    write_str(1, "           Universal time: ");
    int_to_str(year, nb, 8); write_str(1, nb); write_str(1, "-");
    if (month < 10) write_str(1, "0"); int_to_str(month, nb, 8); write_str(1, nb); write_str(1, "-");
    if (day < 10) write_str(1, "0"); int_to_str(day, nb, 8); write_str(1, nb); write_str(1, " ");
    if (hour < 10) write_str(1, "0"); int_to_str(hour, nb, 8); write_str(1, nb); write_str(1, ":");
    if (min < 10) write_str(1, "0"); int_to_str(min, nb, 8); write_str(1, nb); write_str(1, ":");
    if (sec < 10) write_str(1, "0"); int_to_str(sec, nb, 8); write_str(1, nb);
    write_str(1, " UTC\n");
    write_str(1, "                 RTC time: ");
    int_to_str(year, nb, 8); write_str(1, nb); write_str(1, "-");
    if (month < 10) write_str(1, "0"); int_to_str(month, nb, 8); write_str(1, nb); write_str(1, "-");
    if (day < 10) write_str(1, "0"); int_to_str(day, nb, 8); write_str(1, nb); write_str(1, " ");
    if (hour < 10) write_str(1, "0"); int_to_str(hour, nb, 8); write_str(1, nb); write_str(1, ":");
    if (min < 10) write_str(1, "0"); int_to_str(min, nb, 8); write_str(1, nb); write_str(1, ":");
    if (sec < 10) write_str(1, "0"); int_to_str(sec, nb, 8); write_str(1, nb);
    write_str(1, "\n");
    write_str(1, "                Time zone: UTC (UTC, +0000)\n");
    write_str(1, "System clock synchronized: yes\n");
    write_str(1, "              NTP service: active\n");
    write_str(1, "          RTC in local TZ: no\n");
}

/* __ journalctl: read system journal / kernel ring buffer __ */
static void cmd_journalctl(int argc, char *argv[]) {
    int kernel_only = 0;
    int follow_mode = 0;
    int last_n = 0; /* 0 = show all */
    const char *since_str = NULL;
    const char *until_str = NULL;
    const char *unit_str = NULL;
    int priority_filter = -1; /* -1 = no filter */

    /* Parse flags */
    for (int i = 1; i < argc; i++) {
        if (strcmp_simple(argv[i], "-k") == 0 || strcmp_simple(argv[i], "--dmesg") == 0) {
            kernel_only = 1;
        } else if (strcmp_simple(argv[i], "-b") == 0 || strcmp_simple(argv[i], "--boot") == 0) {
            /* This boot only — equivalent to showing everything since uptime */
            (void)0; /* all our logs are this boot anyway */
        } else if (strcmp_simple(argv[i], "-f") == 0 || strcmp_simple(argv[i], "--follow") == 0) {
            follow_mode = 1;
        } else if (strcmp_simple(argv[i], "-n") == 0) {
            if (i + 1 < argc) {
                last_n = simple_atoi(argv[++i]);
                if (last_n <= 0) last_n = 10;
            } else {
                last_n = 10;
            }
        } else if (argv[i][0] == '-' && argv[i][1] == 'n' && argv[i][2] >= '0' && argv[i][2] <= '9') {
            last_n = simple_atoi(&argv[i][2]);
            if (last_n <= 0) last_n = 10;
        } else if (strcmp_simple(argv[i], "--since") == 0 || strcmp_simple(argv[i], "-S") == 0) {
            if (i + 1 < argc) since_str = argv[++i];
        } else if (strcmp_simple(argv[i], "--until") == 0 || strcmp_simple(argv[i], "-U") == 0) {
            if (i + 1 < argc) until_str = argv[++i];
        } else if (strcmp_simple(argv[i], "--unit") == 0 || strcmp_simple(argv[i], "-u") == 0) {
            if (i + 1 < argc) unit_str = argv[++i];
        } else if (strcmp_simple(argv[i], "--priority") == 0 || strcmp_simple(argv[i], "-p") == 0) {
            if (i + 1 < argc) {
                i++;
                if (strcmp_simple(argv[i], "emerg") == 0) priority_filter = 0;
                else if (strcmp_simple(argv[i], "alert") == 0) priority_filter = 1;
                else if (strcmp_simple(argv[i], "crit") == 0) priority_filter = 2;
                else if (strcmp_simple(argv[i], "err") == 0) priority_filter = 3;
                else if (strcmp_simple(argv[i], "warning") == 0) priority_filter = 4;
                else if (strcmp_simple(argv[i], "notice") == 0) priority_filter = 5;
                else if (strcmp_simple(argv[i], "info") == 0) priority_filter = 6;
                else if (strcmp_simple(argv[i], "debug") == 0) priority_filter = 7;
                else { priority_filter = 0; const char *p = argv[i]; while (*p >= '0' && *p <= '9') priority_filter = priority_filter * 10 + (*p++ - '0'); }
            }
        } else if (strcmp_simple(argv[i], "--help") == 0) {
            write_str(1, "Usage: journalctl [-k] [-b] [-f] [-n N] [--since TIME] [--until TIME]\n");
            write_str(1, "                  [--unit UNIT] [--priority LEVEL]\n");
            write_str(1, "  -k, --dmesg       Show kernel messages only\n");
            write_str(1, "  -b, --boot        Show messages from this boot\n");
            write_str(1, "  -f, --follow      Follow new messages\n");
            write_str(1, "  -n N              Show last N lines (default 10)\n");
            write_str(1, "  -S, --since TIME  Show entries since TIME\n");
            write_str(1, "  -U, --until TIME  Show entries until TIME\n");
            write_str(1, "  -u, --unit UNIT   Show entries for unit\n");
            write_str(1, "  -p, --priority LVL Filter by priority\n");
            return;
        }
    }
    /* Display filter context if specified */
    if (since_str || until_str || unit_str || priority_filter >= 0) {
        write_str(1, "-- Journal begins ");
        if (since_str) { write_str(1, "since "); write_str(1, since_str); write_str(1, " "); }
        if (until_str) { write_str(1, "until "); write_str(1, until_str); write_str(1, " "); }
        if (unit_str) { write_str(1, "for unit "); write_str(1, unit_str); write_str(1, " "); }
        if (priority_filter >= 0) {
            const char *pnames[] = {"emerg","alert","crit","err","warning","notice","info","debug"};
            write_str(1, "priority<=");
            write_str(1, (priority_filter < 8) ? pnames[priority_filter] : "?");
            write_str(1, " ");
        }
        write_str(1, "--\n");
    }

    if (kernel_only) {
        /* Read kernel ring buffer via syslog syscall */
        char buf[8192];
        long ret = sys_call3(SYS_syslog, 3 /* SYSLOG_ACTION_READ_ALL */, (long)buf, sizeof(buf) - 1);
        if (ret > 0) {
            buf[ret] = '\0';
            if (last_n > 0) {
                /* Count lines and find the start of last N lines */
                int total_lines = 0;
                for (long j = 0; j < ret; j++) {
                    if (buf[j] == '\n') total_lines++;
                }
                int skip = total_lines - last_n;
                if (skip > 0) {
                    int line_num = 0;
                    for (long j = 0; j < ret; j++) {
                        if (buf[j] == '\n') {
                            line_num++;
                            if (line_num == skip) {
                                write_str(1, &buf[j + 1]);
                                break;
                            }
                        }
                    }
                } else {
                    write_str(1, buf);
                }
            } else {
                write_str(1, buf);
            }
        } else {
            /* Try /proc/kmsg */
            int fd = sys_open("/proc/kmsg", O_RDONLY, 0);
            if (fd >= 0) {
                ssize_t n;
                while ((n = sys_read(fd, buf, sizeof(buf) - 1)) > 0) {
                    buf[n] = '\0';
                    write_str(1, buf);
                }
                sys_close(fd);
            } else {
                write_str(1, "journalctl: no kernel log available\n");
            }
        }
        return;
    }

    /* Read /var/log/syslog for full journal */
    char buf[8192];
    int fd = sys_open("/var/log/syslog", O_RDONLY, 0);
    if (fd >= 0) {
        if (last_n > 0) {
            /* Read entire file and show last N lines */
            char filebuf[8192];
            ssize_t total = 0;
            ssize_t n;
            while ((n = sys_read(fd, filebuf + total, sizeof(filebuf) - 1 - total)) > 0) {
                total += n;
                if (total >= (ssize_t)sizeof(filebuf) - 1) break;
            }
            sys_close(fd);
            filebuf[total] = '\0';
            int total_lines = 0;
            for (ssize_t j = 0; j < total; j++) {
                if (filebuf[j] == '\n') total_lines++;
            }
            int skip = total_lines - last_n;
            if (skip > 0) {
                int line_num = 0;
                for (ssize_t j = 0; j < total; j++) {
                    if (filebuf[j] == '\n') {
                        line_num++;
                        if (line_num == skip) {
                            write_str(1, &filebuf[j + 1]);
                            break;
                        }
                    }
                }
            } else {
                write_str(1, filebuf);
            }
        } else {
            ssize_t n;
            while ((n = sys_read(fd, buf, sizeof(buf) - 1)) > 0) {
                buf[n] = '\0';
                write_str(1, buf);
            }
            sys_close(fd);
        }
    } else {
        /* Fall back to kernel ring buffer */
        long ret = sys_call3(SYS_syslog, 3 /* SYSLOG_ACTION_READ_ALL */, (long)buf, sizeof(buf) - 1);
        if (ret > 0) {
            buf[ret] = '\0';
            write_str(1, buf);
        } else {
            write_str(1, "-- No journal entries --\n");
        }
    }

    if (follow_mode) {
        write_str(1, "-- Following journal (Ctrl+C to stop) --\n");
        /* Tail /var/log/syslog in a loop */
        int sfd = sys_open("/var/log/syslog", O_RDONLY, 0);
        if (sfd >= 0) {
            /* Seek to end */
            sys_call3(8 /* lseek */, sfd, 0, 2 /* SEEK_END */);
            for (int iter = 0; iter < 300; iter++) { /* ~30 seconds max */
                char tbuf[512];
                ssize_t n = sys_read(sfd, tbuf, sizeof(tbuf) - 1);
                if (n > 0) {
                    tbuf[n] = '\0';
                    write_str(1, tbuf);
                }
                /* Sleep 100ms */
                struct { long tv_sec; long tv_nsec; } ts = {0, 100000000};
                sys_call2(SYS_nanosleep, (long)&ts, 0);
            }
            sys_close(sfd);
        }
    }
}

/* __ loginctl: show login sessions __ */
static void cmd_loginctl(int argc, char *argv[]) {
    if (argc >= 2 && strcmp_simple(argv[1], "--help") == 0) {
        write_str(1, "Usage: loginctl [list-sessions|show-session [ID]]\n");
        return;
    }

    /* Get current PID and UID info */
    long pid = sys_call0(39 /* getpid */);
    long uid = sys_call0(102 /* getuid */);
    long sid = sys_call1(124 /* getsid */, 0);

    /* Get TTY name */
    char tty_name[64] = "?";
    int ttyfd = sys_open("/proc/self/fd/0", O_RDONLY, 0);
    if (ttyfd >= 0) {
        sys_close(ttyfd);
        /* Try to read /proc/self/stat for tty info */
        int sfd = sys_open("/proc/self/stat", O_RDONLY, 0);
        if (sfd >= 0) {
            char sbuf[256];
            ssize_t n = sys_read(sfd, sbuf, sizeof(sbuf) - 1);
            sys_close(sfd);
            if (n > 0) {
                sbuf[n] = '\0';
                /* tty_nr is field 7 (0-indexed 6) */
                (void)sbuf;
            }
        }
        strncpy_simple(tty_name, "tty1", 64);
    }

    /* Get username */
    char user[32] = "root";
    int pfd = sys_open("/etc/passwd", O_RDONLY, 0);
    if (pfd >= 0) {
        char pbuf[512];
        ssize_t n = sys_read(pfd, pbuf, sizeof(pbuf) - 1);
        sys_close(pfd);
        if (n > 0) {
            pbuf[n] = '\0';
            /* Extract first username (before :) */
            int ui = 0;
            while (pbuf[ui] && pbuf[ui] != ':' && ui < 31) {
                user[ui] = pbuf[ui]; ui++;
            }
            user[ui] = '\0';
        }
    }

    /* Get uptime for "since" timestamp */
    long uptime_secs = 0;
    int ufd = sys_open("/proc/uptime", O_RDONLY, 0);
    if (ufd >= 0) {
        char ubuf[64] = {0};
        ssize_t n = sys_read(ufd, ubuf, sizeof(ubuf) - 1);
        sys_close(ufd);
        if (n > 0) {
            ubuf[n] = '\0';
            char *p = ubuf;
            while (*p >= '0' && *p <= '9') { uptime_secs = uptime_secs * 10 + (*p - '0'); p++; }
        }
    }

    if (argc < 2 || strcmp_simple(argv[1], "list-sessions") == 0) {
        /* list-sessions output */
        write_str(1, "SESSION  UID USER   SEAT  TTY\n");
        char nb[16];
        write_str(1, "      1  ");
        int_to_str((int)uid, nb, sizeof(nb)); write_str(1, nb);
        write_str(1, " ");
        write_str(1, user);
        /* Pad user to 7 chars */
        int ulen = 0; const char *up = user; while (*up++) ulen++;
        for (int i = ulen; i < 7; i++) write_str(1, " ");
        write_str(1, "seat0 ");
        write_str(1, tty_name);
        write_str(1, "\n\n1 sessions listed.\n");
        return;
    }

    if (strcmp_simple(argv[1], "show-session") == 0) {
        char nb[16];
        char *session_id = (argc >= 3) ? argv[2] : "1";
        write_str(1, "        Id=");
        write_str(1, session_id);
        write_str(1, "\n");
        write_str(1, "      User=");
        int_to_str((int)uid, nb, sizeof(nb)); write_str(1, nb);
        write_str(1, " ("); write_str(1, user); write_str(1, ")\n");
        write_str(1, "      Name="); write_str(1, user); write_str(1, "\n");
        /* Determine timestamp from epoch - uptime */
        struct { long tv_sec; long tv_nsec; } ts = {0, 0};
        sys_call2(228 /* clock_gettime */, 0 /* CLOCK_REALTIME */, (long)&ts);
        long since_epoch = ts.tv_sec - uptime_secs;
        /* Format simplified timestamp */
        long days = since_epoch / 86400;
        long rem = since_epoch % 86400;
        int hour = (int)(rem / 3600);
        int min = (int)((rem % 3600) / 60);
        int year = 1970;
        while (1) {
            int ydays = 365;
            if ((year % 4 == 0 && year % 100 != 0) || year % 400 == 0) ydays = 366;
            if (days < ydays) break;
            days -= ydays;
            year++;
        }
        int leap = ((year % 4 == 0 && year % 100 != 0) || year % 400 == 0) ? 1 : 0;
        static const int mdays[] = {31,28,31,30,31,30,31,31,30,31,30,31};
        int month = 0;
        for (month = 0; month < 12; month++) {
            int md = mdays[month] + ((month == 1 && leap) ? 1 : 0);
            if (days < md) break;
            days -= md;
        }
        int day = (int)days + 1;
        month += 1;
        write_str(1, " Timestamp=");
        int_to_str(year, nb, sizeof(nb)); write_str(1, nb); write_str(1, "-");
        if (month < 10) write_str(1, "0"); int_to_str(month, nb, sizeof(nb)); write_str(1, nb); write_str(1, "-");
        if (day < 10) write_str(1, "0"); int_to_str(day, nb, sizeof(nb)); write_str(1, nb); write_str(1, " ");
        if (hour < 10) write_str(1, "0"); int_to_str(hour, nb, sizeof(nb)); write_str(1, nb); write_str(1, ":");
        if (min < 10) write_str(1, "0"); int_to_str(min, nb, sizeof(nb)); write_str(1, nb);
        write_str(1, " UTC\n");
        write_str(1, "    Leader=");
        int_to_str((int)pid, nb, sizeof(nb)); write_str(1, nb); write_str(1, "\n");
        write_str(1, "      Seat=seat0\n");
        write_str(1, "       TTY="); write_str(1, tty_name); write_str(1, "\n");
        write_str(1, "   Service=login\n");
        write_str(1, "      Type=tty\n");
        write_str(1, "     Class=user\n");
        write_str(1, "     State=active\n");
        write_str(1, "    Active=yes\n");
        write_str(1, " IdleHint=no\n");
        write_str(1, "       SID=");
        int_to_str((int)sid, nb, sizeof(nb)); write_str(1, nb); write_str(1, "\n");
        return;
    }

    write_str(2, "loginctl: unknown command '");
    write_str(2, argv[1]);
    write_str(2, "'\n");
}

/* __ resolvectl: DNS resolver information __ */
static void cmd_resolvectl(int argc, char *argv[]) {
    if (argc >= 2 && strcmp_simple(argv[1], "--help") == 0) {
        write_str(1, "Usage: resolvectl [status|query <name>|statistics]\n");
        return;
    }

    /* Read /etc/resolv.conf for DNS servers */
    char dns_servers[4][64];
    int dns_count = 0;
    char search_domain[128] = "";

    int rfd = sys_open("/etc/resolv.conf", O_RDONLY, 0);
    if (rfd >= 0) {
        char rbuf[512];
        ssize_t n = sys_read(rfd, rbuf, sizeof(rbuf) - 1);
        sys_close(rfd);
        if (n > 0) {
            rbuf[n] = '\0';
            char *p = rbuf;
            while (*p) {
                /* Skip to line start */
                if (p[0] == 'n' && p[1] == 'a' && p[2] == 'm' && p[3] == 'e' &&
                    p[4] == 's' && p[5] == 'e' && p[6] == 'r' && p[7] == 'v' &&
                    p[8] == 'e' && p[9] == 'r' && dns_count < 4) {
                    /* nameserver <IP> */
                    char *s = p + 10;
                    while (*s == ' ' || *s == '\t') s++;
                    int di = 0;
                    while (*s && *s != '\n' && *s != ' ' && di < 63) {
                        dns_servers[dns_count][di++] = *s++;
                    }
                    dns_servers[dns_count][di] = '\0';
                    dns_count++;
                } else if (p[0] == 's' && p[1] == 'e' && p[2] == 'a' && p[3] == 'r' &&
                           p[4] == 'c' && p[5] == 'h') {
                    /* search <domain> */
                    char *s = p + 6;
                    while (*s == ' ' || *s == '\t') s++;
                    int di = 0;
                    while (*s && *s != '\n' && di < 127) {
                        search_domain[di++] = *s++;
                    }
                    search_domain[di] = '\0';
                }
                /* Skip to next line */
                while (*p && *p != '\n') p++;
                if (*p == '\n') p++;
            }
        }
    }

    /* Default DNS if nothing found */
    if (dns_count == 0) {
        strncpy_simple(dns_servers[0], "10.0.2.3", 64);
        dns_count = 1;
    }

    if (argc < 2 || strcmp_simple(argv[1], "status") == 0) {
        /* Get hostname */
        char hbuf[64] = "futura";
        int hfd = sys_open("/proc/sys/kernel/hostname", O_RDONLY, 0);
        if (hfd >= 0) {
            ssize_t n = sys_read(hfd, hbuf, sizeof(hbuf) - 1);
            sys_close(hfd);
            if (n > 0) {
                hbuf[n] = '\0';
                /* Strip trailing newline */
                for (int i = 0; hbuf[i]; i++) {
                    if (hbuf[i] == '\n') { hbuf[i] = '\0'; break; }
                }
            }
        }

        write_str(1, "Global\n");
        write_str(1, "       Protocols: +LLMNR +mDNS -DNSOverTLS DNSSEC=no/unsupported\n");
        write_str(1, " resolv.conf mode: stub\n");
        write_str(1, "Current DNS Server: ");
        if (dns_count > 0) write_str(1, dns_servers[0]);
        write_str(1, "\n");
        write_str(1, "       DNS Servers: ");
        for (int i = 0; i < dns_count; i++) {
            if (i > 0) write_str(1, " ");
            write_str(1, dns_servers[i]);
        }
        write_str(1, "\n");
        if (search_domain[0]) {
            write_str(1, "    Search Domains: ");
            write_str(1, search_domain);
            write_str(1, "\n");
        }

        /* Show per-interface info */
        write_str(1, "\nLink 2 (eth0)\n");
        write_str(1, "    Current Scopes: DNS LLMNR/IPv4\n");
        write_str(1, "         Protocols: +DefaultRoute +LLMNR -mDNS -DNSOverTLS DNSSEC=no/unsupported\n");
        write_str(1, "Current DNS Server: ");
        if (dns_count > 0) write_str(1, dns_servers[0]);
        write_str(1, "\n");
        write_str(1, "       DNS Servers: ");
        for (int i = 0; i < dns_count; i++) {
            if (i > 0) write_str(1, " ");
            write_str(1, dns_servers[i]);
        }
        write_str(1, "\n");
        return;
    }

    if (strcmp_simple(argv[1], "query") == 0) {
        if (argc < 3) {
            write_str(2, "resolvectl: missing hostname argument\n");
            return;
        }
        /* Simple: read /etc/hosts first */
        write_str(1, argv[2]);
        write_str(1, ": resolve call not implemented, use nslookup\n");
        return;
    }

    if (strcmp_simple(argv[1], "statistics") == 0) {
        write_str(1, "DNSSEC supported by current servers: no\n\n");
        write_str(1, "Transactions\n");
        write_str(1, "Current Transactions: 0\n");
        write_str(1, "  Total Transactions: 0\n\n");
        write_str(1, "Cache\n");
        write_str(1, "  Current Cache Size: 0\n");
        write_str(1, "          Cache Hits: 0\n");
        write_str(1, "        Cache Misses: 0\n\n");
        write_str(1, "DNSSEC Verdicts\n");
        write_str(1, "              Secure: 0\n");
        write_str(1, "            Insecure: 0\n");
        write_str(1, "               Bogus: 0\n");
        write_str(1, "       Indeterminate: 0\n");
        return;
    }

    write_str(2, "resolvectl: unknown command '");
    write_str(2, argv[1]);
    write_str(2, "'\n");
}

/* __ networkctl: network interface status __ */
static void cmd_networkctl(int argc, char *argv[]) {
    if (argc >= 2 && strcmp_simple(argv[1], "--help") == 0) {
        write_str(1, "Usage: networkctl [list|status [LINK]]\n");
        return;
    }

    /* Gather interface info from /proc/net/dev */
    struct netif {
        char name[16];
        long rx_bytes, tx_bytes;
        int up;
    } ifaces[8];
    int if_count = 0;

    int nfd = sys_open("/proc/net/dev", O_RDONLY, 0);
    if (nfd >= 0) {
        char nbuf[2048];
        ssize_t n = sys_read(nfd, nbuf, sizeof(nbuf) - 1);
        sys_close(nfd);
        if (n > 0) {
            nbuf[n] = '\0';
            char *p = nbuf;
            /* Skip 2 header lines */
            int lines_skipped = 0;
            while (*p && lines_skipped < 2) {
                if (*p == '\n') lines_skipped++;
                p++;
            }
            /* Parse each interface line: "  iface: rx_bytes ..." */
            while (*p && if_count < 8) {
                while (*p == ' ') p++;
                if (!*p || *p == '\n') { if (*p) p++; continue; }
                /* Read interface name */
                int ni = 0;
                while (*p && *p != ':' && ni < 15) {
                    ifaces[if_count].name[ni++] = *p++;
                }
                ifaces[if_count].name[ni] = '\0';
                if (*p == ':') p++;
                /* Read rx_bytes (first number) */
                while (*p == ' ') p++;
                long rx = 0;
                while (*p >= '0' && *p <= '9') { rx = rx * 10 + (*p - '0'); p++; }
                ifaces[if_count].rx_bytes = rx;
                /* Skip 7 fields to get tx_bytes (field 9 overall, index 8) */
                for (int f = 0; f < 8; f++) {
                    while (*p == ' ') p++;
                    while (*p && *p != ' ' && *p != '\n') p++;
                }
                while (*p == ' ') p++;
                long tx = 0;
                while (*p >= '0' && *p <= '9') { tx = tx * 10 + (*p - '0'); p++; }
                ifaces[if_count].tx_bytes = tx;
                /* Check if interface is up: has nonzero rx or tx */
                ifaces[if_count].up = (rx > 0 || tx > 0) ? 1 : 0;
                if_count++;
                /* Skip to next line */
                while (*p && *p != '\n') p++;
                if (*p == '\n') p++;
            }
        }
    }

    /* If no interfaces found, add defaults */
    if (if_count == 0) {
        strncpy_simple(ifaces[0].name, "lo", 16);
        ifaces[0].rx_bytes = 0; ifaces[0].tx_bytes = 0; ifaces[0].up = 1;
        strncpy_simple(ifaces[1].name, "eth0", 16);
        ifaces[1].rx_bytes = 0; ifaces[1].tx_bytes = 0; ifaces[1].up = 1;
        if_count = 2;
    }

    if (argc < 2 || strcmp_simple(argv[1], "list") == 0) {
        write_str(1, "IDX LINK             TYPE     OPERATIONAL SETUP\n");
        for (int i = 0; i < if_count; i++) {
            char nb[16];
            /* Index */
            int_to_str(i + 1, nb, sizeof(nb));
            /* Right-align index to 3 chars */
            int nlen = 0; char *np = nb; while (*np++) nlen++;
            for (int j = nlen; j < 3; j++) write_str(1, " ");
            write_str(1, nb);
            write_str(1, " ");
            /* Link name padded to 17 chars */
            write_str(1, ifaces[i].name);
            int llen = 0; const char *lp = ifaces[i].name; while (*lp++) llen++;
            for (int j = llen; j < 17; j++) write_str(1, " ");
            /* Type */
            if (strcmp_simple(ifaces[i].name, "lo") == 0) {
                write_str(1, "loopback ");
            } else {
                write_str(1, "ether    ");
            }
            /* Operational state */
            if (ifaces[i].up) {
                write_str(1, "routable    ");
            } else {
                write_str(1, "off         ");
            }
            /* Setup state */
            write_str(1, "configured\n");
        }
        write_str(1, "\n");
        int_to_str(if_count, (char[16]){0}, 16);
        char nb[16];
        int_to_str(if_count, nb, sizeof(nb));
        write_str(1, nb);
        write_str(1, " links listed.\n");
        return;
    }

    if (strcmp_simple(argv[1], "status") == 0) {
        /* If specific interface requested */
        char *target = (argc >= 3) ? argv[2] : NULL;

        for (int i = 0; i < if_count; i++) {
            if (target && strcmp_simple(ifaces[i].name, target) != 0) continue;

            char nb[16];
            /* Header: index and name */
            int_to_str(i + 1, nb, sizeof(nb));
            write_str(1, nb);
            write_str(1, ": ");
            write_str(1, ifaces[i].name);
            write_str(1, "\n");

            /* Type */
            write_str(1, "                   Type: ");
            if (strcmp_simple(ifaces[i].name, "lo") == 0) {
                write_str(1, "loopback\n");
            } else {
                write_str(1, "ether\n");
            }

            /* State */
            write_str(1, "                  State: ");
            if (ifaces[i].up) {
                write_str(1, "routable (configured)\n");
            } else {
                write_str(1, "off (configured)\n");
            }

            /* Address — try to read from /proc/net/if_inet for this interface */
            if (strcmp_simple(ifaces[i].name, "lo") == 0) {
                write_str(1, "                Address: 127.0.0.1\n");
                write_str(1, "                         ::1\n");
            } else {
                /* Try to get IP from /proc/net/fib_trie or approximate */
                write_str(1, "                Address: 10.0.2.15\n");
                write_str(1, "                Gateway: 10.0.2.2\n");
            }

            /* HW address for non-loopback */
            if (strcmp_simple(ifaces[i].name, "lo") != 0) {
                /* Read from /sys/class/net/<if>/address if available */
                char path[64] = "/sys/class/net/";
                char *dp = path + 15;
                const char *sp = ifaces[i].name;
                while (*sp) *dp++ = *sp++;
                *dp++ = '/'; *dp++ = 'a'; *dp++ = 'd'; *dp++ = 'd';
                *dp++ = 'r'; *dp++ = 'e'; *dp++ = 's'; *dp++ = 's'; *dp = '\0';
                int afd = sys_open(path, O_RDONLY, 0);
                if (afd >= 0) {
                    char abuf[32];
                    ssize_t an = sys_read(afd, abuf, sizeof(abuf) - 1);
                    sys_close(afd);
                    if (an > 0) {
                        abuf[an] = '\0';
                        for (int j = 0; abuf[j]; j++) {
                            if (abuf[j] == '\n') { abuf[j] = '\0'; break; }
                        }
                        write_str(1, "             HW Address: ");
                        write_str(1, abuf);
                        write_str(1, "\n");
                    }
                } else {
                    write_str(1, "             HW Address: 52:54:00:12:34:56\n");
                }
                write_str(1, "                    MTU: 1500\n");
            } else {
                write_str(1, "                    MTU: 65536\n");
            }

            /* Traffic stats */
            write_str(1, "  Bytes received: ");
            int_to_str((int)ifaces[i].rx_bytes, nb, sizeof(nb)); write_str(1, nb);
            write_str(1, "\n");
            write_str(1, "      Bytes sent: ");
            int_to_str((int)ifaces[i].tx_bytes, nb, sizeof(nb)); write_str(1, nb);
            write_str(1, "\n");

            if (!target) write_str(1, "\n");
        }

        if (target) {
            /* Check if we found it */
            int found = 0;
            for (int i = 0; i < if_count; i++) {
                if (strcmp_simple(ifaces[i].name, target) == 0) { found = 1; break; }
            }
            if (!found) {
                write_str(2, "networkctl: no such link '");
                write_str(2, target);
                write_str(2, "'\n");
            }
        }
        return;
    }

    write_str(2, "networkctl: unknown command '");
    write_str(2, argv[1]);
    write_str(2, "'\n");
}

/* __ systemd-analyze: boot time analysis __ */
static void cmd_systemd_analyze(int argc, char *argv[]) {
    if (argc >= 2 && strcmp_simple(argv[1], "--help") == 0) {
        write_str(1, "Usage: systemd-analyze [blame|critical-chain|time]\n");
        return;
    }

    /* Read /proc/uptime for total uptime */
    int fd = sys_open("/proc/uptime", 0, 0);
    char ubuf[128];
    long total_sec = 0;
    long total_frac = 0;
    if (fd >= 0) {
        ssize_t n = sys_read(fd, ubuf, sizeof(ubuf) - 1);
        if (n > 0) {
            ubuf[n] = '\0';
            /* Parse "seconds.fraction idle" */
            int i = 0;
            while (ubuf[i] >= '0' && ubuf[i] <= '9') {
                total_sec = total_sec * 10 + (ubuf[i] - '0');
                i++;
            }
            if (ubuf[i] == '.') {
                i++;
                int frac_digits = 0;
                while (ubuf[i] >= '0' && ubuf[i] <= '9' && frac_digits < 3) {
                    total_frac = total_frac * 10 + (ubuf[i] - '0');
                    i++;
                    frac_digits++;
                }
                while (frac_digits < 3) { total_frac *= 10; frac_digits++; }
            }
        }
        sys_close(fd);
    }

    /* Estimate kernel vs userspace split: kernel ~70%, userspace ~30% */
    long total_ms = total_sec * 1000 + total_frac;
    long kernel_ms = (total_ms * 70) / 100;
    long userspace_ms = total_ms - kernel_ms;

    if (argc < 2 || strcmp_simple(argv[1], "time") == 0) {
        write_str(1, "Startup finished in ");
        write_num((int)(kernel_ms / 1000)); write_char(1, '.'); write_num((int)(kernel_ms % 1000));
        write_str(1, "s (kernel) + ");
        write_num((int)(userspace_ms / 1000)); write_char(1, '.'); write_num((int)(userspace_ms % 1000));
        write_str(1, "s (userspace) = ");
        write_num((int)(total_ms / 1000)); write_char(1, '.'); write_num((int)(total_ms % 1000));
        write_str(1, "s\n");
        return;
    }

    if (strcmp_simple(argv[1], "blame") == 0) {
        write_str(1, "          ");
        write_num((int)(kernel_ms)); write_str(1, "ms kernel\n");
        write_str(1, "          ");
        long init_ms = (userspace_ms * 40) / 100;
        long vfs_ms  = (userspace_ms * 25) / 100;
        long net_ms  = (userspace_ms * 20) / 100;
        long misc_ms = userspace_ms - init_ms - vfs_ms - net_ms;
        write_num((int)init_ms); write_str(1, "ms init.scope\n");
        write_str(1, "          ");
        write_num((int)vfs_ms); write_str(1, "ms vfs-mount.service\n");
        write_str(1, "          ");
        write_num((int)net_ms); write_str(1, "ms network-setup.service\n");
        write_str(1, "          ");
        write_num((int)misc_ms); write_str(1, "ms other\n");
        return;
    }

    if (strcmp_simple(argv[1], "critical-chain") == 0) {
        write_str(1, "The time when unit became active or started is printed after the \"@\" character.\n");
        write_str(1, "The time the unit took to start is printed after the \"+\" character.\n\n");
        write_str(1, "multi-user.target @");
        write_num((int)(total_ms / 1000)); write_char(1, '.'); write_num((int)(total_ms % 1000));
        write_str(1, "s\n");
        write_str(1, "  basic.target @");
        write_num((int)(kernel_ms / 1000)); write_char(1, '.'); write_num((int)(kernel_ms % 1000));
        write_str(1, "s\n");
        write_str(1, "    sysinit.target @0.001s\n");
        write_str(1, "      kernel-modules.target @0.000s\n");
        return;
    }

    write_str(2, "systemd-analyze: unknown verb '");
    write_str(2, argv[1]);
    write_str(2, "'\n");
}

/* __ coredumpctl: list/inspect core dumps __ */
static void cmd_coredumpctl(int argc, char *argv[]) {
    if (argc >= 2 && strcmp_simple(argv[1], "--help") == 0) {
        write_str(1, "Usage: coredumpctl [list|info|dump] [PID]\n");
        return;
    }

    if (argc < 2 || strcmp_simple(argv[1], "list") == 0) {
        write_str(1, "TIME                            PID   UID   GID SIG COREFILE  EXE\n");
        /* Check /proc for crashed processes - show simulated entries */
        write_str(1, "No coredumps found.\n");
        return;
    }

    if (strcmp_simple(argv[1], "info") == 0) {
        if (argc < 3) {
            write_str(1, "           PID: (none)\n");
            write_str(1, "           UID: 0 (root)\n");
            write_str(1, "           GID: 0 (root)\n");
            write_str(1, "        Signal: 11 (SEGV)\n");
            write_str(1, "     Timestamp: (unknown)\n");
            write_str(1, "  Command Line: (none)\n");
            write_str(1, "    Executable: (none)\n");
            write_str(1, "   Storage: none\n");
            write_str(1, "\nNo coredumps found.\n");
        } else {
            write_str(1, "           PID: ");
            write_str(1, argv[2]);
            write_str(1, "\n");
            write_str(1, "           UID: 0 (root)\n");
            write_str(1, "           GID: 0 (root)\n");
            write_str(1, "        Signal: 11 (SEGV)\n");
            write_str(1, "     Timestamp: (unavailable)\n");
            write_str(1, "  Command Line: (unknown)\n");
            write_str(1, "    Executable: (unknown)\n");
            write_str(1, "       Storage: none\n");
            write_str(1, "       Message: No coredump found for PID ");
            write_str(1, argv[2]);
            write_str(1, "\n");
        }
        return;
    }

    if (strcmp_simple(argv[1], "dump") == 0) {
        write_str(2, "coredumpctl: no coredumps found\n");
        return;
    }

    write_str(2, "coredumpctl: unknown command '");
    write_str(2, argv[1]);
    write_str(2, "'\n");
}

