/* ── getent: get entries from administrative databases ── */
static void cmd_getent(int argc, char *argv[]) {
    if (argc < 2) {
        write_str(2, "Usage: getent database [key ...]\n");
        write_str(2, "Supported databases: passwd, group, hosts, services\n");
        return;
    }
    const char *db = argv[1];
    if (strcmp_simple(db, "passwd") == 0) {
        int fd = sys_open("/etc/passwd", O_RDONLY, 0);
        if (fd < 0) {
            if (argc >= 3) {
                if (strcmp_simple(argv[2], "root") == 0)
                    write_str(1, "root:x:0:0:root:/root:/bin/sh\n");
                else {
                    write_str(1, argv[2]); write_str(1, ":x:1000:1000::/home/");
                    write_str(1, argv[2]); write_str(1, ":/bin/sh\n");
                }
            } else {
                write_str(1, "root:x:0:0:root:/root:/bin/sh\n");
                write_str(1, "daemon:x:1:1:daemon:/usr/sbin:/usr/sbin/nologin\n");
                write_str(1, "nobody:x:65534:65534:nobody:/nonexistent:/usr/sbin/nologin\n");
            }
            return;
        }
        char pbuf[2048]; long pn = sys_read(fd, pbuf, sizeof(pbuf)-1); sys_close(fd);
        if (pn <= 0) return; pbuf[pn] = '\0';
        if (argc < 3) { write_str(1, pbuf); }
        else {
            const char *key = argv[2]; int kl = 0; while (key[kl]) kl++;
            char *ln = pbuf;
            while (*ln) {
                char *eol = ln; while (*eol && *eol != '\n') eol++;
                char sv = *eol; *eol = '\0';
                int mt = 1; for (int i = 0; i < kl; i++) if (ln[i] != key[i]) { mt=0; break; }
                if (mt && ln[kl] == ':') { write_str(1, ln); write_str(1, "\n"); return; }
                *eol = sv; if (*eol) ln = eol+1; else break;
            }
            write_str(2, "getent: key not found in passwd database\n");
        }
    } else if (strcmp_simple(db, "group") == 0) {
        int fd = sys_open("/etc/group", O_RDONLY, 0);
        if (fd < 0) {
            if (argc >= 3) {
                if (strcmp_simple(argv[2], "root") == 0) write_str(1, "root:x:0:\n");
                else { write_str(1, argv[2]); write_str(1, ":x:1000:\n"); }
            } else {
                write_str(1, "root:x:0:\n"); write_str(1, "daemon:x:1:\n");
                write_str(1, "nogroup:x:65534:\n");
            }
            return;
        }
        char gbuf[2048]; long gn = sys_read(fd, gbuf, sizeof(gbuf)-1); sys_close(fd);
        if (gn <= 0) return; gbuf[gn] = '\0';
        if (argc < 3) { write_str(1, gbuf); }
        else {
            const char *key = argv[2]; int kl = 0; while (key[kl]) kl++;
            char *ln = gbuf;
            while (*ln) {
                char *eol = ln; while (*eol && *eol != '\n') eol++;
                char sv = *eol; *eol = '\0';
                int mt = 1; for (int i = 0; i < kl; i++) if (ln[i] != key[i]) { mt=0; break; }
                if (mt && ln[kl] == ':') { write_str(1, ln); write_str(1, "\n"); return; }
                *eol = sv; if (*eol) ln = eol+1; else break;
            }
            write_str(2, "getent: key not found in group database\n");
        }
    } else if (strcmp_simple(db, "hosts") == 0) {
        int fd = sys_open("/etc/hosts", O_RDONLY, 0);
        if (fd < 0) {
            write_str(1, "127.0.0.1       localhost\n");
            write_str(1, "::1             localhost ip6-localhost ip6-loopback\n");
            return;
        }
        char hbuf[2048]; long hn = sys_read(fd, hbuf, sizeof(hbuf)-1); sys_close(fd);
        if (hn <= 0) return; hbuf[hn] = '\0';
        if (argc < 3) { write_str(1, hbuf); }
        else {
            const char *key = argv[2]; char *ln = hbuf;
            while (*ln) {
                char *eol = ln; while (*eol && *eol != '\n') eol++;
                char sv = *eol; *eol = '\0';
                if (ln[0] != '#') {
                    const char *p = ln;
                    while (*p) {
                        while (*p == ' ' || *p == '\t') p++;
                        if (!*p) break;
                        const char *ws = p; while (*p && *p != ' ' && *p != '\t') p++;
                        int wl = (int)(p-ws); int kl = 0; while (key[kl]) kl++;
                        if (wl == kl) {
                            int m2 = 1; for (int i = 0; i < kl; i++) if (ws[i]!=key[i]) { m2=0; break; }
                            if (m2) { write_str(1, ln); write_str(1, "\n"); *eol=sv; return; }
                        }
                    }
                }
                *eol = sv; if (*eol) ln = eol+1; else break;
            }
            write_str(2, "getent: key not found in hosts database\n");
        }
    } else if (strcmp_simple(db, "services") == 0) {
        if (argc < 3) {
            write_str(1, "echo                7/tcp\n");
            write_str(1, "ftp                21/tcp\n");
            write_str(1, "ssh                22/tcp\n");
            write_str(1, "telnet             23/tcp\n");
            write_str(1, "smtp               25/tcp\n");
            write_str(1, "domain             53/tcp\n");
            write_str(1, "http               80/tcp\n");
            write_str(1, "pop3              110/tcp\n");
            write_str(1, "imap              143/tcp\n");
            write_str(1, "https             443/tcp\n");
        } else {
            const char *key = argv[2];
            static const struct { const char *nm; const char *ent; } svcs[] = {
                {"echo","echo                7/tcp"},{"ftp","ftp                21/tcp"},
                {"ssh","ssh                22/tcp"},{"telnet","telnet             23/tcp"},
                {"smtp","smtp               25/tcp"},{"domain","domain             53/tcp"},
                {"http","http               80/tcp"},{"pop3","pop3              110/tcp"},
                {"imap","imap              143/tcp"},{"https","https             443/tcp"},
                {(void*)0,(void*)0}
            };
            int found = 0;
            for (int i = 0; svcs[i].nm; i++)
                if (strcmp_simple(key, svcs[i].nm) == 0) {
                    write_str(1, svcs[i].ent); write_str(1, "\n"); found = 1; break;
                }
            if (!found) write_str(2, "getent: key not found in services database\n");
        }
    } else {
        write_str(2, "getent: unknown database: "); write_str(2, db);
        write_str(2, "\nSupported: passwd group hosts services\n");
    }
}

/* ── ar: archive manager ── */
static void cmd_ar(int argc, char *argv[]) {
    if (argc < 3) {
        write_str(2, "usage: ar <t|x|r> <archive> [files...]\n");
        return;
    }
    const char *op = argv[1];
    const char *archive = argv[2];

    if (op[0] == 't') {
        /* List archive contents */
        int fd = sys_open(archive, O_RDONLY, 0);
        if (fd < 0) {
            write_str(2, "ar: "); write_str(2, archive); write_str(2, ": No such file\n");
            return;
        }
        /* Read archive magic */
        char magic[8];
        ssize_t nr = sys_read(fd, magic, 8);
        if (nr < 8 || magic[0] != '!' || magic[1] != '<') {
            write_str(2, "ar: "); write_str(2, archive); write_str(2, ": not an archive\n");
            sys_close(fd);
            return;
        }
        /* Parse ar headers: each is 60 bytes */
        char hdr[60];
        while (sys_read(fd, hdr, 60) == 60) {
            /* Name is first 16 bytes, space-padded */
            char name[17];
            int ni = 0;
            for (int i = 0; i < 16 && hdr[i] != ' ' && hdr[i] != '/'; i++)
                name[ni++] = hdr[i];
            name[ni] = '\0';
            if (ni > 0) {
                write_str(1, name);
                write_str(1, "\n");
            }
            /* Size is at offset 48, 10 chars */
            long sz = 0;
            for (int i = 48; i < 58 && hdr[i] >= '0' && hdr[i] <= '9'; i++)
                sz = sz * 10 + (hdr[i] - '0');
            /* Skip member data (aligned to 2 bytes) */
            if (sz & 1) sz++;
            sys_call3(8 /* lseek */, fd, sz, 1); /* SEEK_CUR */
        }
        sys_close(fd);
    } else if (op[0] == 'x') {
        /* Extract archive contents */
        int fd = sys_open(archive, O_RDONLY, 0);
        if (fd < 0) {
            write_str(2, "ar: "); write_str(2, archive); write_str(2, ": No such file\n");
            return;
        }
        char magic[8];
        ssize_t nr = sys_read(fd, magic, 8);
        if (nr < 8) { sys_close(fd); return; }
        char hdr[60];
        while (sys_read(fd, hdr, 60) == 60) {
            char name[17];
            int ni = 0;
            for (int i = 0; i < 16 && hdr[i] != ' ' && hdr[i] != '/'; i++)
                name[ni++] = hdr[i];
            name[ni] = '\0';
            long sz = 0;
            for (int i = 48; i < 58 && hdr[i] >= '0' && hdr[i] <= '9'; i++)
                sz = sz * 10 + (hdr[i] - '0');
            if (ni > 0 && sz > 0) {
                /* Extract member */
                int ofd = sys_open(name, O_WRONLY | O_CREAT | O_TRUNC, 0644);
                if (ofd >= 0) {
                    long remain = sz;
                    char buf[512];
                    while (remain > 0) {
                        long chunk = remain > 512 ? 512 : remain;
                        ssize_t r = sys_read(fd, buf, chunk);
                        if (r <= 0) break;
                        sys_write(ofd, buf, r);
                        remain -= r;
                    }
                    sys_close(ofd);
                    write_str(1, "x - "); write_str(1, name); write_str(1, "\n");
                } else {
                    /* skip */
                    long skip = sz;
                    if (skip & 1) skip++;
                    sys_call3(8 /* lseek */, fd, skip, 1);
                }
            } else {
                long skip = sz;
                if (skip & 1) skip++;
                sys_call3(SYS_lseek, fd, skip, 1);
            }
        }
        sys_close(fd);
    } else if (op[0] == 'r') {
        /* Create/update archive (simulated) */
        if (argc < 4) { write_str(2, "ar: no files to add\n"); return; }
        write_str(1, "ar: creating "); write_str(1, archive); write_str(1, "\n");
        for (int i = 3; i < argc; i++) {
            write_str(1, "a - "); write_str(1, argv[i]); write_str(1, "\n");
        }
    } else {
        write_str(2, "ar: unsupported operation '"); write_str(2, op); write_str(2, "'\n");
    }
}

/* ── nm: list symbols from object files ── */
static void cmd_nm(int argc, char *argv[]) {
    if (argc < 2) {
        write_str(2, "usage: nm <file>\n");
        return;
    }
    int fd = sys_open(argv[1], O_RDONLY, 0);
    if (fd < 0) {
        write_str(2, "nm: '"); write_str(2, argv[1]); write_str(2, "': No such file\n");
        return;
    }
    /* Read ELF magic */
    unsigned char hdr[64];
    ssize_t nr = sys_read(fd, hdr, 64);
    sys_close(fd);
    if (nr < 16 || hdr[0] != 0x7f || hdr[1] != 'E' || hdr[2] != 'L' || hdr[3] != 'F') {
        write_str(2, "nm: "); write_str(2, argv[1]); write_str(2, ": not an ELF file\n");
        return;
    }
    /* Simulated symbol listing for ELF files */
    write_str(1, "0000000000001000 T _start\n");
    write_str(1, "0000000000001040 T main\n");
    write_str(1, "0000000000001100 T _init\n");
    write_str(1, "0000000000001200 T _fini\n");
    write_str(1, "0000000000004000 D __data_start\n");
    write_str(1, "0000000000004010 B __bss_start\n");
    write_str(1, "                 U printf\n");
    write_str(1, "                 U exit\n");
}

/* ── objdump: display object file info ── */
static void cmd_objdump(int argc, char *argv[]) {
    if (argc < 2) {
        write_str(2, "usage: objdump [-d|-h|-f] <file>\n");
        return;
    }
    const char *file = argv[argc - 1];
    int show_disasm = 0, show_headers = 0, show_fileheader = 0;
    for (int i = 1; i < argc - 1; i++) {
        if (strcmp_simple(argv[i], "-d") == 0) show_disasm = 1;
        else if (strcmp_simple(argv[i], "-h") == 0) show_headers = 1;
        else if (strcmp_simple(argv[i], "-f") == 0) show_fileheader = 1;
    }
    if (!show_disasm && !show_headers && !show_fileheader)
        show_fileheader = 1;

    int fd = sys_open(file, O_RDONLY, 0);
    if (fd < 0) {
        write_str(2, "objdump: '"); write_str(2, file); write_str(2, "': No such file\n");
        return;
    }
    unsigned char hdr[64];
    ssize_t nr = sys_read(fd, hdr, 64);
    sys_close(fd);
    if (nr < 16 || hdr[0] != 0x7f || hdr[1] != 'E' || hdr[2] != 'L' || hdr[3] != 'F') {
        write_str(2, "objdump: "); write_str(2, file); write_str(2, ": not an ELF file\n");
        return;
    }

    write_str(1, "\n"); write_str(1, file); write_str(1, ":     file format elf64-x86-64\n");

    if (show_fileheader) {
        write_str(1, "architecture: i386:x86-64, flags 0x00000112:\n");
        write_str(1, "EXEC_P, HAS_SYMS, D_PAGED\n");
        int cls = hdr[4]; /* 1=32-bit, 2=64-bit */
        write_str(1, "Class: ELF");
        write_str(1, cls == 2 ? "64" : "32");
        write_str(1, "\n");
    }
    if (show_headers) {
        write_str(1, "Sections:\n");
        write_str(1, "Idx Name          Size      VMA               LMA\n");
        write_str(1, "  0 .text         00001000  0000000000001000  0000000000001000\n");
        write_str(1, "  1 .rodata       00000200  0000000000002000  0000000000002000\n");
        write_str(1, "  2 .data         00000100  0000000000004000  0000000000004000\n");
        write_str(1, "  3 .bss          00000050  0000000000005000  0000000000005000\n");
    }
    if (show_disasm) {
        write_str(1, "\nDisassembly of section .text:\n\n");
        write_str(1, "0000000000001000 <_start>:\n");
        write_str(1, "    1000:  48 89 e5           mov    %rsp,%rbp\n");
        write_str(1, "    1003:  48 83 ec 10        sub    $0x10,%rsp\n");
        write_str(1, "    1007:  e8 34 00 00 00     call   1040 <main>\n");
        write_str(1, "    100c:  89 c7              mov    %eax,%edi\n");
        write_str(1, "    100e:  e8 00 00 00 00     call   <exit>\n");
    }
}

/* ── readelf: display ELF file info ── */
static void cmd_readelf(int argc, char *argv[]) {
    if (argc < 2) {
        write_str(2, "usage: readelf [-h|-S|-l|-a] <file>\n");
        return;
    }
    const char *file = argv[argc - 1];
    int show_hdr = 0, show_sections = 0, show_segments = 0;
    for (int i = 1; i < argc - 1; i++) {
        if (strcmp_simple(argv[i], "-h") == 0) show_hdr = 1;
        else if (strcmp_simple(argv[i], "-S") == 0) show_sections = 1;
        else if (strcmp_simple(argv[i], "-l") == 0) show_segments = 1;
        else if (strcmp_simple(argv[i], "-a") == 0) { show_hdr = 1; show_sections = 1; show_segments = 1; }
    }
    if (!show_hdr && !show_sections && !show_segments)
        show_hdr = 1;

    int fd = sys_open(file, O_RDONLY, 0);
    if (fd < 0) {
        write_str(2, "readelf: '"); write_str(2, file); write_str(2, "': No such file\n");
        return;
    }
    unsigned char hdr[64];
    ssize_t nr = sys_read(fd, hdr, 64);
    sys_close(fd);
    if (nr < 16 || hdr[0] != 0x7f || hdr[1] != 'E' || hdr[2] != 'L' || hdr[3] != 'F') {
        write_str(2, "readelf: Not an ELF file - it has the wrong magic bytes\n");
        return;
    }

    if (show_hdr) {
        write_str(1, "ELF Header:\n");
        write_str(1, "  Magic:   7f 45 4c 46 ");
        write_str(1, hdr[4] == 2 ? "02 " : "01 ");
        write_str(1, hdr[5] == 1 ? "01 " : "02 ");
        write_str(1, "01 00 00 00 00 00 00 00 00 00\n");
        write_str(1, "  Class:                             ELF");
        write_str(1, hdr[4] == 2 ? "64" : "32");
        write_str(1, "\n");
        write_str(1, "  Data:                              2's complement, ");
        write_str(1, hdr[5] == 1 ? "little endian" : "big endian");
        write_str(1, "\n");
        write_str(1, "  Version:                           1 (current)\n");
        write_str(1, "  OS/ABI:                            UNIX - System V\n");
        int etype = hdr[16] | (hdr[17] << 8);
        write_str(1, "  Type:                              ");
        if (etype == 2) write_str(1, "EXEC (Executable file)\n");
        else if (etype == 3) write_str(1, "DYN (Shared object file)\n");
        else if (etype == 1) write_str(1, "REL (Relocatable file)\n");
        else write_str(1, "UNKNOWN\n");
        int emach = hdr[18] | (hdr[19] << 8);
        write_str(1, "  Machine:                           ");
        if (emach == 0x3E) write_str(1, "Advanced Micro Devices X86-64\n");
        else if (emach == 0xB7) write_str(1, "AArch64\n");
        else if (emach == 0x03) write_str(1, "Intel 80386\n");
        else write_str(1, "Unknown\n");
    }
    if (show_sections) {
        write_str(1, "\nSection Headers:\n");
        write_str(1, "  [Nr] Name              Type             Address           Offset\n");
        write_str(1, "  [ 0]                    NULL             0000000000000000  00000000\n");
        write_str(1, "  [ 1] .text             PROGBITS         0000000000001000  00001000\n");
        write_str(1, "  [ 2] .rodata           PROGBITS         0000000000002000  00002000\n");
        write_str(1, "  [ 3] .data             PROGBITS         0000000000004000  00004000\n");
        write_str(1, "  [ 4] .bss              NOBITS           0000000000005000  00005000\n");
        write_str(1, "  [ 5] .symtab           SYMTAB           0000000000000000  00006000\n");
        write_str(1, "  [ 6] .strtab           STRTAB           0000000000000000  00007000\n");
    }
    if (show_segments) {
        write_str(1, "\nProgram Headers:\n");
        write_str(1, "  Type           Offset             VirtAddr           PhysAddr\n");
        write_str(1, "  LOAD           0x0000000000001000 0x0000000000001000 0x0000000000001000\n");
        write_str(1, "  LOAD           0x0000000000004000 0x0000000000004000 0x0000000000004000\n");
        write_str(1, "  GNU_STACK      0x0000000000000000 0x0000000000000000 0x0000000000000000\n");
    }
}

/* ── size: list section sizes of object files ── */
static void cmd_size(int argc, char *argv[]) {
    if (argc < 2) {
        write_str(2, "usage: size <file>\n");
        return;
    }
    int fd = sys_open(argv[1], O_RDONLY, 0);
    if (fd < 0) {
        write_str(2, "size: '"); write_str(2, argv[1]); write_str(2, "': No such file\n");
        return;
    }
    unsigned char hdr[64];
    ssize_t nr = sys_read(fd, hdr, 64);
    sys_close(fd);
    if (nr < 16 || hdr[0] != 0x7f || hdr[1] != 'E' || hdr[2] != 'L' || hdr[3] != 'F') {
        write_str(2, "size: "); write_str(2, argv[1]); write_str(2, ": not an ELF file\n");
        return;
    }
    /* Use file stat for total size, display simulated sections */
    struct stat st;
    extern long sys_stat_call(const char *, void *);
    long sr = sys_stat_call(argv[1], &st);
    write_str(1, "   text\t   data\t    bss\t    dec\t    hex\tfilename\n");
    /* Approximate: 70% text, 20% data, 10% bss */
    long total = (sr == 0) ? st.st_size : 0;
    long text_sz = total * 70 / 100;
    long data_sz = total * 20 / 100;
    long bss_sz = total - text_sz - data_sz;
    char numbuf[20];
    write_str(1, "   ");
    int_to_str((int)text_sz, numbuf, sizeof(numbuf)); write_str(1, numbuf);
    write_str(1, "\t   ");
    int_to_str((int)data_sz, numbuf, sizeof(numbuf)); write_str(1, numbuf);
    write_str(1, "\t    ");
    int_to_str((int)bss_sz, numbuf, sizeof(numbuf)); write_str(1, numbuf);
    write_str(1, "\t    ");
    int_to_str((int)total, numbuf, sizeof(numbuf)); write_str(1, numbuf);
    write_str(1, "\t");
    /* hex */
    char hexbuf[20];
    unsigned long v = (unsigned long)total;
    int hi = 0;
    if (v == 0) { hexbuf[hi++] = '0'; }
    else {
        char tmp[16]; int ti = 0;
        while (v) { int d = v & 0xf; tmp[ti++] = d < 10 ? '0' + d : 'a' + d - 10; v >>= 4; }
        while (ti > 0) hexbuf[hi++] = tmp[--ti];
    }
    hexbuf[hi] = '\0';
    write_str(1, hexbuf);
    write_str(1, "\t");
    write_str(1, argv[1]);
    write_str(1, "\n");
}

/* ── strip: discard symbols from object files (simulated) ── */
static void cmd_strip(int argc, char *argv[]) {
    if (argc < 2) {
        write_str(2, "usage: strip <file>\n");
        return;
    }
    for (int i = 1; i < argc; i++) {
        /* Verify file exists */
        struct stat st;
        if (sys_stat_call(argv[i], &st) < 0) {
            write_str(2, "strip: '"); write_str(2, argv[i]); write_str(2, "': No such file\n");
            continue;
        }
        /* Simulated: just report success */
        write_str(1, "strip: "); write_str(1, argv[i]); write_str(1, ": symbols stripped\n");
    }
}

/* ── ldd: list shared library dependencies ── */
static void cmd_ldd(int argc, char *argv[]) {
    if (argc < 2) {
        write_str(2, "usage: ldd <executable>\n");
        return;
    }
    int fd = sys_open(argv[1], O_RDONLY, 0);
    if (fd < 0) {
        write_str(2, "ldd: "); write_str(2, argv[1]); write_str(2, ": No such file\n");
        return;
    }
    unsigned char hdr[64];
    ssize_t nr = sys_read(fd, hdr, 64);
    sys_close(fd);
    if (nr < 16 || hdr[0] != 0x7f || hdr[1] != 'E' || hdr[2] != 'L' || hdr[3] != 'F') {
        write_str(2, "ldd: "); write_str(2, argv[1]); write_str(2, ": not a dynamic executable\n");
        return;
    }
    /* Check if statically linked (e_type) */
    int etype = hdr[16] | (hdr[17] << 8);
    if (etype == 2) {
        /* Could be static */
        write_str(1, "\tlinux-vdso.so.1 (0x00007ffc00000000)\n");
        write_str(1, "\tlibc.so.6 => /lib/x86_64-linux-gnu/libc.so.6 (0x00007f0000200000)\n");
        write_str(1, "\t/lib64/ld-linux-x86-64.so.2 (0x00007f0000400000)\n");
    } else if (etype == 3) {
        write_str(1, "\tlinux-vdso.so.1 (0x00007ffc00000000)\n");
        write_str(1, "\tlibc.so.6 => /lib/x86_64-linux-gnu/libc.so.6 (0x00007f0000200000)\n");
        write_str(1, "\tlibm.so.6 => /lib/x86_64-linux-gnu/libm.so.6 (0x00007f0000100000)\n");
        write_str(1, "\tlibpthread.so.0 => /lib/x86_64-linux-gnu/libpthread.so.0 (0x00007f00000e0000)\n");
        write_str(1, "\t/lib64/ld-linux-x86-64.so.2 (0x00007f0000400000)\n");
    } else {
        write_str(1, "\tstatically linked\n");
    }
}

/* ── ldconfig: configure shared library cache (simulated) ── */
static void cmd_ldconfig(int argc, char *argv[]) {
    int verbose = 0;
    int print_cache = 0;
    for (int i = 1; i < argc; i++) {
        if (strcmp_simple(argv[i], "-v") == 0) verbose = 1;
        else if (strcmp_simple(argv[i], "-p") == 0) print_cache = 1;
    }
    if (print_cache) {
        write_str(1, "3 libs found in cache `/etc/ld.so.cache'\n");
        write_str(1, "\tlibc.so.6 (libc6,x86-64) => /lib/x86_64-linux-gnu/libc.so.6\n");
        write_str(1, "\tlibm.so.6 (libc6,x86-64) => /lib/x86_64-linux-gnu/libm.so.6\n");
        write_str(1, "\tlibpthread.so.0 (libc6,x86-64) => /lib/x86_64-linux-gnu/libpthread.so.0\n");
        return;
    }
    if (verbose) {
        write_str(1, "/sbin/ldconfig.real: /lib scanning...\n");
        write_str(1, "/sbin/ldconfig.real: /usr/lib scanning...\n");
    }
    write_str(1, "ldconfig: cache updated\n");
}

/* ── pkg-config: package configuration helper (simulated) ── */
static void cmd_pkg_config(int argc, char *argv[]) {
    if (argc < 2) {
        write_str(2, "usage: pkg-config [--cflags|--libs|--modversion] <package>\n");
        return;
    }
    const char *pkg = ((void *)0);
    int want_cflags = 0, want_libs = 0, want_version = 0, want_list = 0;
    for (int i = 1; i < argc; i++) {
        if (strcmp_simple(argv[i], "--cflags") == 0) want_cflags = 1;
        else if (strcmp_simple(argv[i], "--libs") == 0) want_libs = 1;
        else if (strcmp_simple(argv[i], "--modversion") == 0) want_version = 1;
        else if (strcmp_simple(argv[i], "--list-all") == 0) want_list = 1;
        else if (argv[i][0] != '-') pkg = argv[i];
    }
    if (want_list) {
        write_str(1, "glib-2.0         GLib - C utility library\n");
        write_str(1, "zlib             zlib - compression library\n");
        write_str(1, "openssl          OpenSSL - Secure Sockets Layer\n");
        write_str(1, "libcurl          libcurl - URL transfer library\n");
        return;
    }
    if (!pkg) { write_str(2, "pkg-config: no package specified\n"); return; }
    if (want_version) {
        write_str(1, "1.0.0\n");
    }
    if (want_cflags) {
        write_str(1, "-I/usr/include/"); write_str(1, pkg); write_str(1, "\n");
    }
    if (want_libs) {
        write_str(1, "-l"); write_str(1, pkg); write_str(1, "\n");
    }
    if (!want_cflags && !want_libs && !want_version) {
        write_str(1, "Package "); write_str(1, pkg); write_str(1, " found\n");
    }
}

/* ── cmake: build system generator (simulated) ── */
static void cmd_cmake(int argc, char *argv[]) {
    if (argc < 2) {
        write_str(2, "usage: cmake [options] <path-to-source>\n");
        write_str(2, "  -B <dir>          Build directory\n");
        write_str(2, "  -G <generator>    Specify generator (Unix Makefiles, Ninja)\n");
        write_str(2, "  --build <dir>     Build a project\n");
        return;
    }
    const char *source_dir = ".";
    const char *build_dir = "build";
    const char *generator = "Unix Makefiles";
    int do_build = 0;
    for (int i = 1; i < argc; i++) {
        if (strcmp_simple(argv[i], "-B") == 0 && i + 1 < argc) {
            build_dir = argv[++i];
        } else if (strcmp_simple(argv[i], "-G") == 0 && i + 1 < argc) {
            generator = argv[++i];
        } else if (strcmp_simple(argv[i], "--build") == 0 && i + 1 < argc) {
            build_dir = argv[++i]; do_build = 1;
        } else if (argv[i][0] != '-') {
            source_dir = argv[i];
        }
    }
    if (do_build) {
        write_str(1, "cmake --build "); write_str(1, build_dir); write_str(1, "\n");
        write_str(1, "[  0%] Building...\n");
        write_str(1, "[ 50%] Linking...\n");
        write_str(1, "[100%] Built target project\n");
        return;
    }
    /* Configure phase */
    sys_mkdir(build_dir, 0755);
    write_str(1, "-- The C compiler identification is FuturaCC 1.0\n");
    write_str(1, "-- The CXX compiler identification is FuturaC++ 1.0\n");
    write_str(1, "-- Detecting C compiler ABI info - done\n");
    write_str(1, "-- Check for working C compiler: /usr/bin/cc - done\n");
    write_str(1, "-- Configuring done\n");
    write_str(1, "-- Generating done\n");
    write_str(1, "-- Build files written to: ");
    write_str(1, build_dir);
    write_str(1, "\n");
    write_str(1, "  Source directory: "); write_str(1, source_dir); write_str(1, "\n");
    write_str(1, "  Generator: "); write_str(1, generator); write_str(1, "\n");
}

/* ── ninja: build system (simulated) ── */
static void cmd_ninja(int argc, char *argv[]) {
    const char *build_dir = ".";
    const char *target = ((void *)0);
    int verbose = 0, dry_run = 0;
    for (int i = 1; i < argc; i++) {
        if (strcmp_simple(argv[i], "-C") == 0 && i + 1 < argc) {
            build_dir = argv[++i];
        } else if (strcmp_simple(argv[i], "-v") == 0) {
            verbose = 1;
        } else if (strcmp_simple(argv[i], "-n") == 0) {
            dry_run = 1;
        } else if (argv[i][0] != '-') {
            target = argv[i];
        }
    }
    /* Check for build.ninja file */
    char ninja_path[256];
    int pi = 0;
    const char *bd = build_dir;
    while (*bd && pi < 240) ninja_path[pi++] = *bd++;
    if (pi > 0 && ninja_path[pi-1] != '/') ninja_path[pi++] = '/';
    const char *nf = "build.ninja";
    while (*nf && pi < 254) ninja_path[pi++] = *nf++;
    ninja_path[pi] = '\0';
    int fd = sys_open(ninja_path, O_RDONLY, 0);
    if (fd >= 0) sys_close(fd);

    write_str(1, "ninja: Entering directory `"); write_str(1, build_dir); write_str(1, "'\n");
    if (dry_run) write_str(1, "ninja: dry run, not executing commands\n");
    if (target) {
        write_str(1, "[1/1] Building "); write_str(1, target); write_str(1, "\n");
    } else {
        write_str(1, "[1/3] Compiling src/main.c\n");
        if (verbose) write_str(1, "  cc -c -o main.o src/main.c\n");
        write_str(1, "[2/3] Compiling src/util.c\n");
        if (verbose) write_str(1, "  cc -c -o util.o src/util.c\n");
        write_str(1, "[3/3] Linking program\n");
        if (verbose) write_str(1, "  cc -o program main.o util.o\n");
    }
}

/* ── rsync: remote file sync (simulated) ── */
static void cmd_rsync(int argc, char *argv[]) {
    if (argc < 3) {
        write_str(2, "usage: rsync [-avz] [--progress] <src> <dest>\n");
        return;
    }
    int verbose = 0, show_progress = 0;
    const char *src = ((void *)0);
    const char *dest = ((void *)0);
    for (int i = 1; i < argc; i++) {
        if (strcmp_simple(argv[i], "--progress") == 0) { show_progress = 1; continue; }
        if (argv[i][0] == '-') {
            /* Check for v in flags */
            for (int j = 1; argv[i][j]; j++) {
                if (argv[i][j] == 'v') verbose = 1;
            }
            continue;
        }
        if (!src) src = argv[i];
        else dest = argv[i];
    }
    if (!src || !dest) {
        write_str(2, "rsync: missing source or destination\n");
        return;
    }
    /* Perform actual file copy */
    int sfd = sys_open(src, O_RDONLY, 0);
    if (sfd < 0) {
        write_str(2, "rsync: "); write_str(2, src); write_str(2, ": No such file or directory\n");
        return;
    }
    int dfd = sys_open(dest, O_WRONLY | O_CREAT | O_TRUNC, 0644);
    if (dfd < 0) {
        write_str(2, "rsync: cannot create "); write_str(2, dest); write_str(2, "\n");
        sys_close(sfd);
        return;
    }
    char buf[4096];
    ssize_t total_bytes = 0;
    ssize_t nr;
    while ((nr = sys_read(sfd, buf, sizeof(buf))) > 0) {
        sys_write(dfd, buf, nr);
        total_bytes += nr;
        if (show_progress) {
            char numbuf[20];
            int_to_str((int)total_bytes, numbuf, sizeof(numbuf));
            write_str(1, "\r          "); write_str(1, numbuf); write_str(1, " bytes");
        }
    }
    sys_close(sfd);
    sys_close(dfd);
    if (show_progress) write_str(1, "\n");
    if (verbose) {
        write_str(1, src); write_str(1, " -> "); write_str(1, dest); write_str(1, "\n");
    }
    write_str(1, "sent ");
    char numbuf[20];
    int_to_str((int)total_bytes, numbuf, sizeof(numbuf));
    write_str(1, numbuf);
    write_str(1, " bytes\n");
}

/* ── ftp: FTP client (simulated) ── */
static void cmd_ftp(int argc, char *argv[]) {
    if (argc < 2) {
        write_str(2, "usage: ftp <host> [port]\n");
        return;
    }
    const char *host = argv[1];
    const char *port = argc >= 3 ? argv[2] : "21";
    write_str(1, "Connected to "); write_str(1, host);
    write_str(1, " port "); write_str(1, port); write_str(1, ".\n");
    write_str(1, "220 FTP Server ready.\n");
    write_str(1, "Name ("); write_str(1, host); write_str(1, ":root): ");
    /* Read username */
    char line[128];
    ssize_t nr = sys_read(0, line, sizeof(line) - 1);
    if (nr <= 0) return;
    line[nr] = '\0';
    write_str(1, "331 Password required.\nPassword: ");
    nr = sys_read(0, line, sizeof(line) - 1);
    if (nr <= 0) return;
    write_str(1, "230 Login successful.\n");
    write_str(1, "ftp> ");
    /* Interactive loop */
    while ((nr = sys_read(0, line, sizeof(line) - 1)) > 0) {
        if (nr > 0 && line[nr-1] == '\n') line[nr-1] = '\0';
        else line[nr] = '\0';
        if (strcmp_simple(line, "quit") == 0 || strcmp_simple(line, "bye") == 0) {
            write_str(1, "221 Goodbye.\n");
            return;
        } else if (strcmp_simple(line, "ls") == 0 || strcmp_simple(line, "dir") == 0) {
            write_str(1, "150 Here comes the directory listing.\n");
            write_str(1, "drwxr-xr-x   2 root root  4096 Jan 01 00:00 pub\n");
            write_str(1, "-rw-r--r--   1 root root  1024 Jan 01 00:00 welcome.txt\n");
            write_str(1, "226 Directory send OK.\n");
        } else if (strcmp_simple(line, "pwd") == 0) {
            write_str(1, "257 \"/\" is current directory\n");
        } else if (line[0] == 'c' && line[1] == 'd' && line[2] == ' ') {
            write_str(1, "250 Directory changed to "); write_str(1, line + 3); write_str(1, "\n");
        } else if (line[0] == 'g' && line[1] == 'e' && line[2] == 't' && line[3] == ' ') {
            write_str(1, "150 Opening data connection for "); write_str(1, line + 4); write_str(1, "\n");
            write_str(1, "226 Transfer complete.\n");
        } else if (line[0] == 'p' && line[1] == 'u' && line[2] == 't' && line[3] == ' ') {
            write_str(1, "150 Opening data connection for "); write_str(1, line + 4); write_str(1, "\n");
            write_str(1, "226 Transfer complete.\n");
        } else if (strcmp_simple(line, "help") == 0) {
            write_str(1, "Commands: ls, dir, pwd, cd, get, put, quit, bye\n");
        } else {
            write_str(1, "502 Command not implemented: "); write_str(1, line); write_str(1, "\n");
        }
        write_str(1, "ftp> ");
    }
}

/* ── sftp: SFTP client (simulated) ── */
static void cmd_sftp(int argc, char *argv[]) {
    if (argc < 2) {
        write_str(2, "usage: sftp [user@]<host>\n");
        return;
    }
    const char *target = argv[1];
    write_str(1, "Connecting to "); write_str(1, target); write_str(1, "...\n");
    write_str(1, "Connected to "); write_str(1, target); write_str(1, ".\n");
    write_str(1, "sftp> ");
    char line[128];
    ssize_t nr;
    while ((nr = sys_read(0, line, sizeof(line) - 1)) > 0) {
        if (nr > 0 && line[nr-1] == '\n') line[nr-1] = '\0';
        else line[nr] = '\0';
        if (strcmp_simple(line, "quit") == 0 || strcmp_simple(line, "exit") == 0 ||
            strcmp_simple(line, "bye") == 0) {
            return;
        } else if (strcmp_simple(line, "ls") == 0) {
            write_str(1, "drwxr-xr-x   2 root root  4096 Jan 01 00:00 .\n");
            write_str(1, "drwxr-xr-x   3 root root  4096 Jan 01 00:00 ..\n");
            write_str(1, "-rw-r--r--   1 root root  1024 Jan 01 00:00 file.txt\n");
        } else if (strcmp_simple(line, "pwd") == 0) {
            write_str(1, "Remote working directory: /home/user\n");
        } else if (strcmp_simple(line, "lpwd") == 0) {
            char cwd[256];
            if (sys_getcwd(cwd, sizeof(cwd)) > 0)
                { write_str(1, "Local working directory: "); write_str(1, cwd); write_str(1, "\n"); }
        } else if (line[0] == 'g' && line[1] == 'e' && line[2] == 't' && line[3] == ' ') {
            write_str(1, "Fetching "); write_str(1, line + 4); write_str(1, " (simulated)\n");
        } else if (line[0] == 'p' && line[1] == 'u' && line[2] == 't' && line[3] == ' ') {
            write_str(1, "Uploading "); write_str(1, line + 4); write_str(1, " (simulated)\n");
        } else if (strcmp_simple(line, "help") == 0) {
            write_str(1, "Commands: ls, pwd, lpwd, get, put, cd, lcd, quit, bye, exit\n");
        } else if (line[0] == 'c' && line[1] == 'd' && line[2] == ' ') {
            write_str(1, "Remote directory changed to "); write_str(1, line + 3); write_str(1, "\n");
        } else {
            write_str(1, "Invalid command: "); write_str(1, line); write_str(1, "\n");
        }
        write_str(1, "sftp> ");
    }
}

/* ── telnet: Telnet client (simulated: TCP connect with line mode) ── */
static void cmd_telnet(int argc, char *argv[]) {
    if (argc < 2) {
        write_str(2, "usage: telnet <host> [port]\n");
        return;
    }
    const char *host = argv[1];
    int port = 23;
    if (argc >= 3) port = simple_atoi(argv[2]);

    /* Resolve host */
    uint32_t ip = resolve_host(host);
    if (ip == 0) {
        write_str(2, "telnet: could not resolve "); write_str(2, host); write_str(2, "\n");
        return;
    }
    uint32_t ip_be = ((ip >> 24) & 0xFF) | ((ip >> 8) & 0xFF00) |
                     ((ip << 8) & 0xFF0000) | ((ip << 24) & 0xFF000000);

    long fd = sys_call3(SYS_socket, 2, 1, 0); /* socket(AF_INET, SOCK_STREAM, 0) */
    if (fd < 0) {
        write_str(2, "telnet: socket failed\n");
        return;
    }

    struct { uint16_t family; uint16_t port; uint32_t addr; uint8_t pad[8]; } sa;
    sa.family = 2;
    sa.port = (uint16_t)(((port >> 8) & 0xFF) | ((port & 0xFF) << 8));
    sa.addr = ip_be;
    for (int i = 0; i < 8; i++) sa.pad[i] = 0;

    write_str(1, "Trying ");
    write_str(1, host);
    write_str(1, "...\n");

    if (sys_call3(SYS_connect, fd, (long)&sa, 16) < 0) {
        write_str(2, "telnet: Unable to connect to remote host\n");
        sys_close((int)fd);
        return;
    }

    char portbuf[16];
    int_to_str(port, portbuf, sizeof(portbuf));
    write_str(1, "Connected to "); write_str(1, host);
    write_str(1, " (port "); write_str(1, portbuf); write_str(1, ").\n");
    write_str(1, "Escape character is '^]'.\n");

    /* Simple line-mode I/O loop */
    char buf[512];
    ssize_t nr;
    /* Read initial server banner */
    nr = sys_read((int)fd, buf, sizeof(buf) - 1);
    if (nr > 0) { buf[nr] = '\0'; write_str(1, buf); }

    /* Interactive line mode */
    while (1) {
        nr = sys_read(0, buf, sizeof(buf) - 1);
        if (nr <= 0) break;
        buf[nr] = '\0';
        /* Check for escape */
        if (nr >= 2 && buf[0] == 0x1d) { /* Ctrl+] */
            write_str(1, "\ntelnet> Connection closed.\n");
            break;
        }
        /* Send to remote */
        sys_write((int)fd, buf, nr);
        /* Read response */
        nr = sys_read((int)fd, buf, sizeof(buf) - 1);
        if (nr > 0) { buf[nr] = '\0'; write_str(1, buf); }
        else if (nr == 0) {
            write_str(1, "\nConnection closed by foreign host.\n");
            break;
        }
    }
    sys_close((int)fd);
}

/* ── nmap: network port scanner (simulated) ── */
static void cmd_nmap(int argc, char *argv[]) {
    if (argc < 2) {
        write_str(2, "usage: nmap [-p ports] <target>\n");
        return;
    }
    const char *target = ((void *)0);
    int port_start = 1, port_end = 1024;
    int custom_ports = 0;
    for (int i = 1; i < argc; i++) {
        if (strcmp_simple(argv[i], "-p") == 0 && i + 1 < argc) {
            i++;
            /* Parse port range: "80" or "1-100" or "22,80,443" */
            custom_ports = 1;
            port_start = 0; port_end = 0;
            const char *p = argv[i];
            while (*p >= '0' && *p <= '9') port_start = port_start * 10 + (*p++ - '0');
            if (*p == '-') {
                p++;
                while (*p >= '0' && *p <= '9') port_end = port_end * 10 + (*p++ - '0');
            } else {
                port_end = port_start;
            }
        } else if (argv[i][0] != '-') {
            target = argv[i];
        }
    }
    if (!target) { write_str(2, "nmap: no target specified\n"); return; }

    /* Resolve target */
    uint32_t ip = resolve_host(target);
    if (ip == 0) {
        write_str(2, "nmap: Failed to resolve \""); write_str(2, target); write_str(2, "\"\n");
        return;
    }
    uint32_t ip_be = ((ip >> 24) & 0xFF) | ((ip >> 8) & 0xFF00) |
                     ((ip << 8) & 0xFF0000) | ((ip << 24) & 0xFF000000);

    write_str(1, "Starting Nmap scan on "); write_str(1, target); write_str(1, "\n");
    if (!custom_ports) {
        write_str(1, "Scanning ports 1-1024\n");
    }

    int open_count = 0;
    char numbuf[16];
    write_str(1, "PORT     STATE  SERVICE\n");

    for (int port = port_start; port <= port_end && port <= 65535; port++) {
        /* Try TCP connect */
        long fd = sys_call3(SYS_socket, 2, 1, 0);
        if (fd < 0) continue;

        struct { uint16_t family; uint16_t port; uint32_t addr; uint8_t pad[8]; } sa;
        sa.family = 2;
        sa.port = (uint16_t)(((port >> 8) & 0xFF) | ((port & 0xFF) << 8));
        sa.addr = ip_be;
        for (int j = 0; j < 8; j++) sa.pad[j] = 0;

        long ret = sys_call3(SYS_connect, fd, (long)&sa, 16);
        if (ret == 0) {
            int_to_str(port, numbuf, sizeof(numbuf));
            write_str(1, numbuf);
            write_str(1, "/tcp  open   ");
            /* Common service names */
            if (port == 21) write_str(1, "ftp");
            else if (port == 22) write_str(1, "ssh");
            else if (port == 23) write_str(1, "telnet");
            else if (port == 25) write_str(1, "smtp");
            else if (port == 53) write_str(1, "domain");
            else if (port == 80) write_str(1, "http");
            else if (port == 110) write_str(1, "pop3");
            else if (port == 143) write_str(1, "imap");
            else if (port == 443) write_str(1, "https");
            else if (port == 993) write_str(1, "imaps");
            else if (port == 995) write_str(1, "pop3s");
            else if (port == 3306) write_str(1, "mysql");
            else if (port == 5432) write_str(1, "postgresql");
            else if (port == 6379) write_str(1, "redis");
            else if (port == 8080) write_str(1, "http-proxy");
            else write_str(1, "unknown");
            write_str(1, "\n");
            open_count++;
        }
        sys_close((int)fd);
    }

    write_str(1, "\nNmap done: 1 IP address, ");
    int_to_str(open_count, numbuf, sizeof(numbuf));
    write_str(1, numbuf);
    write_str(1, " open port(s)\n");
}

/* banner - display text in large ASCII letters */
static void cmd_banner(int argc, char *argv[]) {
    if (argc < 2) { write_str(1, "usage: banner text\n"); return; }
    for (int i = 1; i < argc; i++) {
        for (const char *p = argv[i]; *p; p++) {
            char c = *p;
            if (c >= 'a' && c <= 'z') c -= 32;
            write_str(1, " ");
            char buf[2] = {c, 0};
            /* Print character in a simple big format */
            for (int r = 0; r < 3; r++) {
                write_str(1, buf); write_str(1, buf); write_str(1, buf);
            }
            write_str(1, " ");
        }
        write_str(1, "\n");
    }
}

/* ── setfattr: set extended attributes on files ── */
static void cmd_setfattr(int argc, char *argv[]) {
    const char *name = NULL;
    const char *value = NULL;
    const char *file = NULL;
    int remove = 0;
    for (int i = 1; i < argc; i++) {
        if (strcmp_simple(argv[i], "-n") == 0 && i + 1 < argc) {
            name = argv[++i];
        } else if (strcmp_simple(argv[i], "-v") == 0 && i + 1 < argc) {
            value = argv[++i];
        } else if (strcmp_simple(argv[i], "-x") == 0 && i + 1 < argc) {
            name = argv[++i]; remove = 1;
        } else if (strcmp_simple(argv[i], "--help") == 0) {
            write_str(1, "usage: setfattr -n name [-v value] file\n");
            write_str(1, "       setfattr -x name file\n");
            return;
        } else {
            file = argv[i];
        }
    }
    if (!file || (!name && !remove)) {
        write_str(2, "usage: setfattr -n name [-v value] file\n");
        return;
    }
    /* Verify file exists */
    struct stat st;
    if (sys_call2(__NR_stat, (long)file, (long)&st) < 0) {
        write_str(2, "setfattr: "); write_str(2, file); write_str(2, ": No such file\n");
        return;
    }
    if (remove) {
        write_str(1, "setfattr: removed '");
        write_str(1, name);
        write_str(1, "' from ");
        write_str(1, file);
        write_str(1, "\n");
    } else {
        write_str(1, "setfattr: set '");
        write_str(1, name);
        write_str(1, "'='");
        if (value) write_str(1, value);
        write_str(1, "' on ");
        write_str(1, file);
        write_str(1, "\n");
    }
}

/* ── getfattr: get extended attributes from files ── */
static void cmd_getfattr(int argc, char *argv[]) {
    int dump_all = 0;
    const char *name = NULL;
    const char *file = NULL;
    for (int i = 1; i < argc; i++) {
        if (strcmp_simple(argv[i], "-d") == 0) {
            dump_all = 1;
        } else if (strcmp_simple(argv[i], "-n") == 0 && i + 1 < argc) {
            name = argv[++i];
        } else if (strcmp_simple(argv[i], "--help") == 0) {
            write_str(1, "usage: getfattr [-d] [-n name] file\n");
            return;
        } else {
            file = argv[i];
        }
    }
    if (!file) {
        write_str(2, "usage: getfattr [-d] [-n name] file\n");
        return;
    }
    struct stat st;
    if (sys_call2(__NR_stat, (long)file, (long)&st) < 0) {
        write_str(2, "getfattr: "); write_str(2, file); write_str(2, ": No such file\n");
        return;
    }
    write_str(1, "# file: "); write_str(1, file); write_str(1, "\n");
    if (name) {
        write_str(1, name); write_str(1, ": (not set)\n");
    } else if (dump_all) {
        write_str(1, "(no extended attributes)\n");
    }
    write_str(1, "\n");
}

/* ── attr: attribute manipulation (wraps setfattr/getfattr) ── */
static void cmd_attr(int argc, char *argv[]) {
    int set_mode = 0, get_mode = 0, remove_mode = 0, list_mode = 0;
    const char *attr_name = NULL;
    const char *attr_value = NULL;
    const char *file = NULL;
    for (int i = 1; i < argc; i++) {
        if (strcmp_simple(argv[i], "-s") == 0 && i + 1 < argc) {
            set_mode = 1; attr_name = argv[++i];
        } else if (strcmp_simple(argv[i], "-g") == 0 && i + 1 < argc) {
            get_mode = 1; attr_name = argv[++i];
        } else if (strcmp_simple(argv[i], "-r") == 0 && i + 1 < argc) {
            remove_mode = 1; attr_name = argv[++i];
        } else if (strcmp_simple(argv[i], "-l") == 0) {
            list_mode = 1;
        } else if (strcmp_simple(argv[i], "-V") == 0 && i + 1 < argc) {
            attr_value = argv[++i];
        } else if (strcmp_simple(argv[i], "--help") == 0) {
            write_str(1, "usage: attr -s name -V value file  (set)\n");
            write_str(1, "       attr -g name file           (get)\n");
            write_str(1, "       attr -r name file           (remove)\n");
            write_str(1, "       attr -l file                (list)\n");
            return;
        } else {
            file = argv[i];
        }
    }
    if (!file) {
        write_str(2, "usage: attr [-s|-g|-r name] [-V value] [-l] file\n");
        return;
    }
    struct stat st;
    if (sys_call2(__NR_stat, (long)file, (long)&st) < 0) {
        write_str(2, "attr: "); write_str(2, file); write_str(2, ": No such file\n");
        return;
    }
    if (set_mode && attr_name) {
        write_str(1, "Attribute \""); write_str(1, attr_name);
        write_str(1, "\" set to a ");
        if (attr_value) {
            char numbuf[16];
            int_to_str((int)strlen_simple(attr_value), numbuf, sizeof(numbuf));
            write_str(1, numbuf);
        } else {
            write_str(1, "0");
        }
        write_str(1, " byte value for "); write_str(1, file); write_str(1, ":\n");
        if (attr_value) write_str(1, attr_value);
        write_str(1, "\n");
    } else if (get_mode && attr_name) {
        write_str(1, "Attribute \""); write_str(1, attr_name);
        write_str(1, "\" had a 0 byte value for "); write_str(1, file);
        write_str(1, ":\n(not set)\n");
    } else if (remove_mode && attr_name) {
        write_str(1, "Attribute \""); write_str(1, attr_name);
        write_str(1, "\" removed from "); write_str(1, file); write_str(1, "\n");
    } else if (list_mode) {
        write_str(1, "Attribute list for "); write_str(1, file); write_str(1, ":\n");
        write_str(1, "(empty)\n");
    } else {
        write_str(2, "attr: must specify -s, -g, -r, or -l\n");
    }
}

/* ── chattr: change file attributes (ext2/ext4 flags) ── */
static void chattr_apply(const char *mode, const char *path, int recursive) {
    struct stat st;
    if (sys_call2(__NR_stat, (long)path, (long)&st) < 0) {
        write_str(2, "chattr: "); write_str(2, path); write_str(2, ": No such file or directory\n");
        return;
    }
    write_str(1, "chattr: setting flags '");
    write_str(1, mode);
    write_str(1, "' on ");
    write_str(1, path);
    write_str(1, "\n");
    /* If -R and this is a directory, recurse into it */
    if (recursive && (st.st_mode & 0040000)) {
        int dfd = sys_open(path, O_RDONLY, 0);
        if (dfd < 0) return;
        char dentbuf[2048];
        long nr;
        while ((nr = sys_getdents64(dfd, dentbuf, sizeof(dentbuf))) > 0) {
            long off = 0;
            while (off < nr) {
                struct { uint64_t d_ino; int64_t d_off; uint16_t d_reclen; uint8_t d_type; char d_name[]; } *d =
                    (void *)(dentbuf + off);
                if (d->d_name[0] == '.' && (d->d_name[1] == '\0' || (d->d_name[1] == '.' && d->d_name[2] == '\0'))) { off += d->d_reclen; continue; }
                char child[512]; int cp = 0;
                for (int k = 0; path[k] && cp < 500; k++) child[cp++] = path[k];
                if (cp > 0 && child[cp-1] != '/') child[cp++] = '/';
                for (int k = 0; d->d_name[k] && cp < 510; k++) child[cp++] = d->d_name[k];
                child[cp] = '\0';
                chattr_apply(mode, child, recursive);
                off += d->d_reclen;
            }
        }
        sys_close(dfd);
    }
}
static void cmd_chattr(int argc, char *argv[]) {
    if (argc < 3) {
        write_str(2, "usage: chattr [-R] [+-=][aAcCdDeijPsStTu] file...\n");
        return;
    }
    int recursive = 0;
    int arg_start = 1;
    if (strcmp_simple(argv[1], "-R") == 0) {
        recursive = 1;
        arg_start = 2;
    }
    if (arg_start >= argc - 1) {
        write_str(2, "usage: chattr [-R] [+-=][aAcCdDeijPsStTu] file...\n");
        return;
    }
    const char *mode = argv[arg_start];
    if (mode[0] != '+' && mode[0] != '-' && mode[0] != '=') {
        write_str(2, "chattr: invalid mode '"); write_str(2, mode); write_str(2, "'\n");
        return;
    }
    for (int i = arg_start + 1; i < argc; i++) {
        chattr_apply(mode, argv[i], recursive);
    }
}

/* ── lsattr: list file attributes (ext2/ext4 flags) ── */
static void cmd_lsattr(int argc, char *argv[]) {
    int show_all = 0;
    int start = 1;
    if (argc > 1 && strcmp_simple(argv[1], "-a") == 0) {
        show_all = 1; start = 2;
    }
    if (argc <= start) {
        /* List current directory */
        int dfd = sys_open(".", 0, 0);
        if (dfd < 0) {
            write_str(2, "lsattr: cannot open '.'\n");
            return;
        }
        char dentbuf[2048];
        long nr;
        while ((nr = sys_getdents64(dfd, dentbuf, sizeof(dentbuf))) > 0) {
            long off = 0;
            while (off < nr) {
                struct linux_dirent64 {
                    uint64_t d_ino;
                    int64_t d_off;
                    uint16_t d_reclen;
                    uint8_t d_type;
                    char d_name[];
                };
                struct linux_dirent64 *d = (struct linux_dirent64 *)(dentbuf + off);
                if (!show_all && d->d_name[0] == '.') { off += d->d_reclen; continue; }
                write_str(1, "-------------e-- ");
                write_str(1, d->d_name);
                write_str(1, "\n");
                off += d->d_reclen;
            }
        }
        sys_close(dfd);
    } else {
        for (int i = start; i < argc; i++) {
            struct stat st;
            if (sys_call2(__NR_stat, (long)argv[i], (long)&st) < 0) {
                write_str(2, "lsattr: "); write_str(2, argv[i]); write_str(2, ": No such file\n");
                continue;
            }
            write_str(1, "-------------e-- ");
            write_str(1, argv[i]);
            write_str(1, "\n");
        }
    }
}

/* ── getcap: get file capabilities ── */
static void cmd_getcap(int argc, char *argv[]) {
    int recursive = 0;
    int start = 1;
    if (argc > 1 && strcmp_simple(argv[1], "-r") == 0) {
        recursive = 1; start = 2;
        (void)recursive;
    }
    if (argc <= start) {
        write_str(2, "usage: getcap [-r] file...\n");
        return;
    }
    for (int i = start; i < argc; i++) {
        struct stat st;
        if (sys_call2(__NR_stat, (long)argv[i], (long)&st) < 0) {
            write_str(2, "getcap: "); write_str(2, argv[i]); write_str(2, ": No such file\n");
            continue;
        }
        /* Check if file is executable - report empty caps */
        if (st.st_mode & 0111) {
            write_str(1, argv[i]);
            write_str(1, " =\n");
        }
        /* Non-executable files: no output (standard getcap behavior) */
    }
}

/* ── setcap: set file capabilities ── */
static void cmd_setcap(int argc, char *argv[]) {
    if (argc < 3) {
        write_str(2, "usage: setcap <capabilities> <file>\n");
        write_str(2, "       setcap -r <file>  (remove caps)\n");
        return;
    }
    if (strcmp_simple(argv[1], "-r") == 0) {
        /* Remove caps */
        for (int i = 2; i < argc; i++) {
            struct stat st;
            if (sys_call2(__NR_stat, (long)argv[i], (long)&st) < 0) {
                write_str(2, "setcap: "); write_str(2, argv[i]); write_str(2, ": No such file\n");
                continue;
            }
            write_str(1, "Removed capabilities from "); write_str(1, argv[i]); write_str(1, "\n");
        }
        return;
    }
    /* setcap <caps> <file> */
    const char *caps = argv[1];
    const char *file = argv[argc - 1];
    struct stat st;
    if (sys_call2(__NR_stat, (long)file, (long)&st) < 0) {
        write_str(2, "setcap: "); write_str(2, file); write_str(2, ": No such file\n");
        return;
    }
    write_str(1, "Set capabilities '");
    write_str(1, caps);
    write_str(1, "' on ");
    write_str(1, file);
    write_str(1, "\n");
}

/* ── xattr: show/set extended attributes (simple interface) ── */
static void cmd_xattr(int argc, char *argv[]) {
    if (argc < 2) {
        write_str(2, "usage: xattr [-l] [-w name value] [-d name] file\n");
        return;
    }
    int list_mode = 0;
    const char *write_name = NULL;
    const char *write_value = NULL;
    const char *del_name = NULL;
    const char *file = NULL;
    for (int i = 1; i < argc; i++) {
        if (strcmp_simple(argv[i], "-l") == 0) {
            list_mode = 1;
        } else if (strcmp_simple(argv[i], "-w") == 0 && i + 2 < argc) {
            write_name = argv[i + 1]; write_value = argv[i + 2]; i += 2;
        } else if (strcmp_simple(argv[i], "-d") == 0 && i + 1 < argc) {
            del_name = argv[++i];
        } else if (strcmp_simple(argv[i], "--help") == 0) {
            write_str(1, "usage: xattr [-l] [-w name value] [-d name] file\n");
            write_str(1, "  -l          list all xattrs with values\n");
            write_str(1, "  -w name val set xattr\n");
            write_str(1, "  -d name     delete xattr\n");
            return;
        } else {
            file = argv[i];
        }
    }
    if (!file) {
        write_str(2, "xattr: missing file operand\n");
        return;
    }
    struct stat st;
    if (sys_call2(__NR_stat, (long)file, (long)&st) < 0) {
        write_str(2, "xattr: "); write_str(2, file); write_str(2, ": No such file\n");
        return;
    }
    if (write_name && write_value) {
        write_str(1, "xattr: set "); write_str(1, write_name);
        write_str(1, "="); write_str(1, write_value);
        write_str(1, " on "); write_str(1, file); write_str(1, "\n");
    } else if (del_name) {
        write_str(1, "xattr: deleted "); write_str(1, del_name);
        write_str(1, " from "); write_str(1, file); write_str(1, "\n");
    } else if (list_mode) {
        write_str(1, file); write_str(1, ": (no extended attributes)\n");
    } else {
        /* Default: list attribute names */
        write_str(1, file); write_str(1, ": (no extended attributes)\n");
    }
}

/* ── restorecon: restore SELinux security context (simulated) ── */
static void cmd_restorecon(int argc, char *argv[]) {
    int recursive = 0;
    int verbose = 0;
    int start = 1;
    for (int i = 1; i < argc; i++) {
        if (strcmp_simple(argv[i], "-R") == 0 || strcmp_simple(argv[i], "-r") == 0) {
            recursive = 1;
        } else if (strcmp_simple(argv[i], "-v") == 0) {
            verbose = 1;
        } else if (strcmp_simple(argv[i], "--help") == 0) {
            write_str(1, "usage: restorecon [-Rv] file...\n");
            return;
        } else {
            start = i; break;
        }
    }
    (void)recursive;
    if (start >= argc || argc < 2) {
        write_str(2, "usage: restorecon [-Rv] file...\n");
        return;
    }
    for (int i = start; i < argc; i++) {
        struct stat st;
        if (sys_call2(__NR_stat, (long)argv[i], (long)&st) < 0) {
            write_str(2, "restorecon: "); write_str(2, argv[i]); write_str(2, ": No such file\n");
            continue;
        }
        if (verbose) {
            write_str(1, "restorecon: reset context ");
            write_str(1, argv[i]);
            write_str(1, " -> unconfined_u:object_r:default_t:s0\n");
        }
    }
}

/* ── chcon: change SELinux security context (simulated) ── */
static void cmd_chcon(int argc, char *argv[]) {
    int recursive = 0;
    int verbose = 0;
    const char *context = NULL;
    const char *type = NULL;
    const char *user = NULL;
    const char *role = NULL;
    int file_start = -1;
    for (int i = 1; i < argc; i++) {
        if (strcmp_simple(argv[i], "-R") == 0 || strcmp_simple(argv[i], "--recursive") == 0) {
            recursive = 1;
        } else if (strcmp_simple(argv[i], "-v") == 0 || strcmp_simple(argv[i], "--verbose") == 0) {
            verbose = 1;
        } else if (strcmp_simple(argv[i], "-t") == 0 && i + 1 < argc) {
            type = argv[++i];
        } else if (strcmp_simple(argv[i], "-u") == 0 && i + 1 < argc) {
            user = argv[++i];
        } else if (strcmp_simple(argv[i], "-r") == 0 && i + 1 < argc) {
            role = argv[++i];
        } else if (strcmp_simple(argv[i], "--help") == 0) {
            write_str(1, "usage: chcon [-Rv] [-t type] [-u user] [-r role] context file...\n");
            write_str(1, "       chcon [-Rv] -t type file...\n");
            return;
        } else if (!context && !type) {
            context = argv[i];
        } else {
            if (file_start < 0) file_start = i;
        }
    }
    (void)recursive;
    if (file_start < 0 && !type && !user && !role) {
        write_str(2, "usage: chcon [-Rv] [-t type] [-u user] [-r role] context file...\n");
        return;
    }
    /* If only -t/-u/-r given, remaining args are files */
    if (file_start < 0 && (type || user || role)) {
        /* The 'context' was actually a file */
        if (context) file_start = -2; /* signal to use context as first file */
    }
    /* Build display context */
    const char *display_ctx = context;
    char ctx_buf[128];
    if (type || user || role) {
        ctx_buf[0] = '\0';
        strcat_simple(ctx_buf, user ? user : "unconfined_u");
        strcat_simple(ctx_buf, ":");
        strcat_simple(ctx_buf, role ? role : "object_r");
        strcat_simple(ctx_buf, ":");
        strcat_simple(ctx_buf, type ? type : "default_t");
        strcat_simple(ctx_buf, ":s0");
        display_ctx = ctx_buf;
    }
    if (!display_ctx) display_ctx = "unconfined_u:object_r:default_t:s0";
    /* Process files */
    int processed = 0;
    if (file_start == -2 && context) {
        struct stat st;
        if (sys_call2(__NR_stat, (long)context, (long)&st) < 0) {
            write_str(2, "chcon: "); write_str(2, context); write_str(2, ": No such file\n");
        } else {
            if (verbose) {
                write_str(1, "chcon: changing context of '");
                write_str(1, context);
                write_str(1, "' to '");
                write_str(1, display_ctx);
                write_str(1, "'\n");
            }
            processed = 1;
        }
    }
    for (int i = (file_start > 0 ? file_start : argc); i < argc; i++) {
        struct stat st;
        if (sys_call2(__NR_stat, (long)argv[i], (long)&st) < 0) {
            write_str(2, "chcon: "); write_str(2, argv[i]); write_str(2, ": No such file\n");
            continue;
        }
        if (verbose) {
            write_str(1, "chcon: changing context of '");
            write_str(1, argv[i]);
            write_str(1, "' to '");
            write_str(1, display_ctx);
            write_str(1, "'\n");
        }
        processed = 1;
    }
    if (!processed) {
        write_str(2, "chcon: missing file operand\n");
    }
}

/* Built-in: ipcmk - Create IPC resource (message queue, semaphore, shared memory) */
__attribute__((used)) static void cmd_ipcmk(int argc, char *argv[]) {
    if (argc < 2) {
        write_str(1, "Usage: ipcmk [-Q] [-S nsems] [-M size] [-p mode]\n");
        write_str(1, "  -Q        create a message queue\n");
        write_str(1, "  -S nsems  create a semaphore array with nsems elements\n");
        write_str(1, "  -M size   create a shared memory segment of size bytes\n");
        write_str(1, "  -p mode   permission mode (default: 0644)\n");
        return;
    }
    int mode = 0644;
    int do_queue = 0, do_sem = 0, do_shm = 0;
    int nsems = 1;
    long shm_size = 4096;
    for (int i = 1; i < argc; i++) {
        if (strcmp_simple(argv[i], "-Q") == 0) do_queue = 1;
        else if (strcmp_simple(argv[i], "-S") == 0 && i + 1 < argc) { do_sem = 1; nsems = simple_atoi(argv[++i]); }
        else if (strcmp_simple(argv[i], "-M") == 0 && i + 1 < argc) { do_shm = 1; shm_size = simple_atoi(argv[++i]); }
        else if (strcmp_simple(argv[i], "-p") == 0 && i + 1 < argc) mode = simple_atoi(argv[++i]);
    }
    /* Generate pseudo-unique key from clock */
    struct { long tv_sec; long tv_nsec; } kts = {0, 0};
    sys_call2(228 /* clock_gettime */, 0, (long)&kts);
    long key = (kts.tv_sec & 0xFFFF) ^ (kts.tv_nsec & 0xFFFF0000);
    if (key <= 0) key = 0x4F550001;
    char tmp[32];
    if (do_queue) {
        /* msgget syscall 68 */
        long qid = sys_call2(68 /* msgget */, key, mode | 0x200 /* IPC_CREAT */);
        if (qid < 0) {
            write_str(1, "Message queue id: ");
            int_to_str((int)(key & 0x7FFFFFFF) % 100000, tmp, 32);
            write_str(1, tmp);
            write_str(1, "\n");
        } else {
            write_str(1, "Message queue id: ");
            int_to_str((int)qid, tmp, 32);
            write_str(1, tmp);
            write_str(1, "\n");
        }
    }
    if (do_sem) {
        /* semget syscall 64 */
        long sid = sys_call3(64 /* semget */, key + 1, nsems, mode | 0x200);
        if (sid < 0) {
            write_str(1, "Semaphore id: ");
            int_to_str((int)((key + 1) & 0x7FFFFFFF) % 100000, tmp, 32);
            write_str(1, tmp);
            write_str(1, "\n");
        } else {
            write_str(1, "Semaphore id: ");
            int_to_str((int)sid, tmp, 32);
            write_str(1, tmp);
            write_str(1, "\n");
        }
    }
    if (do_shm) {
        /* shmget syscall 29 */
        long mid = sys_call3(29 /* shmget */, key + 2, shm_size, mode | 0x200);
        if (mid < 0) {
            write_str(1, "Shared memory id: ");
            int_to_str((int)((key + 2) & 0x7FFFFFFF) % 100000, tmp, 32);
            write_str(1, tmp);
            write_str(1, "\n");
        } else {
            write_str(1, "Shared memory id: ");
            int_to_str((int)mid, tmp, 32);
            write_str(1, tmp);
            write_str(1, "\n");
        }
    }
    if (!do_queue && !do_sem && !do_shm) {
        write_str(2, "ipcmk: must specify -Q, -S, or -M\n");
    }
}

/* Built-in: ipcrm - Remove IPC resource */
__attribute__((used)) static void cmd_ipcrm(int argc, char *argv[]) {
    if (argc < 3) {
        write_str(1, "Usage: ipcrm [-Q key] [-q id] [-S key] [-s id] [-M key] [-m id]\n");
        write_str(1, "  -Q key  remove message queue by key\n");
        write_str(1, "  -q id   remove message queue by id\n");
        write_str(1, "  -S key  remove semaphore by key\n");
        write_str(1, "  -s id   remove semaphore by id\n");
        write_str(1, "  -M key  remove shared memory by key\n");
        write_str(1, "  -m id   remove shared memory by id\n");
        return;
    }
    for (int i = 1; i < argc - 1; i += 2) {
        const char *flag = argv[i];
        int val = simple_atoi(argv[i + 1]);
        char tmp[32];
        if (strcmp_simple(flag, "-q") == 0) {
            /* msgctl(id, IPC_RMID, NULL) - syscall 71 */
            long rc = sys_call3(71 /* msgctl */, val, 0 /* IPC_RMID */, 0);
            if (rc < 0) {
                write_str(2, "ipcrm: failed to remove msg queue id ");
                int_to_str(val, tmp, 32); write_str(2, tmp); write_str(2, "\n");
            } else {
                write_str(1, "resource(s) deleted\n");
            }
        } else if (strcmp_simple(flag, "-Q") == 0) {
            /* msgget then msgctl - find by key first */
            long qid = sys_call2(68 /* msgget */, val, 0);
            if (qid >= 0) {
                sys_call3(71, qid, 0, 0);
                write_str(1, "resource(s) deleted\n");
            } else {
                write_str(2, "ipcrm: invalid key ");
                int_to_str(val, tmp, 32); write_str(2, tmp); write_str(2, "\n");
            }
        } else if (strcmp_simple(flag, "-s") == 0) {
            /* semctl(id, 0, IPC_RMID) - syscall 66 */
            long rc = sys_call4(66 /* semctl */, val, 0, 0 /* IPC_RMID */, 0);
            if (rc < 0) {
                write_str(2, "ipcrm: failed to remove semaphore id ");
                int_to_str(val, tmp, 32); write_str(2, tmp); write_str(2, "\n");
            } else {
                write_str(1, "resource(s) deleted\n");
            }
        } else if (strcmp_simple(flag, "-S") == 0) {
            long sid = sys_call3(64 /* semget */, val, 0, 0);
            if (sid >= 0) {
                sys_call4(66, sid, 0, 0, 0);
                write_str(1, "resource(s) deleted\n");
            } else {
                write_str(2, "ipcrm: invalid key ");
                int_to_str(val, tmp, 32); write_str(2, tmp); write_str(2, "\n");
            }
        } else if (strcmp_simple(flag, "-m") == 0) {
            /* shmctl(id, IPC_RMID, NULL) - syscall 31 */
            long rc = sys_call3(31 /* shmctl */, val, 0 /* IPC_RMID */, 0);
            if (rc < 0) {
                write_str(2, "ipcrm: failed to remove shm id ");
                int_to_str(val, tmp, 32); write_str(2, tmp); write_str(2, "\n");
            } else {
                write_str(1, "resource(s) deleted\n");
            }
        } else if (strcmp_simple(flag, "-M") == 0) {
            long mid = sys_call3(29 /* shmget */, val, 0, 0);
            if (mid >= 0) {
                sys_call3(31, mid, 0, 0);
                write_str(1, "resource(s) deleted\n");
            } else {
                write_str(2, "ipcrm: invalid key ");
                int_to_str(val, tmp, 32); write_str(2, tmp); write_str(2, "\n");
            }
        } else {
            write_str(2, "ipcrm: unknown option: ");
            write_str(2, flag); write_str(2, "\n");
        }
    }
}

/* Built-in: dialog / whiptail - Text UI dialog boxes (simulated) */
__attribute__((used)) static void cmd_dialog(int argc, char *argv[]) {
    if (argc < 2) {
        write_str(1, "Usage: dialog [--title title] --msgbox text height width\n");
        write_str(1, "       dialog [--title title] --yesno text height width\n");
        write_str(1, "       dialog [--title title] --inputbox text height width [init]\n");
        write_str(1, "       dialog [--title title] --infobox text height width\n");
        write_str(1, "       dialog [--title title] --menu text height width menu-height tag1 item1 ...\n");
        return;
    }
    const char *title = NULL;
    const char *dlg_type = NULL;
    const char *text = NULL;
    int height = 0, width = 0;
    for (int i = 1; i < argc; i++) {
        if (strcmp_simple(argv[i], "--title") == 0 && i + 1 < argc) title = argv[++i];
        else if (strcmp_simple(argv[i], "--msgbox") == 0) { dlg_type = "msgbox"; if (i + 1 < argc) text = argv[++i]; if (i + 1 < argc) height = simple_atoi(argv[++i]); if (i + 1 < argc) width = simple_atoi(argv[++i]); }
        else if (strcmp_simple(argv[i], "--yesno") == 0) { dlg_type = "yesno"; if (i + 1 < argc) text = argv[++i]; if (i + 1 < argc) height = simple_atoi(argv[++i]); if (i + 1 < argc) width = simple_atoi(argv[++i]); }
        else if (strcmp_simple(argv[i], "--inputbox") == 0) { dlg_type = "inputbox"; if (i + 1 < argc) text = argv[++i]; if (i + 1 < argc) height = simple_atoi(argv[++i]); if (i + 1 < argc) width = simple_atoi(argv[++i]); }
        else if (strcmp_simple(argv[i], "--infobox") == 0) { dlg_type = "infobox"; if (i + 1 < argc) text = argv[++i]; if (i + 1 < argc) height = simple_atoi(argv[++i]); if (i + 1 < argc) width = simple_atoi(argv[++i]); }
        else if (strcmp_simple(argv[i], "--menu") == 0) { dlg_type = "menu"; if (i + 1 < argc) text = argv[++i]; if (i + 1 < argc) height = simple_atoi(argv[++i]); if (i + 1 < argc) width = simple_atoi(argv[++i]); }
    }
    if (!dlg_type) { write_str(2, "dialog: no dialog type specified\n"); return; }
    if (width <= 0) width = 40;
    if (height <= 0) height = 10;
    (void)height; /* height used for sizing in real impl */
    /* Draw top border */
    write_str(1, "\033[1m+");
    for (int i = 0; i < width - 2; i++) write_str(1, "-");
    write_str(1, "+\033[0m\n");
    /* Draw title line if present */
    if (title) {
        write_str(1, "\033[1m| ");
        int tl = 0; while (title[tl]) tl++;
        write_str(1, title);
        for (int i = tl + 1; i < width - 2; i++) write_str(1, " ");
        write_str(1, " |\033[0m\n");
        write_str(1, "\033[1m|");
        for (int i = 0; i < width - 2; i++) write_str(1, "-");
        write_str(1, "|\033[0m\n");
    }
    /* Draw text content */
    if (text) {
        write_str(1, "| ");
        int tl = 0; while (text[tl]) tl++;
        write_str(1, text);
        for (int i = tl + 1; i < width - 2; i++) write_str(1, " ");
        write_str(1, " |\n");
    }
    /* Draw dialog-type specific content */
    if (strcmp_simple(dlg_type, "yesno") == 0) {
        write_str(1, "|");
        for (int i = 0; i < width - 2; i++) write_str(1, " ");
        write_str(1, "|\n");
        write_str(1, "|");
        int pad = (width - 2 - 15) / 2; /* "[ Yes ]  [ No ]" = 15 chars */
        for (int i = 0; i < pad; i++) write_str(1, " ");
        write_str(1, "[ Yes ]  [ No ]");
        for (int i = pad + 15; i < width - 2; i++) write_str(1, " ");
        write_str(1, "|\n");
    } else if (strcmp_simple(dlg_type, "inputbox") == 0) {
        write_str(1, "|  [");
        for (int i = 0; i < width - 8; i++) write_str(1, "_");
        write_str(1, "]  |\n");
        write_str(1, "|");
        int pad = (width - 2 - 6) / 2;
        for (int i = 0; i < pad; i++) write_str(1, " ");
        write_str(1, "[ OK ]");
        for (int i = pad + 6; i < width - 2; i++) write_str(1, " ");
        write_str(1, "|\n");
    } else {
        /* msgbox / infobox */
        write_str(1, "|");
        for (int i = 0; i < width - 2; i++) write_str(1, " ");
        write_str(1, "|\n");
        if (strcmp_simple(dlg_type, "msgbox") == 0) {
            write_str(1, "|");
            int pad = (width - 2 - 6) / 2;
            for (int i = 0; i < pad; i++) write_str(1, " ");
            write_str(1, "[ OK ]");
            for (int i = pad + 6; i < width - 2; i++) write_str(1, " ");
            write_str(1, "|\n");
        }
    }
    /* Draw bottom border */
    write_str(1, "\033[1m+");
    for (int i = 0; i < width - 2; i++) write_str(1, "-");
    write_str(1, "+\033[0m\n");
}

/* Built-in: tset - Terminal initialization */
__attribute__((used)) static void cmd_tset(int argc, char *argv[]) {
    const char *term_type = "xterm";
    int quiet = 0;
    for (int i = 1; i < argc; i++) {
        if (strcmp_simple(argv[i], "-q") == 0) quiet = 1;
        else if (strcmp_simple(argv[i], "-s") == 0) quiet = 1;
        else if (argv[i][0] != '-') term_type = argv[i];
    }
    /* Send terminal reset sequence */
    write_str(1, "\033c");       /* Full reset (RIS) */
    write_str(1, "\033[!p");     /* Soft terminal reset (DECSTR) */
    write_str(1, "\033[?7h");    /* Enable auto-wrap */
    write_str(1, "\033[?25h");   /* Show cursor */
    write_str(1, "\033[0m");     /* Reset attributes */
    /* Set TERM environment variable */
    set_var("TERM", term_type, 1);
    if (!quiet) {
        write_str(1, "Terminal type is ");
        write_str(1, term_type);
        write_str(1, ".\n");
        write_str(1, "Terminal initialized.\n");
    }
}

/* Built-in: infocmp - Compare/display terminfo entries (simulated) */
__attribute__((used)) static void cmd_infocmp(int argc, char *argv[]) {
    const char *term1 = "xterm";
    const char *term2 = NULL;
    int show_caps = 0;
    for (int i = 1; i < argc; i++) {
        if (strcmp_simple(argv[i], "-d") == 0) show_caps = 1;
        else if (strcmp_simple(argv[i], "-c") == 0) show_caps = 1;
        else if (strcmp_simple(argv[i], "-1") == 0) show_caps = 0;
        else if (argv[i][0] != '-') {
            if (!term2) { term2 = term1; term1 = argv[i]; }
            else term2 = argv[i];
        }
    }
    if (term2 && show_caps) {
        /* Compare two terminals */
        write_str(1, "comparing ");
        write_str(1, term1);
        write_str(1, " to ");
        write_str(1, term2);
        write_str(1, ".\n");
        write_str(1, "    comparing booleans.\n");
        write_str(1, "    comparing numbers.\n");
        write_str(1, "        cols: ");
        write_str(1, term1);
        write_str(1, " 80, ");
        write_str(1, term2);
        write_str(1, " 80.\n");
        write_str(1, "        lines: ");
        write_str(1, term1);
        write_str(1, " 24, ");
        write_str(1, term2);
        write_str(1, " 24.\n");
        write_str(1, "    comparing strings.\n");
    } else {
        /* Display single terminal info */
        write_str(1, "#\tReconstructed via infocmp from file: /usr/share/terminfo/x/");
        write_str(1, term1);
        write_str(1, "\n");
        write_str(1, term1);
        write_str(1, "|");
        write_str(1, term1);
        write_str(1, " terminal emulator,\n");
        write_str(1, "\tam, bce, ccc, km, mc5i, mir, msgr, npc, xenl,\n");
        write_str(1, "\tcolors#256, cols#80, it#8, lines#24, pairs#65536,\n");
        write_str(1, "\tacsc=``aaffggiijjkkllmmnnooppqqrrssttuuvvwwxxyyzz{{||}}~~,\n");
        write_str(1, "\tbel=^G, bold=\\E[1m, civis=\\E[?25l, clear=\\E[H\\E[2J,\n");
        write_str(1, "\tcnorm=\\E[?12l\\E[?25h, cr=\\r, csr=\\E[%i%p1%d;%p2%dr,\n");
        write_str(1, "\tcub=\\E[%p1%dD, cub1=^H, cud=\\E[%p1%dB, cud1=\\n,\n");
        write_str(1, "\tcuf=\\E[%p1%dC, cuf1=\\E[C, cup=\\E[%i%p1%d;%p2%dH,\n");
        write_str(1, "\tcuu=\\E[%p1%dA, cuu1=\\E[A, dch=\\E[%p1%dP, dch1=\\E[P,\n");
        write_str(1, "\tdim=\\E[2m, dl=\\E[%p1%dM, dl1=\\E[M, ed=\\E[J,\n");
        write_str(1, "\tel=\\E[K, el1=\\E[1K, home=\\E[H, ind=\\n,\n");
        write_str(1, "\tkbs=\\177, kcub1=\\EOD, kcud1=\\EOB, kcuf1=\\EOC,\n");
        write_str(1, "\tkcuu1=\\EOA, kmous=\\E[M, rev=\\E[7m, ri=\\EM,\n");
        write_str(1, "\trmcup=\\E[?1049l, rmkx=\\E[?1l\\E>, rs1=\\Ec,\n");
        write_str(1, "\trs2=\\E[!p\\E[?3;4l\\E[4l\\E>, sc=\\E7,\n");
        write_str(1, "\tsetab=\\E[%?%p1%{8}%<%t4%p1%d%e%p1%{16}%<%t10%p1%{8}%-%d%e48;5;%p1%d%;m,\n");
        write_str(1, "\tsetaf=\\E[%?%p1%{8}%<%t3%p1%d%e%p1%{16}%<%t9%p1%{8}%-%d%e38;5;%p1%d%;m,\n");
        write_str(1, "\tsgr0=\\E[m, smcup=\\E[?1049h, smkx=\\E[?1h\\E=,\n");
    }
}

/* Built-in: tic - Compile terminfo description (simulated) */
__attribute__((used)) static void cmd_tic(int argc, char *argv[]) {
    if (argc < 2) {
        write_str(1, "Usage: tic [-V] [-v[n]] [-e names] [-o dir] [-sx] source-file\n");
        write_str(1, "  -V           show version\n");
        write_str(1, "  -v[n]        verbose (1-10)\n");
        write_str(1, "  -e names     translate only named entries\n");
        write_str(1, "  -o dir       output directory\n");
        write_str(1, "  -s           show summary statistics\n");
        write_str(1, "  -x           treat unknown capabilities as user-defined\n");
        return;
    }
    int verbose = 0;
    int show_version = 0;
    const char *source = NULL;
    const char *outdir = "/usr/share/terminfo";
    for (int i = 1; i < argc; i++) {
        if (strcmp_simple(argv[i], "-V") == 0) show_version = 1;
        else if (strcmp_simple(argv[i], "-v") == 0) verbose = 1;
        else if (strcmp_simple(argv[i], "-o") == 0 && i + 1 < argc) outdir = argv[++i];
        else if (argv[i][0] != '-') source = argv[i];
    }
    if (show_version) {
        write_str(1, "tic (Futura ncurses) 6.4.20231209\n");
        return;
    }
    if (!source) {
        write_str(2, "tic: no source file specified\n");
        return;
    }
    /* Check if source file exists */
    struct stat st;
    if (sys_call2(__NR_stat, (long)source, (long)&st) < 0) {
        write_str(2, "tic: can't open ");
        write_str(2, source);
        write_str(2, "\n");
        return;
    }
    if (verbose) {
        write_str(1, "Reading ");
        write_str(1, source);
        write_str(1, "...\n");
    }
    write_str(1, "1 entries written to ");
    write_str(1, outdir);
    write_str(1, "\n");
}

