/* jq - JSON processor */
static void cmd_jq(int argc, char *argv[]) {
    if (argc >= 2 && strcmp_simple(argv[1], "--version") == 0) {
        write_str(1, "jq-1.7.1\n");
        return;
    }
    if (argc >= 2 && strcmp_simple(argv[1], "--help") == 0) {
        write_str(1, "Usage: jq [OPTIONS...] FILTER [FILE...]\n");
        write_str(1, "\n");
        write_str(1, "  jq is a tool for processing JSON inputs.\n");
        write_str(1, "\n");
        write_str(1, "  Filters: . .key .key.subkey .[0] .[] keys values length\n");
        return;
    }
    if (argc < 2) {
        write_str(1, "Usage: jq FILTER [FILE]\n");
        return;
    }
    const char *filter = argv[1];
    char buf[4096];
    ssize_t total = 0;

    if (argc >= 3) {
        /* Read from file */
        int fd = sys_open(argv[2], 0 /* O_RDONLY */, 0);
        if (fd < 0) {
            write_str(2, "jq: ");
            write_str(2, argv[2]);
            write_str(2, ": No such file or directory\n");
            return;
        }
        total = sys_read(fd, buf, sizeof(buf) - 1);
        sys_close(fd);
        if (total <= 0) return;
        buf[total] = '\0';
    } else {
        /* Read from stdin */
        total = sys_read(0, buf, sizeof(buf) - 1);
        if (total <= 0) return;
        buf[total] = '\0';
    }

    /* Simple . filter: pass through with formatting */
    if (filter[0] == '.' && filter[1] == '\0') {
        write_str(1, buf);
        if (total > 0 && buf[total - 1] != '\n') write_str(1, "\n");
        return;
    }

    /* .key filter: extract a top-level key value from JSON */
    if (filter[0] == '.') {
        const char *key = filter + 1;
        size_t klen = 0;
        while (key[klen] && key[klen] != '.' && key[klen] != '[') klen++;

        /* Find "key": in buffer */
        char search[128];
        search[0] = '"';
        size_t si = 1;
        for (size_t k = 0; k < klen && si < sizeof(search) - 4; k++)
            search[si++] = key[k];
        search[si++] = '"';
        search[si++] = ':';
        search[si] = '\0';

        /* Search for the key in JSON */
        const char *p = buf;
        while (*p) {
            int match = 1;
            for (size_t k = 0; k < si; k++) {
                if (p[k] != search[k]) { match = 0; break; }
            }
            if (match) {
                p += si;
                while (*p == ' ' || *p == '\t') p++;
                /* Print the value */
                if (*p == '"') {
                    /* String value */
                    p++;
                    write_str(1, "\"");
                    while (*p && *p != '"') {
                        if (*p == '\\' && *(p + 1)) {
                            char esc[3] = {'\\', *(p + 1), '\0'};
                            write_str(1, esc);
                            p += 2;
                        } else {
                            char c[2] = {*p, '\0'};
                            write_str(1, c);
                            p++;
                        }
                    }
                    write_str(1, "\"\n");
                } else {
                    /* Number, bool, null */
                    const char *start = p;
                    while (*p && *p != ',' && *p != '}' && *p != ']' && *p != '\n' && *p != ' ')
                        p++;
                    while (p > start && (*(p-1) == ' ' || *(p-1) == '\r')) p--;
                    char val[256];
                    size_t vlen = (size_t)(p - start);
                    if (vlen >= sizeof(val)) vlen = sizeof(val) - 1;
                    for (size_t k = 0; k < vlen; k++) val[k] = start[k];
                    val[vlen] = '\0';
                    write_str(1, val);
                    write_str(1, "\n");
                }
                return;
            }
            p++;
        }
        write_str(1, "null\n");
        return;
    }

    /* keys filter */
    if (strcmp_simple(filter, "keys") == 0) {
        write_str(1, "[\n");
        const char *p = buf;
        int first = 1;
        while (*p) {
            if (*p == '"') {
                p++;
                const char *kstart = p;
                while (*p && *p != '"') p++;
                /* Check if followed by : */
                const char *after = p + 1;
                while (*after == ' ' || *after == '\t') after++;
                if (*after == ':') {
                    if (!first) write_str(1, ",\n");
                    write_str(1, "  \"");
                    char key[128];
                    size_t kl = (size_t)(p - kstart);
                    if (kl >= sizeof(key)) kl = sizeof(key) - 1;
                    for (size_t k = 0; k < kl; k++) key[k] = kstart[k];
                    key[kl] = '\0';
                    write_str(1, key);
                    write_str(1, "\"");
                    first = 0;
                }
                if (*p) p++;
            } else {
                p++;
            }
        }
        write_str(1, "\n]\n");
        return;
    }

    /* Fallback: pass through */
    write_str(1, buf);
    if (total > 0 && buf[total - 1] != '\n') write_str(1, "\n");
}

/* yq - YAML processor (simulated) */
static void cmd_yq(int argc, char *argv[]) {
    if (argc >= 2 && strcmp_simple(argv[1], "--version") == 0) {
        write_str(1, "yq (https://github.com/mikefarah/yq/) version v4.40.5\n");
        return;
    }
    if (argc >= 2 && strcmp_simple(argv[1], "--help") == 0) {
        write_str(1, "Usage: yq [OPTIONS...] EXPRESSION [FILE...]\n");
        write_str(1, "\n");
        write_str(1, "  yq is a lightweight and portable command-line YAML processor.\n");
        write_str(1, "\n");
        write_str(1, "  Expressions: . .key .key.subkey .[0] .[] keys values length\n");
        return;
    }
    if (argc < 2) {
        write_str(1, "Usage: yq EXPRESSION [FILE]\n");
        return;
    }
    const char *filter = argv[1];
    char buf[4096];
    ssize_t total = 0;

    if (argc >= 3) {
        int fd = sys_open(argv[2], 0, 0);
        if (fd < 0) {
            write_str(2, "yq: ");
            write_str(2, argv[2]);
            write_str(2, ": No such file or directory\n");
            return;
        }
        total = sys_read(fd, buf, sizeof(buf) - 1);
        sys_close(fd);
        if (total <= 0) return;
        buf[total] = '\0';
    } else {
        total = sys_read(0, buf, sizeof(buf) - 1);
        if (total <= 0) return;
        buf[total] = '\0';
    }

    /* . filter: passthrough */
    if (filter[0] == '.' && filter[1] == '\0') {
        write_str(1, buf);
        if (total > 0 && buf[total - 1] != '\n') write_str(1, "\n");
        return;
    }

    /* .key filter: find "key: value" in YAML */
    if (filter[0] == '.') {
        const char *key = filter + 1;
        size_t klen = 0;
        while (key[klen] && key[klen] != '.') klen++;

        const char *p = buf;
        while (*p) {
            /* Check at start of line */
            int match = 1;
            for (size_t k = 0; k < klen; k++) {
                if (p[k] != key[k]) { match = 0; break; }
            }
            if (match && p[klen] == ':') {
                p += klen + 1;
                while (*p == ' ' || *p == '\t') p++;
                const char *vstart = p;
                while (*p && *p != '\n') p++;
                char val[256];
                size_t vlen = (size_t)(p - vstart);
                if (vlen >= sizeof(val)) vlen = sizeof(val) - 1;
                for (size_t k = 0; k < vlen; k++) val[k] = vstart[k];
                val[vlen] = '\0';
                write_str(1, val);
                write_str(1, "\n");
                return;
            }
            /* Advance to next line */
            while (*p && *p != '\n') p++;
            if (*p == '\n') p++;
        }
        write_str(1, "null\n");
        return;
    }

    write_str(1, buf);
    if (total > 0 && buf[total - 1] != '\n') write_str(1, "\n");
}

/* xmllint - XML validator (simulated) */
static void cmd_xmllint(int argc, char *argv[]) {
    if (argc >= 2 && strcmp_simple(argv[1], "--version") == 0) {
        write_str(1, "xmllint: using libxml version 21200\n");
        write_str(1, "   compiled with: Threads Tree Output Push Reader Patterns Writer SAXv1\n");
        return;
    }
    if (argc < 2) {
        write_str(1, "Usage: xmllint [OPTIONS] FILE\n");
        write_str(1, "  --noout       suppress output\n");
        write_str(1, "  --format      pretty-print\n");
        write_str(1, "  --valid       validate against DTD\n");
        write_str(1, "  --schema XSD  validate against schema\n");
        return;
    }

    const char *filename = NULL;
    int noout = 0;
    int format = 0;

    for (int i = 1; i < argc; i++) {
        if (strcmp_simple(argv[i], "--noout") == 0) { noout = 1; }
        else if (strcmp_simple(argv[i], "--format") == 0) { format = 1; }
        else if (strcmp_simple(argv[i], "--valid") == 0) { /* no-op */ }
        else if (strcmp_simple(argv[i], "--schema") == 0) { i++; /* skip schema file */ }
        else if (strcmp_simple(argv[i], "-") == 0) { filename = "-"; }
        else if (argv[i][0] != '-') { filename = argv[i]; }
    }

    char buf[4096];
    ssize_t total = 0;

    if (filename && strcmp_simple(filename, "-") != 0) {
        int fd = sys_open(filename, 0, 0);
        if (fd < 0) {
            write_str(2, "xmllint: ");
            write_str(2, filename);
            write_str(2, ": failed to load\n");
            return;
        }
        total = sys_read(fd, buf, sizeof(buf) - 1);
        sys_close(fd);
        if (total <= 0) return;
        buf[total] = '\0';
    } else {
        total = sys_read(0, buf, sizeof(buf) - 1);
        if (total <= 0) return;
        buf[total] = '\0';
    }

    /* Basic XML validation: check for matching < > */
    int depth = 0;
    int valid = 1;
    for (ssize_t i = 0; i < total; i++) {
        if (buf[i] == '<') depth++;
        if (buf[i] == '>') depth--;
        if (depth < 0) { valid = 0; break; }
    }
    if (depth != 0) valid = 0;

    if (!valid) {
        write_str(2, "xmllint: document is not well-formed\n");
        return;
    }

    if (noout) {
        /* Validated OK, no output */
        return;
    }

    (void)format;
    write_str(1, buf);
    if (total > 0 && buf[total - 1] != '\n') write_str(1, "\n");
}

/* sqlite3 - SQLite CLI (simulated) */
static void cmd_sqlite3(int argc, char *argv[]) {
    if (argc >= 2 && strcmp_simple(argv[1], "--version") == 0) {
        write_str(1, "3.45.0 2024-01-15 17:01:13\n");
        return;
    }

    const char *dbname = ":memory:";
    if (argc >= 2 && argv[1][0] != '-') {
        dbname = argv[1];
    }

    /* Check for -cmd or inline SQL */
    for (int i = 1; i < argc; i++) {
        if (strcmp_simple(argv[i], "-cmd") == 0 && i + 1 < argc) {
            /* Execute command */
            i++;
            continue;
        }
    }

    /* Check for SQL on command line: sqlite3 :memory: "SELECT ..." */
    if (argc >= 3 && argv[2][0] != '-') {
        const char *sql = argv[2];
        /* Handle SELECT */
        if ((sql[0] == 'S' || sql[0] == 's') &&
            (sql[1] == 'E' || sql[1] == 'e') &&
            (sql[2] == 'L' || sql[2] == 'l') &&
            (sql[3] == 'E' || sql[3] == 'e') &&
            (sql[4] == 'C' || sql[4] == 'c') &&
            (sql[5] == 'T' || sql[5] == 't')) {
            /* Check for SELECT 1+1, SELECT date(), SELECT sqlite_version() */
            const char *after = sql + 6;
            while (*after == ' ') after++;
            if (after[0] == 's' && after[1] == 'q' && after[2] == 'l' &&
                after[3] == 'i' && after[4] == 't' && after[5] == 'e' &&
                after[6] == '_' && after[7] == 'v') {
                write_str(1, "3.45.0\n");
            } else if (after[0] == 'd' && after[1] == 'a' && after[2] == 't' && after[3] == 'e') {
                write_str(1, "2024-01-15\n");
            } else {
                /* Try numeric evaluation */
                int val = simple_atoi(after);
                char nbuf[32];
                int_to_str(val, nbuf, sizeof(nbuf));
                write_str(1, nbuf);
                write_str(1, "\n");
            }
        } else {
            write_str(1, "OK\n");
        }
        return;
    }

    /* Interactive mode */
    write_str(1, "SQLite version 3.45.0 2024-01-15 17:01:13\n");
    write_str(1, "Enter \".help\" for usage hints.\n");
    if (strcmp_simple(dbname, ":memory:") == 0) {
        write_str(1, "Connected to a transient in-memory database.\n");
        write_str(1, "Use \".open FILENAME\" to reopen on a persistent database.\n");
    }

    char line[512];
    while (1) {
        write_str(1, "sqlite> ");
        ssize_t n = sys_read(0, line, sizeof(line) - 1);
        if (n <= 0) break;
        if (line[n - 1] == '\n') line[n - 1] = '\0';
        else line[n] = '\0';
        if (strcmp_simple(line, ".quit") == 0 || strcmp_simple(line, ".exit") == 0) break;
        if (strcmp_simple(line, ".help") == 0) {
            write_str(1, ".databases         List names and files of attached databases\n");
            write_str(1, ".dump              Render database content as SQL\n");
            write_str(1, ".exit              Exit this program\n");
            write_str(1, ".help              Show this message\n");
            write_str(1, ".mode              Set output mode (csv, column, json, list, table)\n");
            write_str(1, ".open              Open a database file\n");
            write_str(1, ".quit              Exit this program\n");
            write_str(1, ".schema            Show the CREATE statements\n");
            write_str(1, ".tables            List names of tables\n");
            continue;
        }
        if (strcmp_simple(line, ".tables") == 0) {
            /* No tables in memory db */
            continue;
        }
        if (strcmp_simple(line, ".databases") == 0) {
            write_str(1, "main: ");
            write_str(1, dbname);
            write_str(1, " r/w\n");
            continue;
        }
        if (line[0] == '\0') continue;
        /* Handle SQL statements */
        if ((line[0] == 'C' || line[0] == 'c') &&
            (line[1] == 'R' || line[1] == 'r') &&
            (line[2] == 'E' || line[2] == 'e') &&
            (line[3] == 'A' || line[3] == 'a') &&
            (line[4] == 'T' || line[4] == 't') &&
            (line[5] == 'E' || line[5] == 'e')) {
            /* CREATE TABLE/INDEX accepted */
            continue;
        }
        if ((line[0] == 'I' || line[0] == 'i') &&
            (line[1] == 'N' || line[1] == 'n') &&
            (line[2] == 'S' || line[2] == 's') &&
            (line[3] == 'E' || line[3] == 'e') &&
            (line[4] == 'R' || line[4] == 'r') &&
            (line[5] == 'T' || line[5] == 't')) {
            /* INSERT accepted */
            continue;
        }
        if ((line[0] == 'S' || line[0] == 's') &&
            (line[1] == 'E' || line[1] == 'e') &&
            (line[2] == 'L' || line[2] == 'l') &&
            (line[3] == 'E' || line[3] == 'e') &&
            (line[4] == 'C' || line[4] == 'c') &&
            (line[5] == 'T' || line[5] == 't')) {
            const char *after = line + 6;
            while (*after == ' ') after++;
            if (after[0] == 's' && after[1] == 'q' && after[2] == 'l' &&
                after[3] == 'i' && after[4] == 't' && after[5] == 'e' &&
                after[6] == '_' && after[7] == 'v') {
                write_str(1, "3.45.0\n");
            } else {
                int val = simple_atoi(after);
                char nbuf[32];
                int_to_str(val, nbuf, sizeof(nbuf));
                write_str(1, nbuf);
                write_str(1, "\n");
            }
            continue;
        }
        write_str(1, "Error: near \"");
        char first[16];
        int fi = 0;
        while (line[fi] && line[fi] != ' ' && fi < 15) { first[fi] = line[fi]; fi++; }
        first[fi] = '\0';
        write_str(1, first);
        write_str(1, "\": syntax error\n");
    }
}

/* mysql - MySQL client (simulated) */
static void cmd_mysql(int argc, char *argv[]) {
    if (argc >= 2 && (strcmp_simple(argv[1], "--version") == 0 || strcmp_simple(argv[1], "-V") == 0)) {
        write_str(1, "mysql  Ver 8.0.36 for Linux on x86_64 (Futura OS)\n");
        return;
    }
    if (argc >= 2 && strcmp_simple(argv[1], "--help") == 0) {
        write_str(1, "mysql  Ver 8.0.36 for Linux on x86_64\n");
        write_str(1, "Usage: mysql [OPTIONS] [database]\n");
        write_str(1, "  -h, --host=name     Connect to host\n");
        write_str(1, "  -u, --user=name     User for login\n");
        write_str(1, "  -p, --password      Password to use\n");
        write_str(1, "  -P, --port=#        Port number\n");
        write_str(1, "  -e, --execute=stmt  Execute statement and quit\n");
        return;
    }

    /* Check for -e flag */
    for (int i = 1; i < argc; i++) {
        if (strcmp_simple(argv[i], "-e") == 0 && i + 1 < argc) {
            const char *sql = argv[i + 1];
            if ((sql[0] == 'S' || sql[0] == 's') &&
                (sql[1] == 'E' || sql[1] == 'e') &&
                (sql[2] == 'L' || sql[2] == 'l')) {
                write_str(1, "+-----------+\n");
                write_str(1, "| result    |\n");
                write_str(1, "+-----------+\n");
                write_str(1, "| (empty)   |\n");
                write_str(1, "+-----------+\n");
                write_str(1, "1 row in set (0.00 sec)\n");
            } else {
                write_str(1, "Query OK, 0 rows affected (0.00 sec)\n");
            }
            return;
        }
    }

    /* Interactive mode */
    write_str(1, "Welcome to the MySQL monitor.  Commands end with ; or \\g.\n");
    write_str(1, "Your MySQL connection id is 42\n");
    write_str(1, "Server version: 8.0.36 Futura OS MySQL\n\n");
    write_str(1, "Type 'help;' or '\\h' for help. Type '\\c' to clear the current input statement.\n\n");

    char line[512];
    while (1) {
        write_str(1, "mysql> ");
        ssize_t n = sys_read(0, line, sizeof(line) - 1);
        if (n <= 0) break;
        if (line[n - 1] == '\n') line[n - 1] = '\0';
        else line[n] = '\0';
        if (strcmp_simple(line, "quit") == 0 || strcmp_simple(line, "exit") == 0 ||
            strcmp_simple(line, "quit;") == 0 || strcmp_simple(line, "exit;") == 0 ||
            strcmp_simple(line, "\\q") == 0) {
            write_str(1, "Bye\n");
            break;
        }
        if (line[0] == '\0') continue;
        if (strcmp_simple(line, "help;") == 0 || strcmp_simple(line, "\\h") == 0) {
            write_str(1, "List of all MySQL commands:\n");
            write_str(1, "help      Display this help\n");
            write_str(1, "quit      Exit mysql\n");
            write_str(1, "status    Get status information\n");
            write_str(1, "use       Use another database\n");
            continue;
        }
        if (strcmp_simple(line, "status;") == 0 || strcmp_simple(line, "\\s") == 0) {
            write_str(1, "Connection id:          42\n");
            write_str(1, "Current database:       (none)\n");
            write_str(1, "Server version:         8.0.36 Futura OS\n");
            write_str(1, "Protocol version:       10\n");
            write_str(1, "Connection:             localhost via TCP/IP\n");
            write_str(1, "Uptime:                 1 hour 0 min 0 sec\n");
            continue;
        }
        /* Generic SQL response */
        if ((line[0] == 'S' || line[0] == 's') &&
            (line[1] == 'E' || line[1] == 'e') &&
            (line[2] == 'L' || line[2] == 'l')) {
            write_str(1, "Empty set (0.00 sec)\n");
        } else if ((line[0] == 'S' || line[0] == 's') &&
                   (line[1] == 'H' || line[1] == 'h') &&
                   (line[2] == 'O' || line[2] == 'o') &&
                   (line[3] == 'W' || line[3] == 'w')) {
            write_str(1, "Empty set (0.00 sec)\n");
        } else {
            write_str(1, "Query OK, 0 rows affected (0.00 sec)\n");
        }
    }
}

/* psql - PostgreSQL client (simulated) */
static void cmd_psql(int argc, char *argv[]) {
    if (argc >= 2 && (strcmp_simple(argv[1], "--version") == 0 || strcmp_simple(argv[1], "-V") == 0)) {
        write_str(1, "psql (PostgreSQL) 16.1 (Futura OS)\n");
        return;
    }
    if (argc >= 2 && strcmp_simple(argv[1], "--help") == 0) {
        write_str(1, "psql is the PostgreSQL interactive terminal.\n\n");
        write_str(1, "Usage: psql [OPTION]... [DBNAME [USERNAME]]\n");
        write_str(1, "  -h, --host=HOSTNAME      database server host\n");
        write_str(1, "  -p, --port=PORT          database server port\n");
        write_str(1, "  -U, --username=USERNAME  database user name\n");
        write_str(1, "  -d, --dbname=DBNAME      database name to connect to\n");
        write_str(1, "  -c, --command=COMMAND    run only single command and exit\n");
        return;
    }

    /* Check for -c flag */
    for (int i = 1; i < argc; i++) {
        if (strcmp_simple(argv[i], "-c") == 0 && i + 1 < argc) {
            const char *sql = argv[i + 1];
            if ((sql[0] == 'S' || sql[0] == 's') &&
                (sql[1] == 'E' || sql[1] == 'e') &&
                (sql[2] == 'L' || sql[2] == 'l')) {
                write_str(1, " result \n");
                write_str(1, "--------\n");
                write_str(1, "(0 rows)\n");
            } else {
                write_str(1, "COMMAND OK\n");
            }
            return;
        }
    }

    /* Interactive mode */
    const char *dbname = "postgres";
    for (int i = 1; i < argc; i++) {
        if (strcmp_simple(argv[i], "-d") == 0 && i + 1 < argc) {
            dbname = argv[i + 1]; i++;
        } else if (argv[i][0] != '-') {
            dbname = argv[i];
        }
    }

    write_str(1, "psql (16.1)\nType \"help\" for help.\n\n");

    char line[512];
    while (1) {
        write_str(1, dbname);
        write_str(1, "=# ");
        ssize_t n = sys_read(0, line, sizeof(line) - 1);
        if (n <= 0) break;
        if (line[n - 1] == '\n') line[n - 1] = '\0';
        else line[n] = '\0';
        if (strcmp_simple(line, "\\q") == 0 || strcmp_simple(line, "quit") == 0 ||
            strcmp_simple(line, "exit") == 0) break;
        if (line[0] == '\0') continue;
        if (strcmp_simple(line, "\\?") == 0 || strcmp_simple(line, "help") == 0) {
            write_str(1, "General:\n");
            write_str(1, "  \\q         quit psql\n");
            write_str(1, "  \\?         show help\n");
            write_str(1, "  \\l         list databases\n");
            write_str(1, "  \\dt        list tables\n");
            write_str(1, "  \\d TABLE   describe table\n");
            write_str(1, "  \\conninfo  connection info\n");
            continue;
        }
        if (strcmp_simple(line, "\\l") == 0) {
            write_str(1, "                         List of databases\n");
            write_str(1, "   Name    | Owner  | Encoding |   Collate   |    Ctype    \n");
            write_str(1, "-----------+--------+----------+-------------+-------------\n");
            write_str(1, " postgres  | root   | UTF8     | en_US.UTF-8 | en_US.UTF-8\n");
            write_str(1, " template0 | root   | UTF8     | en_US.UTF-8 | en_US.UTF-8\n");
            write_str(1, " template1 | root   | UTF8     | en_US.UTF-8 | en_US.UTF-8\n");
            write_str(1, "(3 rows)\n");
            continue;
        }
        if (strcmp_simple(line, "\\dt") == 0) {
            write_str(1, "Did not find any relations.\n");
            continue;
        }
        if (strcmp_simple(line, "\\conninfo") == 0) {
            write_str(1, "You are connected to database \"");
            write_str(1, dbname);
            write_str(1, "\" as user \"root\" via socket in \"/tmp\" at port \"5432\".\n");
            continue;
        }
        /* SQL */
        if ((line[0] == 'S' || line[0] == 's') &&
            (line[1] == 'E' || line[1] == 'e') &&
            (line[2] == 'L' || line[2] == 'l')) {
            const char *after = line + 6;
            while (*after == ' ') after++;
            if (after[0] == 'v' && after[1] == 'e' && after[2] == 'r') {
                write_str(1, "              version\n");
                write_str(1, "-----------------------------------\n");
                write_str(1, " PostgreSQL 16.1 (Futura OS)\n");
                write_str(1, "(1 row)\n");
            } else if (after[0] == 'n' && after[1] == 'o' && after[2] == 'w') {
                write_str(1, "              now\n");
                write_str(1, "-------------------------------\n");
                write_str(1, " 2024-01-15 12:00:00+00\n");
                write_str(1, "(1 row)\n");
            } else {
                write_str(1, "(0 rows)\n");
            }
        } else if ((line[0] == 'C' || line[0] == 'c') &&
                   (line[1] == 'R' || line[1] == 'r') &&
                   (line[2] == 'E' || line[2] == 'e')) {
            write_str(1, "CREATE TABLE\n");
        } else if ((line[0] == 'I' || line[0] == 'i') &&
                   (line[1] == 'N' || line[1] == 'n') &&
                   (line[2] == 'S' || line[2] == 's')) {
            write_str(1, "INSERT 0 1\n");
        } else if ((line[0] == 'D' || line[0] == 'd') &&
                   (line[1] == 'R' || line[1] == 'r') &&
                   (line[2] == 'O' || line[2] == 'o') &&
                   (line[3] == 'P' || line[3] == 'p')) {
            write_str(1, "DROP TABLE\n");
        } else {
            write_str(1, "ERROR:  syntax error at or near \"");
            char first[16];
            int fi = 0;
            while (line[fi] && line[fi] != ' ' && fi < 15) { first[fi] = line[fi]; fi++; }
            first[fi] = '\0';
            write_str(1, first);
            write_str(1, "\"\n");
        }
    }
}

/* redis-cli - Redis client (simulated) */
static void cmd_redis_cli(int argc, char *argv[]) {
    if (argc >= 2 && (strcmp_simple(argv[1], "--version") == 0 || strcmp_simple(argv[1], "-v") == 0)) {
        write_str(1, "redis-cli 7.2.4 (futura)\n");
        return;
    }
    if (argc >= 2 && strcmp_simple(argv[1], "--help") == 0) {
        write_str(1, "redis-cli 7.2.4\n\n");
        write_str(1, "Usage: redis-cli [OPTIONS] [cmd [arg [arg ...]]]\n");
        write_str(1, "  -h <hostname>    Server hostname (default: 127.0.0.1)\n");
        write_str(1, "  -p <port>        Server port (default: 6379)\n");
        write_str(1, "  -n <db>          Database number\n");
        return;
    }

    /* Inline command mode: redis-cli SET key value */
    if (argc >= 3) {
        if (strcmp_simple(argv[1], "SET") == 0 || strcmp_simple(argv[1], "set") == 0) {
            write_str(1, "OK\n");
            return;
        }
        if (strcmp_simple(argv[1], "GET") == 0 || strcmp_simple(argv[1], "get") == 0) {
            write_str(1, "(nil)\n");
            return;
        }
        if (strcmp_simple(argv[1], "DEL") == 0 || strcmp_simple(argv[1], "del") == 0) {
            write_str(1, "(integer) 0\n");
            return;
        }
        if (strcmp_simple(argv[1], "HSET") == 0 || strcmp_simple(argv[1], "hset") == 0) {
            write_str(1, "(integer) 1\n");
            return;
        }
        if (strcmp_simple(argv[1], "HGET") == 0 || strcmp_simple(argv[1], "hget") == 0) {
            write_str(1, "(nil)\n");
            return;
        }
    }
    if (argc >= 2) {
        if (strcmp_simple(argv[1], "PING") == 0 || strcmp_simple(argv[1], "ping") == 0) {
            write_str(1, "PONG\n");
            return;
        }
        if (strcmp_simple(argv[1], "INFO") == 0 || strcmp_simple(argv[1], "info") == 0) {
            write_str(1, "# Server\nredis_version:7.2.4\nos:Futura OS\n");
            write_str(1, "# Clients\nconnected_clients:1\n");
            write_str(1, "# Memory\nused_memory:1048576\nused_memory_human:1.00M\n");
            return;
        }
        if (strcmp_simple(argv[1], "DBSIZE") == 0 || strcmp_simple(argv[1], "dbsize") == 0) {
            write_str(1, "(integer) 0\n");
            return;
        }
        if (strcmp_simple(argv[1], "KEYS") == 0 || strcmp_simple(argv[1], "keys") == 0) {
            write_str(1, "(empty array)\n");
            return;
        }
    }

    /* Interactive mode */
    write_str(1, "127.0.0.1:6379> Connected to Redis 7.2.4\n");

    /* Simple in-memory key-value store */
    #define REDIS_MAX_KEYS 32
    #define REDIS_KEY_LEN 64
    #define REDIS_VAL_LEN 256
    static char redis_keys[REDIS_MAX_KEYS][REDIS_KEY_LEN];
    static char redis_vals[REDIS_MAX_KEYS][REDIS_VAL_LEN];
    static int redis_used[REDIS_MAX_KEYS];

    for (int i = 0; i < REDIS_MAX_KEYS; i++) redis_used[i] = 0;

    char line[512];
    while (1) {
        write_str(1, "127.0.0.1:6379> ");
        ssize_t n = sys_read(0, line, sizeof(line) - 1);
        if (n <= 0) break;
        if (line[n - 1] == '\n') line[n - 1] = '\0';
        else line[n] = '\0';
        if (strcmp_simple(line, "quit") == 0 || strcmp_simple(line, "QUIT") == 0 ||
            strcmp_simple(line, "exit") == 0) break;
        if (line[0] == '\0') continue;

        /* Parse command and args */
        char *parts[8];
        int nparts = 0;
        char *p = line;
        while (*p && nparts < 8) {
            while (*p == ' ') p++;
            if (!*p) break;
            parts[nparts++] = p;
            if (*p == '"') {
                p++;
                parts[nparts - 1] = p;
                while (*p && *p != '"') p++;
                if (*p == '"') *p++ = '\0';
            } else {
                while (*p && *p != ' ') p++;
                if (*p) *p++ = '\0';
            }
        }
        if (nparts == 0) continue;

        if (strcmp_simple(parts[0], "PING") == 0 || strcmp_simple(parts[0], "ping") == 0) {
            if (nparts >= 2) {
                write_str(1, "\"");
                write_str(1, parts[1]);
                write_str(1, "\"\n");
            } else {
                write_str(1, "PONG\n");
            }
        } else if ((strcmp_simple(parts[0], "SET") == 0 || strcmp_simple(parts[0], "set") == 0) && nparts >= 3) {
            /* Store key-value */
            int slot = -1;
            for (int i = 0; i < REDIS_MAX_KEYS; i++) {
                if (redis_used[i] && strcmp_simple(redis_keys[i], parts[1]) == 0) {
                    slot = i; break;
                }
            }
            if (slot < 0) {
                for (int i = 0; i < REDIS_MAX_KEYS; i++) {
                    if (!redis_used[i]) { slot = i; break; }
                }
            }
            if (slot >= 0) {
                strncpy_simple(redis_keys[slot], parts[1], REDIS_KEY_LEN - 1);
                redis_keys[slot][REDIS_KEY_LEN - 1] = '\0';
                strncpy_simple(redis_vals[slot], parts[2], REDIS_VAL_LEN - 1);
                redis_vals[slot][REDIS_VAL_LEN - 1] = '\0';
                redis_used[slot] = 1;
                write_str(1, "OK\n");
            } else {
                write_str(1, "(error) ERR max keys reached\n");
            }
        } else if ((strcmp_simple(parts[0], "GET") == 0 || strcmp_simple(parts[0], "get") == 0) && nparts >= 2) {
            int found = 0;
            for (int i = 0; i < REDIS_MAX_KEYS; i++) {
                if (redis_used[i] && strcmp_simple(redis_keys[i], parts[1]) == 0) {
                    write_str(1, "\"");
                    write_str(1, redis_vals[i]);
                    write_str(1, "\"\n");
                    found = 1; break;
                }
            }
            if (!found) write_str(1, "(nil)\n");
        } else if ((strcmp_simple(parts[0], "DEL") == 0 || strcmp_simple(parts[0], "del") == 0) && nparts >= 2) {
            int count = 0;
            for (int j = 1; j < nparts; j++) {
                for (int i = 0; i < REDIS_MAX_KEYS; i++) {
                    if (redis_used[i] && strcmp_simple(redis_keys[i], parts[j]) == 0) {
                        redis_used[i] = 0;
                        count++;
                    }
                }
            }
            char nbuf[16];
            int_to_str(count, nbuf, sizeof(nbuf));
            write_str(1, "(integer) ");
            write_str(1, nbuf);
            write_str(1, "\n");
        } else if (strcmp_simple(parts[0], "KEYS") == 0 || strcmp_simple(parts[0], "keys") == 0) {
            int idx = 1;
            int any = 0;
            for (int i = 0; i < REDIS_MAX_KEYS; i++) {
                if (redis_used[i]) {
                    char nbuf[16];
                    int_to_str(idx++, nbuf, sizeof(nbuf));
                    write_str(1, nbuf);
                    write_str(1, ") \"");
                    write_str(1, redis_keys[i]);
                    write_str(1, "\"\n");
                    any = 1;
                }
            }
            if (!any) write_str(1, "(empty array)\n");
        } else if (strcmp_simple(parts[0], "DBSIZE") == 0 || strcmp_simple(parts[0], "dbsize") == 0) {
            int count = 0;
            for (int i = 0; i < REDIS_MAX_KEYS; i++) {
                if (redis_used[i]) count++;
            }
            char nbuf[16];
            int_to_str(count, nbuf, sizeof(nbuf));
            write_str(1, "(integer) ");
            write_str(1, nbuf);
            write_str(1, "\n");
        } else if (strcmp_simple(parts[0], "FLUSHDB") == 0 || strcmp_simple(parts[0], "flushdb") == 0 ||
                   strcmp_simple(parts[0], "FLUSHALL") == 0 || strcmp_simple(parts[0], "flushall") == 0) {
            for (int i = 0; i < REDIS_MAX_KEYS; i++) redis_used[i] = 0;
            write_str(1, "OK\n");
        } else if (strcmp_simple(parts[0], "EXISTS") == 0 || strcmp_simple(parts[0], "exists") == 0) {
            if (nparts >= 2) {
                int count = 0;
                for (int j = 1; j < nparts; j++) {
                    for (int i = 0; i < REDIS_MAX_KEYS; i++) {
                        if (redis_used[i] && strcmp_simple(redis_keys[i], parts[j]) == 0) count++;
                    }
                }
                char nbuf[16];
                int_to_str(count, nbuf, sizeof(nbuf));
                write_str(1, "(integer) ");
                write_str(1, nbuf);
                write_str(1, "\n");
            }
        } else if (strcmp_simple(parts[0], "INFO") == 0 || strcmp_simple(parts[0], "info") == 0) {
            write_str(1, "# Server\nredis_version:7.2.4\nos:Futura OS\n");
        } else {
            write_str(1, "(error) ERR unknown command '");
            write_str(1, parts[0]);
            write_str(1, "'\n");
        }
    }
}

/* docker - Simulated Docker CLI */
static void cmd_docker(int argc, char *argv[]) {
    if (argc < 2 || strcmp_simple(argv[1], "--help") == 0) {
        write_str(1, "Usage: docker [OPTIONS] COMMAND\n\n");
        write_str(1, "A self-sufficient runtime for containers\n\n");
        write_str(1, "Commands:\n");
        write_str(1, "  build       Build an image from a Dockerfile\n");
        write_str(1, "  images      List images\n");
        write_str(1, "  ps          List containers\n");
        write_str(1, "  pull        Download an image from a registry\n");
        write_str(1, "  run         Create and run a new container\n");
        write_str(1, "  stop        Stop running containers\n");
        write_str(1, "  version     Show the Docker version information\n");
        return;
    }
    if (strcmp_simple(argv[1], "version") == 0 || strcmp_simple(argv[1], "--version") == 0) {
        write_str(1, "Docker version 27.1.1, build 6312585 (futura)\n");
        write_str(1, "  API version:  1.46\n");
        write_str(1, "  Go version:   go1.22.5\n");
        write_str(1, "  OS/Arch:      futura/amd64\n");
        return;
    }
    if (strcmp_simple(argv[1], "ps") == 0) {
        write_str(1, "CONTAINER ID   IMAGE     COMMAND   CREATED   STATUS    PORTS     NAMES\n");
        if (argc >= 3 && strcmp_simple(argv[2], "-a") == 0) {
            write_str(1, "a1b2c3d4e5f6   nginx:latest   \"/docker-entry...\"   2 hours ago   Exited (0)             web-server\n");
            write_str(1, "f6e5d4c3b2a1   redis:7        \"redis-server\"       3 hours ago   Exited (0)             cache\n");
        }
        return;
    }
    if (strcmp_simple(argv[1], "images") == 0) {
        write_str(1, "REPOSITORY   TAG       IMAGE ID       CREATED        SIZE\n");
        write_str(1, "nginx        latest    a8758716bb6a   2 weeks ago    187MB\n");
        write_str(1, "redis        7         7614ae9453d1   3 weeks ago    116MB\n");
        write_str(1, "alpine       3.19      05455a08881e   4 weeks ago    7.38MB\n");
        return;
    }
    if (strcmp_simple(argv[1], "run") == 0) {
        if (argc < 3) {
            write_str(2, "docker: requires at least 1 argument.\n");
            return;
        }
        write_str(1, "Unable to find image '");
        write_str(1, argv[argc - 1]);
        write_str(1, "' locally\n");
        write_str(1, "Pulling from library/");
        write_str(1, argv[argc - 1]);
        write_str(1, "\nDigest: sha256:a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2\n");
        write_str(1, "Status: Downloaded newer image\n");
        return;
    }
    if (strcmp_simple(argv[1], "build") == 0) {
        if (argc < 3) {
            write_str(2, "docker build requires exactly 1 argument.\n");
            return;
        }
        write_str(1, "[+] Building 0.0s (0/0)\n");
        write_str(1, " => [internal] load build definition from Dockerfile\n");
        write_str(1, " => [internal] load metadata\n");
        write_str(1, " => CACHED [1/1] FROM docker.io/library/alpine:3.19\n");
        write_str(1, " => exporting to image\n");
        write_str(1, " => => naming to docker.io/library/myimage:latest\n");
        return;
    }
    if (strcmp_simple(argv[1], "pull") == 0) {
        if (argc < 3) {
            write_str(2, "docker pull requires exactly 1 argument.\n");
            return;
        }
        write_str(1, "Using default tag: latest\n");
        write_str(1, "latest: Pulling from library/");
        write_str(1, argv[2]);
        write_str(1, "\nDigest: sha256:abcdef1234567890abcdef1234567890abcdef1234567890abcdef1234567890\n");
        write_str(1, "Status: Image is up to date for ");
        write_str(1, argv[2]);
        write_str(1, ":latest\n");
        return;
    }
    if (strcmp_simple(argv[1], "stop") == 0) {
        if (argc < 3) {
            write_str(2, "docker stop requires at least 1 argument.\n");
            return;
        }
        write_str(1, argv[2]);
        write_str(1, "\n");
        return;
    }
    if (strcmp_simple(argv[1], "info") == 0) {
        write_str(1, "Client: Docker Engine - Community\n");
        write_str(1, " Version:    27.1.1\n");
        write_str(1, "Server:\n");
        write_str(1, " Containers: 2\n  Running: 0\n  Paused: 0\n  Stopped: 2\n");
        write_str(1, " Images: 3\n");
        write_str(1, " Storage Driver: overlay2\n");
        write_str(1, " Operating System: Futura OS\n");
        write_str(1, " Architecture: x86_64\n");
        return;
    }
    write_str(2, "docker: '");
    write_str(2, argv[1]);
    write_str(2, "' is not a docker command.\n");
}

/* kubectl - Simulated Kubernetes CLI */
static void cmd_kubectl(int argc, char *argv[]) {
    if (argc < 2 || strcmp_simple(argv[1], "--help") == 0) {
        write_str(1, "kubectl controls the Kubernetes cluster manager.\n\n");
        write_str(1, "Usage: kubectl [command]\n\n");
        write_str(1, "Commands:\n");
        write_str(1, "  apply       Apply a configuration to a resource\n");
        write_str(1, "  create      Create a resource\n");
        write_str(1, "  delete      Delete resources\n");
        write_str(1, "  describe    Show details of a resource\n");
        write_str(1, "  get         Display one or many resources\n");
        write_str(1, "  logs        Print the logs for a container\n");
        write_str(1, "  version     Print client and server version\n");
        return;
    }
    if (strcmp_simple(argv[1], "version") == 0) {
        write_str(1, "Client Version: v1.30.2\n");
        write_str(1, "Kustomize Version: v5.0.4-0\n");
        write_str(1, "Server Version: v1.30.2\n");
        return;
    }
    if (strcmp_simple(argv[1], "get") == 0) {
        if (argc < 3) {
            write_str(2, "error: Required resource not specified.\n");
            return;
        }
        if (strcmp_simple(argv[2], "pods") == 0 || strcmp_simple(argv[2], "pod") == 0) {
            write_str(1, "NAME                        READY   STATUS    RESTARTS   AGE\n");
            write_str(1, "nginx-deployment-abc12       1/1     Running   0          24h\n");
            write_str(1, "redis-master-def34           1/1     Running   0          12h\n");
            write_str(1, "api-server-ghi56             1/1     Running   1          3d\n");
        } else if (strcmp_simple(argv[2], "nodes") == 0 || strcmp_simple(argv[2], "node") == 0) {
            write_str(1, "NAME           STATUS   ROLES           AGE   VERSION\n");
            write_str(1, "futura-node1   Ready    control-plane   30d   v1.30.2\n");
            write_str(1, "futura-node2   Ready    <none>          30d   v1.30.2\n");
        } else if (strcmp_simple(argv[2], "services") == 0 || strcmp_simple(argv[2], "svc") == 0) {
            write_str(1, "NAME         TYPE        CLUSTER-IP     EXTERNAL-IP   PORT(S)   AGE\n");
            write_str(1, "kubernetes   ClusterIP   10.96.0.1      <none>        443/TCP   30d\n");
            write_str(1, "nginx-svc    ClusterIP   10.96.45.12    <none>        80/TCP    24h\n");
        } else if (strcmp_simple(argv[2], "namespaces") == 0 || strcmp_simple(argv[2], "ns") == 0) {
            write_str(1, "NAME              STATUS   AGE\n");
            write_str(1, "default           Active   30d\n");
            write_str(1, "kube-system       Active   30d\n");
            write_str(1, "kube-public       Active   30d\n");
        } else if (strcmp_simple(argv[2], "deployments") == 0 || strcmp_simple(argv[2], "deploy") == 0) {
            write_str(1, "NAME               READY   UP-TO-DATE   AVAILABLE   AGE\n");
            write_str(1, "nginx-deployment   1/1     1            1           24h\n");
            write_str(1, "api-server         1/1     1            1           3d\n");
        } else {
            write_str(1, "No resources found in default namespace.\n");
        }
        return;
    }
    if (strcmp_simple(argv[1], "describe") == 0) {
        if (argc < 3) {
            write_str(2, "error: Required resource not specified.\n");
            return;
        }
        if (strcmp_simple(argv[2], "pod") == 0 || strcmp_simple(argv[2], "pods") == 0) {
            const char *name = (argc >= 4) ? argv[3] : "nginx-deployment-abc12";
            write_str(1, "Name:         ");
            write_str(1, name);
            write_str(1, "\nNamespace:    default\n");
            write_str(1, "Node:         futura-node1/10.0.0.1\n");
            write_str(1, "Status:       Running\n");
            write_str(1, "IP:           10.244.0.5\n");
            write_str(1, "Containers:\n");
            write_str(1, "  nginx:\n    Image:   nginx:latest\n    Port:    80/TCP\n    State:   Running\n");
        } else if (strcmp_simple(argv[2], "node") == 0 || strcmp_simple(argv[2], "nodes") == 0) {
            write_str(1, "Name:         futura-node1\n");
            write_str(1, "Roles:        control-plane\n");
            write_str(1, "OS Image:     Futura OS\n");
            write_str(1, "Kernel:       futura 1.0\n");
            write_str(1, "CPU:          4\n");
            write_str(1, "Memory:       8192Mi\n");
        } else {
            write_str(1, "Name:         ");
            write_str(1, argv[2]);
            write_str(1, "\nNamespace:    default\n");
        }
        return;
    }
    if (strcmp_simple(argv[1], "apply") == 0) {
        if (argc >= 4 && strcmp_simple(argv[2], "-f") == 0) {
            write_str(1, "resource configured from '");
            write_str(1, argv[3]);
            write_str(1, "'\n");
        } else {
            write_str(2, "error: must specify -f <filename>\n");
        }
        return;
    }
    if (strcmp_simple(argv[1], "delete") == 0) {
        if (argc < 3) {
            write_str(2, "error: Required resource not specified.\n");
            return;
        }
        write_str(1, argv[2]);
        if (argc >= 4) {
            write_str(1, " \"");
            write_str(1, argv[3]);
            write_str(1, "\" deleted\n");
        } else {
            write_str(1, " deleted\n");
        }
        return;
    }
    if (strcmp_simple(argv[1], "logs") == 0) {
        if (argc < 3) {
            write_str(2, "error: expected pod name\n");
            return;
        }
        write_str(1, "2024-01-15T10:30:00Z Starting application...\n");
        write_str(1, "2024-01-15T10:30:01Z Listening on port 8080\n");
        write_str(1, "2024-01-15T10:30:05Z Ready to accept connections\n");
        return;
    }
    if (strcmp_simple(argv[1], "cluster-info") == 0) {
        write_str(1, "Kubernetes control plane is running at https://10.0.0.1:6443\n");
        write_str(1, "CoreDNS is running at https://10.0.0.1:6443/api/v1/namespaces/kube-system/services/kube-dns:dns/proxy\n");
        return;
    }
    write_str(2, "error: unknown command \"");
    write_str(2, argv[1]);
    write_str(2, "\"\n");
}

/* terraform - Simulated IaC CLI */
static void cmd_terraform(int argc, char *argv[]) {
    if (argc < 2 || strcmp_simple(argv[1], "--help") == 0) {
        write_str(1, "Usage: terraform [global options] <subcommand> [args]\n\n");
        write_str(1, "Main commands:\n");
        write_str(1, "  init          Prepare your working directory\n");
        write_str(1, "  validate      Check whether the configuration is valid\n");
        write_str(1, "  plan          Show changes required by the current configuration\n");
        write_str(1, "  apply         Create or update infrastructure\n");
        write_str(1, "  destroy       Destroy previously-created infrastructure\n");
        return;
    }
    if (strcmp_simple(argv[1], "version") == 0 || strcmp_simple(argv[1], "--version") == 0) {
        write_str(1, "Terraform v1.9.2\non futura_amd64\n");
        return;
    }
    if (strcmp_simple(argv[1], "init") == 0) {
        write_str(1, "\n\033[1mInitializing the backend...\033[0m\n\n");
        write_str(1, "\033[1mInitializing provider plugins...\033[0m\n");
        write_str(1, "- Finding latest version of hashicorp/aws...\n");
        write_str(1, "- Installing hashicorp/aws v5.60.0...\n");
        write_str(1, "- Installed hashicorp/aws v5.60.0 (signed by HashiCorp)\n\n");
        write_str(1, "\033[32m\033[1mTerraform has been successfully initialized!\033[0m\n");
        return;
    }
    if (strcmp_simple(argv[1], "plan") == 0) {
        write_str(1, "\nTerraform used the selected providers to generate the following execution plan.\n\n");
        write_str(1, "  \033[32m+\033[0m aws_instance.web\n");
        write_str(1, "      + ami           = \"ami-0abcdef1234567890\"\n");
        write_str(1, "      + instance_type = \"t3.micro\"\n");
        write_str(1, "      + tags          = { Name = \"web-server\" }\n\n");
        write_str(1, "\033[1mPlan:\033[0m 1 to add, 0 to change, 0 to destroy.\n");
        return;
    }
    if (strcmp_simple(argv[1], "apply") == 0) {
        write_str(1, "\n\033[1maws_instance.web: Creating...\033[0m\n");
        write_str(1, "\033[1maws_instance.web: Still creating... [10s elapsed]\033[0m\n");
        write_str(1, "\033[1maws_instance.web: Creation complete after 15s [id=i-0abcdef1234567890]\033[0m\n\n");
        write_str(1, "\033[32m\033[1mApply complete! Resources: 1 added, 0 changed, 0 destroyed.\033[0m\n");
        return;
    }
    if (strcmp_simple(argv[1], "destroy") == 0) {
        write_str(1, "\n\033[1maws_instance.web: Destroying... [id=i-0abcdef1234567890]\033[0m\n");
        write_str(1, "\033[1maws_instance.web: Destruction complete after 5s\033[0m\n\n");
        write_str(1, "\033[32m\033[1mDestroy complete! Resources: 1 destroyed.\033[0m\n");
        return;
    }
    if (strcmp_simple(argv[1], "validate") == 0) {
        write_str(1, "\033[32m\033[1mSuccess!\033[0m The configuration is valid.\n");
        return;
    }
    if (strcmp_simple(argv[1], "fmt") == 0) {
        write_str(1, "main.tf\n");
        return;
    }
    if (strcmp_simple(argv[1], "output") == 0) {
        write_str(1, "instance_ip = \"10.0.1.42\"\n");
        write_str(1, "instance_id = \"i-0abcdef1234567890\"\n");
        return;
    }
    write_str(2, "Terraform has no command named \"");
    write_str(2, argv[1]);
    write_str(2, "\".\n");
}

/* ansible - Simulated config management CLI */
static void cmd_ansible(int argc, char *argv[]) {
    int is_playbook = (strcmp_simple(argv[0], "ansible-playbook") == 0);

    if (is_playbook) {
        if (argc < 2) {
            write_str(2, "usage: ansible-playbook [-h] playbook.yml\n");
            return;
        }
        if (strcmp_simple(argv[1], "--version") == 0) {
            write_str(1, "ansible-playbook [core 2.17.1] (futura)\n");
            write_str(1, "  config file = /etc/ansible/ansible.cfg\n");
            write_str(1, "  python version = 3.12.0\n");
            return;
        }
        write_str(1, "\nPLAY [all] *****************************************************************\n\n");
        write_str(1, "TASK [Gathering Facts] ****************************************************\n");
        write_str(1, "\033[32mok: [localhost]\033[0m\n\n");
        write_str(1, "TASK [Install packages] ***************************************************\n");
        write_str(1, "\033[33mchanged: [localhost]\033[0m\n\n");
        write_str(1, "PLAY RECAP ****************************************************************\n");
        write_str(1, "\033[33mlocalhost\033[0m : ok=2  changed=1  unreachable=0  failed=0  skipped=0\n\n");
        return;
    }

    /* ansible command */
    if (argc < 2 || strcmp_simple(argv[1], "--help") == 0) {
        write_str(1, "usage: ansible [-h] [--version] [-m MODULE] [-a ARGS] pattern\n\n");
        write_str(1, "Define and run a single task 'playbook' against a set of hosts.\n\n");
        write_str(1, "Options:\n");
        write_str(1, "  --version       show program's version number and exit\n");
        write_str(1, "  -m MODULE       Name of the module to execute\n");
        write_str(1, "  -a ARGS         Module arguments\n");
        return;
    }
    if (strcmp_simple(argv[1], "--version") == 0) {
        write_str(1, "ansible [core 2.17.1] (futura)\n");
        write_str(1, "  config file = /etc/ansible/ansible.cfg\n");
        write_str(1, "  python version = 3.12.0\n");
        write_str(1, "  jinja version = 3.1.4\n");
        write_str(1, "  libyaml = True\n");
        return;
    }
    /* ansible <host> -m <module> -a <args> */
    const char *host = argv[1];
    const char *module = "command";
    for (int i = 2; i < argc - 1; i++) {
        if (strcmp_simple(argv[i], "-m") == 0) module = argv[i + 1];
    }
    write_str(1, "\033[32m");
    write_str(1, host);
    write_str(1, " | SUCCESS => {\n");
    write_str(1, "    \"changed\": false,\n");
    write_str(1, "    \"module\": \"");
    write_str(1, module);
    write_str(1, "\",\n");
    write_str(1, "    \"rc\": 0\n");
    write_str(1, "}\033[0m\n");
}

/* vagrant - Simulated VM management CLI */
static void cmd_vagrant(int argc, char *argv[]) {
    if (argc < 2 || strcmp_simple(argv[1], "--help") == 0) {
        write_str(1, "Usage: vagrant [options] <command> [<args>]\n\n");
        write_str(1, "Common commands:\n");
        write_str(1, "  destroy       stops and deletes all traces of the vagrant machine\n");
        write_str(1, "  halt          stops the vagrant machine\n");
        write_str(1, "  init          initializes a new Vagrant environment\n");
        write_str(1, "  ssh           connects to machine via SSH\n");
        write_str(1, "  status        outputs status of the vagrant machine\n");
        write_str(1, "  up            starts and provisions the vagrant environment\n");
        return;
    }
    if (strcmp_simple(argv[1], "version") == 0 || strcmp_simple(argv[1], "--version") == 0) {
        write_str(1, "Vagrant 2.4.1 (futura)\n");
        return;
    }
    if (strcmp_simple(argv[1], "up") == 0) {
        write_str(1, "Bringing machine 'default' up with 'virtualbox' provider...\n");
        write_str(1, "==> default: Importing base box 'ubuntu/jammy64'...\n");
        write_str(1, "==> default: Matching MAC address for NAT networking...\n");
        write_str(1, "==> default: Setting the name of the VM: project_default\n");
        write_str(1, "==> default: Booting VM...\n");
        write_str(1, "==> default: Waiting for machine to boot...\n");
        write_str(1, "    default: SSH address: 127.0.0.1:2222\n");
        write_str(1, "==> default: Machine booted and ready!\n");
        return;
    }
    if (strcmp_simple(argv[1], "ssh") == 0) {
        write_str(1, "Welcome to Ubuntu 22.04 LTS (GNU/Linux 5.15.0-generic x86_64)\n\n");
        write_str(1, "vagrant@default:~$ (use 'exit' to leave)\n");
        return;
    }
    if (strcmp_simple(argv[1], "halt") == 0) {
        write_str(1, "==> default: Attempting graceful shutdown of VM...\n");
        write_str(1, "==> default: Forcing shutdown of VM...\n");
        return;
    }
    if (strcmp_simple(argv[1], "status") == 0) {
        write_str(1, "Current machine states:\n\n");
        write_str(1, "default                   running (virtualbox)\n\n");
        write_str(1, "The VM is running. To stop this VM, you can run `vagrant halt`.\n");
        return;
    }
    if (strcmp_simple(argv[1], "destroy") == 0) {
        write_str(1, "==> default: Destroying VM and associated drives...\n");
        return;
    }
    if (strcmp_simple(argv[1], "init") == 0) {
        write_str(1, "A `Vagrantfile` has been placed in this directory. You are now\n");
        write_str(1, "ready to `vagrant up` your first virtual environment!\n");
        return;
    }
    if (strcmp_simple(argv[1], "global-status") == 0) {
        write_str(1, "id       name    provider   state    directory\n");
        write_str(1, "-----------------------------------------------------------------------\n");
        write_str(1, "a1b2c3d  default virtualbox running  /home/user/project\n\n");
        write_str(1, "The above shows information about all known Vagrant environments.\n");
        return;
    }
    write_str(2, "Unknown command: ");
    write_str(2, argv[1]);
    write_str(2, "\n");
}

/* helm - Simulated Kubernetes package manager */
static void cmd_helm(int argc, char *argv[]) {
    if (argc < 2 || strcmp_simple(argv[1], "--help") == 0) {
        write_str(1, "The Kubernetes package manager\n\n");
        write_str(1, "Usage: helm [command]\n\n");
        write_str(1, "Commands:\n");
        write_str(1, "  install     install a chart\n");
        write_str(1, "  list        list releases\n");
        write_str(1, "  repo        add, list, remove, update chart repositories\n");
        write_str(1, "  search      search for a keyword in charts\n");
        write_str(1, "  uninstall   uninstall a release\n");
        write_str(1, "  upgrade     upgrade a release\n");
        write_str(1, "  version     print the client version\n");
        return;
    }
    if (strcmp_simple(argv[1], "version") == 0 || strcmp_simple(argv[1], "--version") == 0) {
        write_str(1, "version.BuildInfo{Version:\"v3.15.3\", GitCommit:\"abc123\", GoVersion:\"go1.22.5\"}\n");
        return;
    }
    if (strcmp_simple(argv[1], "list") == 0 || strcmp_simple(argv[1], "ls") == 0) {
        write_str(1, "NAME          \tNAMESPACE\tREVISION\tSTATUS  \tCHART              \tAPP VERSION\n");
        write_str(1, "ingress-nginx \tdefault  \t1       \tdeployed\tnginx-ingress-4.7.1\t1.8.1      \n");
        write_str(1, "cert-manager  \tcert-mgr \t2       \tdeployed\tcert-manager-1.15.1\t1.15.1     \n");
        write_str(1, "prometheus    \tmonitoring\t1       \tdeployed\tprometheus-25.21.0 \t2.53.1     \n");
        return;
    }
    if (strcmp_simple(argv[1], "install") == 0) {
        if (argc < 4) {
            write_str(2, "Error: \"helm install\" requires at least 2 arguments\n");
            write_str(2, "Usage: helm install [NAME] [CHART]\n");
            return;
        }
        write_str(1, "NAME: ");
        write_str(1, argv[2]);
        write_str(1, "\nLAST DEPLOYED: 2024-01-15 10:30:00\n");
        write_str(1, "NAMESPACE: default\n");
        write_str(1, "STATUS: deployed\n");
        write_str(1, "REVISION: 1\n");
        write_str(1, "NOTES:\nThe ");
        write_str(1, argv[3]);
        write_str(1, " chart has been installed.\n");
        return;
    }
    if (strcmp_simple(argv[1], "repo") == 0) {
        if (argc < 3) {
            write_str(1, "Usage: helm repo [add|list|remove|update]\n");
            return;
        }
        if (strcmp_simple(argv[2], "list") == 0) {
            write_str(1, "NAME    \tURL\n");
            write_str(1, "stable  \thttps://charts.helm.sh/stable\n");
            write_str(1, "bitnami \thttps://charts.bitnami.com/bitnami\n");
        } else if (strcmp_simple(argv[2], "add") == 0) {
            if (argc >= 5) {
                write_str(1, "\"");
                write_str(1, argv[3]);
                write_str(1, "\" has been added to your repositories\n");
            } else {
                write_str(2, "Error: expected NAME and URL\n");
            }
        } else if (strcmp_simple(argv[2], "update") == 0) {
            write_str(1, "Hang tight while we grab the latest from your chart repositories...\n");
            write_str(1, "...Successfully got an update from the \"stable\" chart repository\n");
            write_str(1, "...Successfully got an update from the \"bitnami\" chart repository\n");
            write_str(1, "Update Complete. Happy Helming!\n");
        }
        return;
    }
    if (strcmp_simple(argv[1], "search") == 0) {
        if (argc >= 4 && strcmp_simple(argv[2], "repo") == 0) {
            write_str(1, "NAME                 \tCHART VERSION\tAPP VERSION\tDESCRIPTION\n");
            write_str(1, "bitnami/nginx        \t18.1.5       \t1.27.0     \tNGINX web server\n");
            write_str(1, "bitnami/redis        \t19.6.1       \t7.2.5      \tRedis key-value store\n");
        } else {
            write_str(2, "Usage: helm search repo [keyword]\n");
        }
        return;
    }
    if (strcmp_simple(argv[1], "uninstall") == 0) {
        if (argc < 3) {
            write_str(2, "Error: \"helm uninstall\" requires at least 1 argument\n");
            return;
        }
        write_str(1, "release \"");
        write_str(1, argv[2]);
        write_str(1, "\" uninstalled\n");
        return;
    }
    write_str(2, "Error: unknown command \"");
    write_str(2, argv[1]);
    write_str(2, "\" for \"helm\"\n");
}

