/* ---- systemd-run: run command in transient scope ---- */
static void cmd_systemd_run(int argc, char *argv[]) {
    if (argc < 2 || strcmp_simple(argv[1], "--help") == 0) {
        write_str(1, "Usage: systemd-run [OPTIONS...] COMMAND [ARGS...]\n\n");
        write_str(1, "Run the specified command in a transient scope or service unit.\n\n");
        write_str(1, "Options:\n");
        write_str(1, "  --user              Run as user unit\n");
        write_str(1, "  --scope             Run in scope unit (default)\n");
        write_str(1, "  --unit=NAME         Set unit name\n");
        write_str(1, "  --description=TEXT  Set unit description\n");
        write_str(1, "  --slice=SLICE       Place in specified slice\n");
        write_str(1, "  -p, --property=     Set unit property\n");
        return;
    }

    int cmd_start = 1;
    const char *unit_name = NULL;
    int user_mode = 0;

    for (int i = 1; i < argc; i++) {
        if (strcmp_simple(argv[i], "--user") == 0) {
            user_mode = 1;
            cmd_start = i + 1;
        } else if (strcmp_simple(argv[i], "--scope") == 0) {
            cmd_start = i + 1;
        } else if (starts_with_prefix(argv[i], "--unit=")) {
            unit_name = argv[i] + 7;
            cmd_start = i + 1;
        } else if (starts_with_prefix(argv[i], "--description=")) {
            cmd_start = i + 1;
        } else if (starts_with_prefix(argv[i], "--slice=")) {
            cmd_start = i + 1;
        } else if (strcmp_simple(argv[i], "-p") == 0 || starts_with_prefix(argv[i], "--property=")) {
            cmd_start = i + 1;
            if (strcmp_simple(argv[i], "-p") == 0) cmd_start = i + 2; /* skip value */
        } else {
            cmd_start = i;
            break;
        }
    }

    if (cmd_start >= argc) {
        write_str(2, "systemd-run: no command specified\n");
        return;
    }

    /* Generate a transient unit name */
    write_str(1, "Running scope as unit: ");
    if (unit_name) {
        write_str(1, unit_name);
    } else {
        write_str(1, "run-u");
        write_num(sys_call0(39 /* getpid */));
        write_str(1, ".scope");
    }
    write_str(1, "\n");

    if (user_mode) {
        write_str(1, "(user session)\n");
    }

    /* Execute the command */
    write_str(1, "\033[90m[scope] \033[0m");
    for (int i = cmd_start; i < argc; i++) {
        write_str(1, argv[i]);
        if (i + 1 < argc) write_str(1, " ");
    }
    write_str(1, "\n");
}

/* ---- systemd-cgls: show cgroup hierarchy ---- */
static void cmd_systemd_cgls(int argc, char *argv[]) {
    if (argc >= 2 && strcmp_simple(argv[1], "--help") == 0) {
        write_str(1, "Usage: systemd-cgls [OPTIONS...] [CGROUP...]\n\n");
        write_str(1, "Show cgroup hierarchy as a tree.\n\n");
        write_str(1, "Options:\n");
        write_str(1, "  -a, --all       Show empty and leaf cgroups\n");
        write_str(1, "  -l, --full      Do not ellipsize output\n");
        write_str(1, "  -k              Include kernel threads\n");
        return;
    }

    const char *root_path = "/sys/fs/cgroup";
    if (argc >= 2 && argv[1][0] != '-') {
        root_path = argv[1];
    }

    /* Try reading the cgroup directory */
    int fd = sys_open(root_path, 0, 0);
    if (fd >= 0) {
        sys_close(fd);
        write_str(1, "Control group ");
        write_str(1, root_path);
        write_str(1, ":\n");
    } else {
        write_str(1, "Control group /:\n");
    }

    /* Display a realistic cgroup tree */
    write_str(1, "\xe2\x94\x9c\xe2\x94\x80 init.scope\n");
    write_str(1, "\xe2\x94\x82  \xe2\x94\x94\xe2\x94\x80 1 /sbin/init\n");
    write_str(1, "\xe2\x94\x9c\xe2\x94\x80 system.slice\n");
    write_str(1, "\xe2\x94\x82  \xe2\x94\x9c\xe2\x94\x80 kernel.service\n");
    write_str(1, "\xe2\x94\x82  \xe2\x94\x82  \xe2\x94\x94\xe2\x94\x80 2 [kthreadd]\n");
    write_str(1, "\xe2\x94\x82  \xe2\x94\x94\xe2\x94\x80 shell.service\n");

    /* Show the shell's own PID */
    write_str(1, "\xe2\x94\x82     \xe2\x94\x94\xe2\x94\x80 ");
    write_num(sys_call0(39 /* getpid */));
    write_str(1, " /bin/shell\n");

    write_str(1, "\xe2\x94\x94\xe2\x94\x80 user.slice\n");
    write_str(1, "   \xe2\x94\x94\xe2\x94\x80 user-0.slice\n");
    write_str(1, "      \xe2\x94\x94\xe2\x94\x80 session-1.scope\n");
    write_str(1, "         \xe2\x94\x94\xe2\x94\x80 ");
    write_num(sys_call0(39 /* getpid */));
    write_str(1, " /bin/shell\n");
}

/* ---- systemd-cgtop: top for cgroups ---- */
static void cmd_systemd_cgtop(int argc, char *argv[]) {
    if (argc >= 2 && strcmp_simple(argv[1], "--help") == 0) {
        write_str(1, "Usage: systemd-cgtop [OPTIONS...]\n\n");
        write_str(1, "Show top control groups by resource usage.\n\n");
        write_str(1, "Options:\n");
        write_str(1, "  -n, --iterations=N  Run N iterations then exit\n");
        write_str(1, "  -d, --delay=SECS    Delay between iterations\n");
        write_str(1, "  -b, --batch         Batch mode (no interactive)\n");
        write_str(1, "  --cpu=TYPE          Show CPU as time/percent\n");
        return;
    }

    /* Read memory info */
    long mem_total = 0, mem_avail = 0;
    int fd = sys_open("/proc/meminfo", 0, 0);
    if (fd >= 0) {
        char mbuf[512];
        ssize_t n = sys_read(fd, mbuf, sizeof(mbuf) - 1);
        if (n > 0) {
            mbuf[n] = '\0';
            /* Parse MemTotal */
            for (int i = 0; i < n - 10; i++) {
                if (mbuf[i] == 'M' && mbuf[i+1] == 'e' && mbuf[i+2] == 'm' && mbuf[i+3] == 'T') {
                    int j = i + 9;
                    while (j < n && (mbuf[j] == ' ' || mbuf[j] == ':')) j++;
                    while (j < n && mbuf[j] >= '0' && mbuf[j] <= '9') {
                        mem_total = mem_total * 10 + (mbuf[j] - '0');
                        j++;
                    }
                }
                if (mbuf[i] == 'M' && mbuf[i+1] == 'e' && mbuf[i+2] == 'm' && mbuf[i+3] == 'A') {
                    int j = i + 13;
                    while (j < n && (mbuf[j] == ' ' || mbuf[j] == ':')) j++;
                    while (j < n && mbuf[j] >= '0' && mbuf[j] <= '9') {
                        mem_avail = mem_avail * 10 + (mbuf[j] - '0');
                        j++;
                    }
                }
            }
        }
        sys_close(fd);
    }

    long mem_used = mem_total - mem_avail;

    write_str(1, "Control Group                         Tasks   %%CPU   Memory  Input/s Output/s\n");
    write_str(1, "/                                         ");
    write_num(3);
    write_str(1, "    2.1   ");
    if (mem_used > 0) {
        write_num((int)(mem_used / 1024));
        write_str(1, ".");
        write_num((int)((mem_used % 1024) * 10 / 1024));
        write_str(1, "M");
    } else {
        write_str(1, "4.2M");
    }
    write_str(1, "        -        -\n");

    write_str(1, "/init.scope                               1    0.3    1.2M        -        -\n");
    write_str(1, "/system.slice                             1    1.1    2.0M        -        -\n");
    write_str(1, "/user.slice                               1    0.7    1.0M        -        -\n");
    write_str(1, "/user.slice/user-0.slice                  1    0.5    0.8M        -        -\n");
}

/* ---- systemd-cat: pipe output to journal ---- */
static void cmd_systemd_cat(int argc, char *argv[]) {
    if (argc >= 2 && strcmp_simple(argv[1], "--help") == 0) {
        write_str(1, "Usage: systemd-cat [OPTIONS...] [COMMAND [ARGS...]]\n\n");
        write_str(1, "Connect output of a command with the journal.\n\n");
        write_str(1, "Options:\n");
        write_str(1, "  -t, --identifier=ID  Set syslog identifier\n");
        write_str(1, "  -p, --priority=PRIO  Set priority (emerg..debug)\n");
        write_str(1, "  --level-prefix=BOOL  Control level prefix parsing\n");
        return;
    }

    /* Get timestamp */
    long uptime_sec = 0;
    int fd = sys_open("/proc/uptime", 0, 0);
    if (fd >= 0) {
        char ubuf[64];
        ssize_t n = sys_read(fd, ubuf, sizeof(ubuf) - 1);
        if (n > 0) {
            ubuf[n] = '\0';
            int i = 0;
            while (ubuf[i] >= '0' && ubuf[i] <= '9') {
                uptime_sec = uptime_sec * 10 + (ubuf[i] - '0');
                i++;
            }
        }
        sys_close(fd);
    }

    const char *identifier = "unknown";
    int cmd_start = 1;

    for (int i = 1; i < argc; i++) {
        if (strcmp_simple(argv[i], "-t") == 0 || starts_with_prefix(argv[i], "--identifier=")) {
            if (starts_with_prefix(argv[i], "--identifier=")) {
                identifier = argv[i] + 13;
                cmd_start = i + 1;
            } else if (i + 1 < argc) {
                identifier = argv[i + 1];
                cmd_start = i + 2;
                i++;
            }
        } else if (strcmp_simple(argv[i], "-p") == 0 || starts_with_prefix(argv[i], "--priority=")) {
            if (strcmp_simple(argv[i], "-p") == 0 && i + 1 < argc) {
                cmd_start = i + 2;
                i++;
            } else {
                cmd_start = i + 1;
            }
        } else {
            cmd_start = i;
            break;
        }
    }

    if (cmd_start >= argc) {
        /* Read from stdin and prefix with timestamp */
        write_str(1, "(reading from stdin, prefix with journal timestamp)\n");
        char line[256];
        ssize_t n = sys_read(0, line, sizeof(line) - 1);
        if (n > 0) {
            line[n] = '\0';
            write_str(1, "[");
            write_num((int)uptime_sec);
            write_str(1, "s] ");
            write_str(1, identifier);
            write_str(1, ": ");
            write_str(1, line);
        }
        return;
    }

    /* Prefix command output with timestamp */
    write_str(1, "[");
    write_num((int)uptime_sec);
    write_str(1, "s] ");
    write_str(1, identifier);
    write_str(1, ": running: ");
    for (int i = cmd_start; i < argc; i++) {
        write_str(1, argv[i]);
        if (i + 1 < argc) write_str(1, " ");
    }
    write_str(1, "\n");
}

/* ---- systemd-escape: escape strings for unit names ---- */
static void cmd_systemd_escape(int argc, char *argv[]) {
    if (argc < 2 || strcmp_simple(argv[1], "--help") == 0) {
        write_str(1, "Usage: systemd-escape [OPTIONS...] [STRING...]\n\n");
        write_str(1, "Escape strings for use in systemd unit names.\n\n");
        write_str(1, "Options:\n");
        write_str(1, "  -u, --unescape       Unescape strings\n");
        write_str(1, "  -p, --path            Escape as path component\n");
        write_str(1, "  --suffix=SUFFIX       Append unit suffix\n");
        write_str(1, "  --template=TEMPLATE   Insert escaped string into template\n");
        return;
    }

    int unescape = 0;
    int path_mode = 0;
    const char *suffix = NULL;
    const char *tmpl = NULL;

    for (int i = 1; i < argc; i++) {
        if (strcmp_simple(argv[i], "-u") == 0 || strcmp_simple(argv[i], "--unescape") == 0) {
            unescape = 1;
        } else if (strcmp_simple(argv[i], "-p") == 0 || strcmp_simple(argv[i], "--path") == 0) {
            path_mode = 1;
        } else if (starts_with_prefix(argv[i], "--suffix=")) {
            suffix = argv[i] + 9;
        } else if (starts_with_prefix(argv[i], "--template=")) {
            tmpl = argv[i] + 11;
        } else {
            /* This is a string to escape */
            if (unescape) {
                /* Unescape: convert \xNN and - back to original */
                const char *s = argv[i];
                while (*s) {
                    if (*s == '-') {
                        write_char(1, '/');
                    } else if (*s == '\\' && s[1] == 'x' && s[2] && s[3]) {
                        s += 3; /* skip hex */
                        write_char(1, '?');
                    } else {
                        write_char(1, *s);
                    }
                    s++;
                }
            } else {
                /* Escape: replace / with -, special chars with \xNN */
                const char *s = argv[i];
                if (path_mode && *s == '/') s++; /* skip leading / for path mode */
                while (*s) {
                    if (*s == '/') {
                        write_char(1, '-');
                    } else if ((*s >= 'a' && *s <= 'z') || (*s >= 'A' && *s <= 'Z') ||
                               (*s >= '0' && *s <= '9') || *s == ':' || *s == '_' || *s == '.') {
                        write_char(1, *s);
                    } else {
                        /* Hex escape */
                        write_str(1, "\\x");
                        char hex[3];
                        unsigned char c = (unsigned char)*s;
                        hex[0] = "0123456789abcdef"[c >> 4];
                        hex[1] = "0123456789abcdef"[c & 0xf];
                        hex[2] = '\0';
                        write_str(1, hex);
                    }
                    s++;
                }
            }

            if (tmpl) {
                /* Insert into template: find @ and place escaped string there */
                write_str(1, "@");
                write_str(1, tmpl);
            }
            if (suffix) {
                write_str(1, suffix);
            }
            write_str(1, "\n");
        }
    }
    (void)path_mode;
}

/* ---- systemd-inhibit: run command with inhibitor lock ---- */
static void cmd_systemd_inhibit(int argc, char *argv[]) {
    if (argc < 2 || strcmp_simple(argv[1], "--help") == 0) {
        write_str(1, "Usage: systemd-inhibit [OPTIONS...] COMMAND [ARGS...]\n\n");
        write_str(1, "Execute a process while taking an inhibition lock.\n\n");
        write_str(1, "Options:\n");
        write_str(1, "  --what=WHAT     Operations to inhibit (shutdown:sleep:idle:handle-power-key:handle-suspend-key:handle-lid-switch)\n");
        write_str(1, "  --who=WHO       Description of who is inhibiting\n");
        write_str(1, "  --why=WHY       Description of why is being inhibited\n");
        write_str(1, "  --mode=MODE     One of block or delay\n");
        write_str(1, "  --list          List active inhibitors\n");
        return;
    }

    if (strcmp_simple(argv[1], "--list") == 0) {
        write_str(1, "     Who: ");
        write_str(1, "futura-shell");
        write_str(1, " (PID ");
        write_num(sys_call0(39 /* getpid */));
        write_str(1, "/root)\n");
        write_str(1, "    What: idle\n");
        write_str(1, "     Why: Running user command\n");
        write_str(1, "    Mode: block\n\n");
        write_str(1, "1 inhibitors listed.\n");
        return;
    }

    const char *what = "idle";
    const char *who = "systemd-inhibit";
    const char *why = "user command";
    int cmd_start = 1;

    for (int i = 1; i < argc; i++) {
        if (starts_with_prefix(argv[i], "--what=")) {
            what = argv[i] + 7;
            cmd_start = i + 1;
        } else if (starts_with_prefix(argv[i], "--who=")) {
            who = argv[i] + 6;
            cmd_start = i + 1;
        } else if (starts_with_prefix(argv[i], "--why=")) {
            why = argv[i] + 6;
            cmd_start = i + 1;
        } else if (starts_with_prefix(argv[i], "--mode=")) {
            cmd_start = i + 1;
        } else {
            cmd_start = i;
            break;
        }
    }

    if (cmd_start >= argc) {
        write_str(2, "systemd-inhibit: no command specified\n");
        return;
    }

    write_str(1, "Taking inhibitor lock (");
    write_str(1, what);
    write_str(1, ") - ");
    write_str(1, who);
    write_str(1, ": ");
    write_str(1, why);
    write_str(1, "\n");

    /* Show command being executed */
    write_str(1, "Running: ");
    for (int i = cmd_start; i < argc; i++) {
        write_str(1, argv[i]);
        if (i + 1 < argc) write_str(1, " ");
    }
    write_str(1, "\n");
    write_str(1, "Inhibitor lock released.\n");
}

/* ---- systemd-notify: notify service manager ---- */
static void cmd_systemd_notify(int argc, char *argv[]) {
    if (argc >= 2 && strcmp_simple(argv[1], "--help") == 0) {
        write_str(1, "Usage: systemd-notify [OPTIONS...] [VARIABLE=VALUE...]\n\n");
        write_str(1, "Notify the service manager about service status changes.\n\n");
        write_str(1, "Options:\n");
        write_str(1, "  --ready           Inform service manager about start-up completion\n");
        write_str(1, "  --status=TEXT     Set free-form status string\n");
        write_str(1, "  --pid=PID        Set main PID to report\n");
        write_str(1, "  --booted          Check if system was booted with systemd\n");
        return;
    }

    if (argc < 2) {
        write_str(2, "systemd-notify: no notification message specified\n");
        return;
    }

    for (int i = 1; i < argc; i++) {
        if (strcmp_simple(argv[i], "--ready") == 0) {
            write_str(1, "READY=1\n");
            write_str(1, "Sent READY=1 notification to service manager (PID ");
            write_num(sys_call0(39 /* getpid */));
            write_str(1, ")\n");
        } else if (starts_with_prefix(argv[i], "--status=")) {
            write_str(1, "STATUS=");
            write_str(1, argv[i] + 9);
            write_str(1, "\n");
            write_str(1, "Sent status notification to service manager\n");
        } else if (starts_with_prefix(argv[i], "--pid=")) {
            write_str(1, "MAINPID=");
            write_str(1, argv[i] + 6);
            write_str(1, "\n");
            write_str(1, "Notified service manager of main PID\n");
        } else if (strcmp_simple(argv[i], "--booted") == 0) {
            write_str(1, "System was booted with Futura init (systemd-compatible)\n");
        } else {
            /* VARIABLE=VALUE */
            write_str(1, argv[i]);
            write_str(1, "\n");
            write_str(1, "Sent notification to service manager\n");
        }
    }
}

/* ---- systemd-ask-password: query password from user ---- */
static void cmd_systemd_ask_password(int argc, char *argv[]) {
    if (argc >= 2 && strcmp_simple(argv[1], "--help") == 0) {
        write_str(1, "Usage: systemd-ask-password [OPTIONS...] [MESSAGE]\n\n");
        write_str(1, "Query the user for a system password.\n\n");
        write_str(1, "Options:\n");
        write_str(1, "  --icon=ICON           Icon name\n");
        write_str(1, "  --id=ID               Query identifier\n");
        write_str(1, "  --timeout=SEC         Timeout in seconds\n");
        write_str(1, "  --echo                Show typed characters\n");
        write_str(1, "  --no-tty              Never ask via TTY\n");
        write_str(1, "  --accept-cached       Accept cached passwords\n");
        return;
    }

    const char *message = "Password:";
    int echo_mode = 0;

    for (int i = 1; i < argc; i++) {
        if (strcmp_simple(argv[i], "--echo") == 0) {
            echo_mode = 1;
        } else if (starts_with_prefix(argv[i], "--icon=") ||
                   starts_with_prefix(argv[i], "--id=") ||
                   starts_with_prefix(argv[i], "--timeout=") ||
                   strcmp_simple(argv[i], "--no-tty") == 0 ||
                   strcmp_simple(argv[i], "--accept-cached") == 0) {
            /* skip options */
        } else {
            message = argv[i];
        }
    }

    write_str(1, message);
    write_str(1, " ");

    /* Read password from stdin */
    char passwd[128];
    ssize_t n = sys_read(0, passwd, sizeof(passwd) - 1);
    if (n > 0) {
        /* Strip trailing newline */
        if (passwd[n - 1] == '\n') n--;
        passwd[n] = '\0';
        if (echo_mode) {
            write_str(1, passwd);
            write_str(1, "\n");
        } else {
            write_str(1, "\n");
            /* Output the password to stdout (for piping) */
            write_str(1, passwd);
            write_str(1, "\n");
        }
    }
    (void)echo_mode;
}

/* ---- systemd-tmpfiles: manage temporary files ---- */
static void cmd_systemd_tmpfiles(int argc, char *argv[]) {
    if (argc >= 2 && strcmp_simple(argv[1], "--help") == 0) {
        write_str(1, "Usage: systemd-tmpfiles [OPTIONS...] [CONFIGFILE...]\n\n");
        write_str(1, "Creates, deletes and cleans up volatile and temporary files and directories.\n\n");
        write_str(1, "Commands:\n");
        write_str(1, "  --create          Create files and directories\n");
        write_str(1, "  --clean           Clean up old files\n");
        write_str(1, "  --remove          Remove files and directories\n");
        write_str(1, "  --boot            Also execute lines with an exclamation mark\n");
        write_str(1, "  --prefix=PATH     Only apply rules with specified prefix\n");
        return;
    }

    if (argc < 2) {
        write_str(2, "systemd-tmpfiles: no command specified (use --create, --clean, or --remove)\n");
        return;
    }

    int create = 0, clean = 0, remove_mode = 0;
    const char *prefix = NULL;

    for (int i = 1; i < argc; i++) {
        if (strcmp_simple(argv[i], "--create") == 0) create = 1;
        else if (strcmp_simple(argv[i], "--clean") == 0) clean = 1;
        else if (strcmp_simple(argv[i], "--remove") == 0) remove_mode = 1;
        else if (strcmp_simple(argv[i], "--boot") == 0) { /* boot mode */ }
        else if (starts_with_prefix(argv[i], "--prefix=")) prefix = argv[i] + 9;
    }

    if (create) {
        write_str(1, "Creating temporary files and directories...\n");
        if (prefix) {
            write_str(1, "  Prefix filter: ");
            write_str(1, prefix);
            write_str(1, "\n");
        }

        /* Show standard tmpfiles.d entries being created */
        write_str(1, "  d /tmp 1777 root root 10d\n");
        write_str(1, "  d /var/tmp 1777 root root 30d\n");
        write_str(1, "  d /run/lock 0755 root root -\n");
        write_str(1, "  d /run/user/0 0700 root root -\n");
        write_str(1, "  L /var/lock - - - - ../run/lock\n");

        /* Try to actually create /tmp if it doesn't exist */
        sys_mkdir("/tmp", 0x1ff);   /* 0777 */
        sys_mkdir("/var/tmp", 0x1ff);
        sys_mkdir("/run/lock", 0x1ed); /* 0755 */
        sys_mkdir("/run/user", 0x1c0); /* 0700 */
        sys_mkdir("/run/user/0", 0x1c0);

        write_str(1, "Done. 5 entries processed.\n");
    }

    if (clean) {
        write_str(1, "Cleaning up old temporary files...\n");
        if (prefix) {
            write_str(1, "  Prefix filter: ");
            write_str(1, prefix);
            write_str(1, "\n");
        }
        write_str(1, "  Scanning /tmp (age: 10d)...\n");
        write_str(1, "  Scanning /var/tmp (age: 30d)...\n");
        write_str(1, "Done. 0 files removed.\n");
    }

    if (remove_mode) {
        write_str(1, "Removing temporary files and directories...\n");
        if (prefix) {
            write_str(1, "  Prefix filter: ");
            write_str(1, prefix);
            write_str(1, "\n");
        }
        write_str(1, "  /tmp: retained (system directory)\n");
        write_str(1, "  /var/tmp: retained (system directory)\n");
        write_str(1, "Done.\n");
    }

    if (!create && !clean && !remove_mode) {
        write_str(2, "systemd-tmpfiles: no command specified (use --create, --clean, or --remove)\n");
    }
}

/* ── at: schedule commands for later execution ── */
static void cmd_at(int argc, char *argv[]) {
    if (argc < 2) {
        write_str(2, "Usage: at <timespec>\n");
        write_str(2, "  at now + 5 minutes\n");
        write_str(2, "  at 14:30\n");
        write_str(2, "  at -l            List pending jobs\n");
        write_str(2, "  at -r <jobid>    Remove a pending job\n");
        write_str(2, "Commands are read from stdin until EOF (Ctrl+D).\n");
        return;
    }

    if (strcmp_simple(argv[1], "-l") == 0 || strcmp_simple(argv[1], "--list") == 0) {
        /* List pending at jobs from /var/spool/at/ */
        int fd = sys_open("/var/spool/at", O_RDONLY, 0);
        if (fd < 0) {
            write_str(1, "No pending jobs.\n");
            return;
        }
        struct at_dirent64 {
            unsigned long long d_ino;
            long long d_off;
            unsigned short d_reclen;
            unsigned char d_type;
            char d_name[256];
        };
        char dbuf[1024];
        long nr = sys_call3(SYS_getdents64, fd, (long)dbuf, sizeof(dbuf));
        if (nr <= 0) {
            write_str(1, "No pending jobs.\n");
            sys_close(fd);
            return;
        }
        write_str(1, "Job ID   Scheduled\n");
        write_str(1, "------   ---------\n");
        long off = 0;
        while (off < nr) {
            struct at_dirent64 *d = (struct at_dirent64 *)(dbuf + off);
            if (d->d_name[0] != '.') {
                write_str(1, d->d_name);
                write_str(1, "       queued\n");
            }
            off += d->d_reclen;
        }
        sys_close(fd);
        return;
    }

    if (strcmp_simple(argv[1], "-r") == 0 || strcmp_simple(argv[1], "-d") == 0) {
        if (argc < 3) {
            write_str(2, "at: -r requires a job ID\n");
            return;
        }
        char path[64];
        int pi = 0;
        const char *pfx = "/var/spool/at/";
        for (int i = 0; pfx[i]; i++) path[pi++] = pfx[i];
        for (int i = 0; argv[2][i] && pi < 62; i++) path[pi++] = argv[2][i];
        path[pi] = '\0';
        long rc = sys_call1(SYS_unlink, (long)path);
        if (rc < 0)
            write_str(2, "at: job not found\n");
        else
            write_str(1, "at: job removed\n");
        return;
    }

    /* Parse time specification: "now + N minutes/hours" or "HH:MM" */
    int delay_secs = 0;
    if (strcmp_simple(argv[1], "now") == 0) {
        /* at now + N minutes/hours */
        if (argc >= 4 && argv[2][0] == '+') {
            int amount = simple_atoi(argv[3]);
            if (argc >= 5) {
                if (argv[4][0] == 'm') delay_secs = amount * 60;
                else if (argv[4][0] == 'h') delay_secs = amount * 3600;
                else if (argv[4][0] == 's') delay_secs = amount;
                else delay_secs = amount * 60; /* default minutes */
            } else {
                delay_secs = amount * 60;
            }
        }
    } else {
        /* HH:MM format — schedule for that time (simplified: delay 0) */
        delay_secs = 0;
    }

    /* Read commands from stdin */
    write_str(1, "at> ");
    static char cmdbuf[2048];
    int total = 0;
    static char line[256];
    ssize_t n;
    while ((n = sys_read(0, line, sizeof(line) - 1)) > 0) {
        line[n] = '\0';
        /* Check for Ctrl+D / empty read */
        for (int i = 0; i < (int)n && total < 2046; i++)
            cmdbuf[total++] = line[i];
        write_str(1, "at> ");
    }
    cmdbuf[total] = '\0';
    write_str(1, "\n");

    if (total == 0) {
        write_str(2, "at: no commands specified\n");
        return;
    }

    /* Save job to /var/spool/at/ */
    sys_mkdir("/var/spool", 0755);
    sys_mkdir("/var/spool/at", 0755);

    /* Generate job ID from clock */
    struct { long sec; long nsec; } ts;
    sys_call2(SYS_clock_gettime, 0, (long)&ts);
    int jobid = (int)(ts.nsec % 99999) + 1;
    char jobpath[64];
    int jp = 0;
    const char *spfx = "/var/spool/at/";
    for (int i = 0; spfx[i]; i++) jobpath[jp++] = spfx[i];
    /* Convert jobid to string */
    char jstr[8]; int ji = 0;
    char jrev[8]; int jr = 0;
    int jv = jobid;
    if (jv == 0) jrev[jr++] = '0';
    while (jv > 0) { jrev[jr++] = '0' + jv % 10; jv /= 10; }
    while (jr > 0) jstr[ji++] = jrev[--jr];
    jstr[ji] = '\0';
    for (int i = 0; jstr[i] && jp < 62; i++) jobpath[jp++] = jstr[i];
    jobpath[jp] = '\0';

    int jfd = sys_open(jobpath, O_WRONLY | O_CREAT | O_TRUNC, 0644);
    if (jfd >= 0) {
        sys_write(jfd, cmdbuf, total);
        sys_close(jfd);
    }

    write_str(1, "job ");
    write_str(1, jstr);
    write_str(1, " scheduled");
    if (delay_secs > 0) {
        write_str(1, " (delay: ");
        char ds[12]; int di = 0;
        char dr[12]; int dri = 0;
        int dv = delay_secs;
        if (dv == 0) dr[dri++] = '0';
        while (dv > 0) { dr[dri++] = '0' + dv % 10; dv /= 10; }
        while (dri > 0) ds[di++] = dr[--dri];
        ds[di] = '\0';
        write_str(1, ds);
        write_str(1, "s)");
    }
    write_str(1, "\n");
}

/* ── batch: run commands when system load is low ── */
static void cmd_batch(int argc, char *argv[]) {
    /* batch is equivalent to 'at' with load-dependent scheduling */
    write_str(1, "batch: scheduling job for execution when system load permits\n");
    /* Delegate to cmd_at with "now" timespec */
    if (argc < 2) {
        char *at_argv[] = { "at", "now", NULL };
        cmd_at(2, at_argv);
    } else {
        cmd_at(argc, argv);
    }
}

/* ── pr: paginate text files with headers and page numbers ── */
static void cmd_pr(int argc, char *argv[]) {
    int page_len = 66;  /* default lines per page */
    int page_width = 72;
    const char *header = NULL;
    int num_cols = 1;
    int arg_start = 1;
    int omit_header = 0;

    /* Parse options */
    while (arg_start < argc && argv[arg_start][0] == '-') {
        if (strcmp_simple(argv[arg_start], "-h") == 0 && arg_start + 1 < argc) {
            header = argv[arg_start + 1];
            arg_start += 2;
        } else if (strcmp_simple(argv[arg_start], "-l") == 0 && arg_start + 1 < argc) {
            page_len = simple_atoi(argv[arg_start + 1]);
            if (page_len < 10) page_len = 66;
            arg_start += 2;
        } else if (strcmp_simple(argv[arg_start], "-w") == 0 && arg_start + 1 < argc) {
            page_width = simple_atoi(argv[arg_start + 1]);
            if (page_width < 10) page_width = 72;
            arg_start += 2;
        } else if (argv[arg_start][1] >= '1' && argv[arg_start][1] <= '9' && argv[arg_start][2] == '\0') {
            num_cols = argv[arg_start][1] - '0';
            arg_start++;
        } else if (strcmp_simple(argv[arg_start], "-t") == 0) {
            omit_header = 1;
            arg_start++;
        } else {
            break;
        }
    }
    (void)num_cols; /* multi-column: future enhancement */
    (void)page_width;

    /* Open input file or read from stdin */
    int fd = 0;
    const char *filename = "stdin";
    if (arg_start < argc) {
        filename = argv[arg_start];
        fd = sys_open(filename, O_RDONLY, 0);
        if (fd < 0) {
            write_str(2, "pr: cannot open "); write_str(2, filename); write_str(2, "\n");
            return;
        }
    }

    if (!header) header = filename;

    /* Read all input */
    static char fbuf[16384];
    int total = 0;
    ssize_t n;
    while ((n = sys_read(fd, fbuf + total, sizeof(fbuf) - total - 1)) > 0) {
        total += (int)n;
        if (total >= (int)sizeof(fbuf) - 1) break;
    }
    if (fd > 0) sys_close(fd);
    fbuf[total] = '\0';

    /* Split into lines */
    char *lines[4096];
    int nlines = 0;
    char *p = fbuf;
    while (*p && nlines < 4096) {
        lines[nlines++] = p;
        while (*p && *p != '\n') p++;
        if (*p == '\n') *p++ = '\0';
    }

    /* Output with page headers */
    int body_lines = page_len - 5; /* 2 header + 3 footer margin */
    if (body_lines < 1) body_lines = page_len;
    int page_num = 1;
    int line_idx = 0;

    while (line_idx < nlines) {
        if (!omit_header) {
            /* Page header */
            write_str(1, "\n\n");
            write_str(1, header);
            write_str(1, "    Page ");
            char pn[8]; int pi = 0;
            char pr2[8]; int pri = 0;
            int pv = page_num;
            if (pv == 0) pr2[pri++] = '0';
            while (pv > 0) { pr2[pri++] = '0' + pv % 10; pv /= 10; }
            while (pri > 0) pn[pi++] = pr2[--pri];
            pn[pi] = '\0';
            write_str(1, pn);
            write_str(1, "\n\n");
        }

        /* Body lines */
        int count = 0;
        while (line_idx < nlines && count < body_lines) {
            write_str(1, lines[line_idx]);
            write_str(1, "\n");
            line_idx++;
            count++;
        }

        if (!omit_header) {
            /* Footer: pad remaining lines + blank footer */
            while (count < body_lines) {
                write_str(1, "\n");
                count++;
            }
            write_str(1, "\n\n\n");
        }
        page_num++;
    }
}

/* ── ptx: produce permuted index (keyword-in-context concordance) ── */
static void cmd_ptx(int argc, char *argv[]) {
    int arg_start = 1;
    int width = 72;
    int traditional = 0; /* -t for traditional format */

    while (arg_start < argc && argv[arg_start][0] == '-') {
        if (strcmp_simple(argv[arg_start], "-w") == 0 && arg_start + 1 < argc) {
            width = simple_atoi(argv[arg_start + 1]);
            if (width < 20) width = 72;
            arg_start += 2;
        } else if (strcmp_simple(argv[arg_start], "-t") == 0) {
            traditional = 1;
            arg_start++;
        } else {
            break;
        }
    }
    (void)traditional;

    /* Open input file or read from stdin */
    int fd = 0;
    if (arg_start < argc) {
        fd = sys_open(argv[arg_start], O_RDONLY, 0);
        if (fd < 0) {
            write_str(2, "ptx: cannot open "); write_str(2, argv[arg_start]); write_str(2, "\n");
            return;
        }
    }

    /* Read all input */
    static char fbuf[16384];
    int total = 0;
    ssize_t n;
    while ((n = sys_read(fd, fbuf + total, sizeof(fbuf) - total - 1)) > 0) {
        total += (int)n;
        if (total >= (int)sizeof(fbuf) - 1) break;
    }
    if (fd > 0) sys_close(fd);
    fbuf[total] = '\0';

    /* Split into lines */
    static char *lines[2048];
    int nlines = 0;
    char *p = fbuf;
    while (*p && nlines < 2048) {
        lines[nlines++] = p;
        while (*p && *p != '\n') p++;
        if (*p == '\n') *p++ = '\0';
    }

    /* For each line, for each word, produce a KWIC entry */
    /* Format: left-context  [KEYWORD]  right-context */
    for (int li = 0; li < nlines; li++) {
        char *line = lines[li];
        int llen = 0;
        while (line[llen]) llen++;

        /* Find each word in the line */
        int wi = 0;
        while (wi < llen) {
            /* Skip whitespace */
            while (wi < llen && (line[wi] == ' ' || line[wi] == '\t')) wi++;
            if (wi >= llen) break;

            /* Start of word */
            int ws = wi;
            while (wi < llen && line[wi] != ' ' && line[wi] != '\t') wi++;
            int we = wi; /* word end (exclusive) */
            int wlen = we - ws;

            /* Skip very short words (articles, prepositions) */
            if (wlen <= 2) continue;

            /* Build KWIC line */
            /* Left context: chars before the keyword */
            int ctx_width = (width - wlen - 4) / 2;
            if (ctx_width < 0) ctx_width = 10;

            /* Right-pad left context */
            int left_start = ws - ctx_width;
            if (left_start < 0) left_start = 0;

            /* Print: spaces for alignment, left context, [KEYWORD], right context */
            /* Left context */
            int lctx_len = ws - left_start;
            int pad = ctx_width - lctx_len;
            for (int i = 0; i < pad; i++) write_char(1, ' ');
            for (int i = left_start; i < ws; i++) write_char(1, line[i]);

            /* Keyword in brackets */
            write_str(1, " [");
            for (int i = ws; i < we; i++) {
                char c = line[i];
                /* Uppercase the keyword */
                if (c >= 'a' && c <= 'z') c -= 32;
                write_char(1, c);
            }
            write_str(1, "] ");

            /* Right context */
            int right_end = we + ctx_width;
            if (right_end > llen) right_end = llen;
            for (int i = we; i < right_end; i++) write_char(1, line[i]);

            write_char(1, '\n');
        }
    }
}

/* ---- lsusb: list USB devices ---- */
static void cmd_lsusb(int argc, char *argv[]) {
    int verbose = 0;
    for (int i = 1; i < argc; i++) {
        if (strcmp_simple(argv[i], "-v") == 0) verbose = 1;
    }
    /* Try reading from /sys/bus/usb/devices first */
    int fd = sys_open("/sys/bus/usb/devices", O_RDONLY, 0);
    if (fd >= 0) {
        char buf[2048]; ssize_t n = sys_read(fd, buf, sizeof(buf)-1);
        sys_close(fd);
        if (n > 0) { buf[n] = '\0'; write_str(1, buf); return; }
    }
    /* Simulated USB device listing */
    write_str(1, "Bus 001 Device 001: ID 1d6b:0002 Linux Foundation 2.0 root hub\n");
    write_str(1, "Bus 001 Device 002: ID 0627:0001 QEMU USB Tablet\n");
    write_str(1, "Bus 002 Device 001: ID 1d6b:0003 Linux Foundation 3.0 root hub\n");
    if (verbose) {
        write_str(1, "\nBus 001 Device 001: ID 1d6b:0002 Linux Foundation 2.0 root hub\n");
        write_str(1, "  bcdUSB               2.00\n");
        write_str(1, "  bDeviceClass           9 Hub\n");
        write_str(1, "  bMaxPower              0mA\n");
        write_str(1, "\nBus 001 Device 002: ID 0627:0001 QEMU USB Tablet\n");
        write_str(1, "  bcdUSB               2.00\n");
        write_str(1, "  bDeviceClass           0\n");
        write_str(1, "  bMaxPower            100mA\n");
    }
}

/* ---- dmidecode: DMI/SMBIOS information ---- */
static void cmd_dmidecode(int argc, char *argv[]) {
    const char *type_filter = NULL;
    for (int i = 1; i < argc; i++) {
        if (strcmp_simple(argv[i], "-t") == 0 && i + 1 < argc) {
            type_filter = argv[++i];
        } else if (strcmp_simple(argv[i], "--help") == 0) {
            write_str(1, "Usage: dmidecode [-t TYPE]\n");
            write_str(1, "Types: bios, system, baseboard, processor, memory, cache\n");
            return;
        }
    }
    /* Try /sys/firmware/dmi/tables */
    int fd = sys_open("/sys/firmware/dmi/tables/smbios_entry_point", O_RDONLY, 0);
    if (fd >= 0) {
        sys_close(fd);
        write_str(1, "# dmidecode: reading from /sys/firmware/dmi/tables\n");
    }
    write_str(1, "# dmidecode 3.4\n");
    write_str(1, "Getting SMBIOS data from sysfs.\n");
    write_str(1, "SMBIOS 2.8 present.\n\n");
    if (!type_filter || strcmp_simple(type_filter, "bios") == 0) {
        write_str(1, "Handle 0x0000, DMI type 0, 24 bytes\n");
        write_str(1, "BIOS Information\n");
        write_str(1, "  Vendor: Futura OS BIOS\n");
        write_str(1, "  Version: 1.0\n");
        write_str(1, "  Release Date: 01/01/2025\n");
        write_str(1, "  ROM Size: 256 kB\n\n");
    }
    if (!type_filter || strcmp_simple(type_filter, "system") == 0) {
        write_str(1, "Handle 0x0100, DMI type 1, 27 bytes\n");
        write_str(1, "System Information\n");
        write_str(1, "  Manufacturer: Futura Project\n");
        write_str(1, "  Product Name: Futura Virtual Machine\n");
        write_str(1, "  Version: 1.0\n");
        write_str(1, "  Serial Number: FUTURA-0001\n");
        write_str(1, "  UUID: 12345678-1234-1234-1234-123456789abc\n\n");
    }
    if (!type_filter || strcmp_simple(type_filter, "processor") == 0) {
        write_str(1, "Handle 0x0400, DMI type 4, 42 bytes\n");
        write_str(1, "Processor Information\n");
        write_str(1, "  Socket Designation: CPU0\n");
        write_str(1, "  Type: Central Processor\n");
        /* Read actual CPU info if available */
        fd = sys_open("/proc/cpuinfo", O_RDONLY, 0);
        if (fd >= 0) {
            char buf[512]; ssize_t n = sys_read(fd, buf, sizeof(buf)-1);
            sys_close(fd);
            if (n > 0) {
                buf[n] = '\0';
                /* Find model name line */
                char *p = buf;
                while (*p) {
                    if (*p == 'm' && p[1] == 'o' && p[2] == 'd' && p[3] == 'e' && p[4] == 'l') {
                        char *colon = p;
                        while (*colon && *colon != ':') colon++;
                        if (*colon == ':') {
                            colon++;
                            while (*colon == ' ') colon++;
                            write_str(1, "  Version: ");
                            char *end = colon;
                            while (*end && *end != '\n') end++;
                            char saved = *end; *end = '\0';
                            write_str(1, colon);
                            *end = saved;
                            write_str(1, "\n");
                        }
                        break;
                    }
                    while (*p && *p != '\n') p++;
                    if (*p) p++;
                }
            }
        } else {
            write_str(1, "  Version: QEMU Virtual CPU\n");
        }
        write_str(1, "  Max Speed: 3000 MHz\n");
        write_str(1, "  Status: Populated, Enabled\n\n");
    }
    if (!type_filter || strcmp_simple(type_filter, "memory") == 0) {
        write_str(1, "Handle 0x1100, DMI type 17, 40 bytes\n");
        write_str(1, "Memory Device\n");
        write_str(1, "  Size: 128 MB\n");
        write_str(1, "  Type: DDR4\n");
        write_str(1, "  Speed: 2400 MT/s\n");
        write_str(1, "  Manufacturer: Futura\n\n");
    }
}

/* ---- hwinfo: hardware information summary ---- */
static void cmd_hwinfo(int argc, char *argv[]) {
    int short_mode = 0;
    for (int i = 1; i < argc; i++) {
        if (strcmp_simple(argv[i], "--short") == 0) short_mode = 1;
    }
    if (short_mode) {
        write_str(1, "cpu:\n");
        write_str(1, "                       QEMU Virtual CPU\n");
        write_str(1, "memory:\n");
        write_str(1, "                       Main Memory\n");
        write_str(1, "disk:\n");
        write_str(1, "  /dev/vda             VirtIO Block Device\n");
        write_str(1, "network:\n");
        write_str(1, "  eth0                 VirtIO Network Device\n");
        write_str(1, "graphics:\n");
        write_str(1, "  /dev/fb0             VirtIO GPU\n");
        return;
    }
    write_str(1, "============ System =============\n");
    /* Read hostname */
    int fd = sys_open("/proc/sys/kernel/hostname", O_RDONLY, 0);
    if (fd >= 0) {
        char buf[128]; ssize_t n = sys_read(fd, buf, sizeof(buf)-1);
        sys_close(fd);
        if (n > 0) { buf[n] = '\0'; write_str(1, "  Hostname: "); write_str(1, buf); }
    } else {
        write_str(1, "  Hostname: futura\n");
    }
    write_str(1, "  Hardware Class: system\n");
    write_str(1, "  Model: Futura Virtual Machine\n\n");

    write_str(1, "============ CPU ================\n");
    fd = sys_open("/proc/cpuinfo", O_RDONLY, 0);
    if (fd >= 0) {
        char buf[1024]; ssize_t n = sys_read(fd, buf, sizeof(buf)-1);
        sys_close(fd);
        if (n > 0) { buf[n] = '\0'; write_str(1, buf); }
    } else {
        write_str(1, "  Model: QEMU Virtual CPU\n");
    }
    write_str(1, "\n");

    write_str(1, "============ Memory =============\n");
    fd = sys_open("/proc/meminfo", O_RDONLY, 0);
    if (fd >= 0) {
        char buf[512]; ssize_t n = sys_read(fd, buf, sizeof(buf)-1);
        sys_close(fd);
        if (n > 0) { buf[n] = '\0'; write_str(1, buf); }
    } else {
        write_str(1, "  Memory: 128 MB\n");
    }
    write_str(1, "\n");

    write_str(1, "============ Network ============\n");
    write_str(1, "  eth0: VirtIO Ethernet\n");
    write_str(1, "  Driver: virtio_net\n\n");

    write_str(1, "============ Storage ============\n");
    write_str(1, "  /dev/vda: VirtIO Block Device\n");
    write_str(1, "  Driver: virtio_blk\n");
}

/* ---- lshw: list hardware ---- */
static void cmd_lshw(int argc, char *argv[]) {
    int short_mode = 0;
    const char *class_filter = NULL;
    for (int i = 1; i < argc; i++) {
        if (strcmp_simple(argv[i], "-short") == 0) short_mode = 1;
        else if (strcmp_simple(argv[i], "-class") == 0 && i + 1 < argc) {
            class_filter = argv[++i];
        }
    }
    if (short_mode) {
        write_str(1, "H/W path        Device     Class       Description\n");
        write_str(1, "===================================================\n");
        write_str(1, "                           system      Futura Virtual Machine\n");
        write_str(1, "/0                         bus         Motherboard\n");
        write_str(1, "/0/0                       memory      System memory\n");
        write_str(1, "/0/1                       processor   CPU\n");
        if (!class_filter || strcmp_simple(class_filter, "disk") == 0)
            write_str(1, "/0/2            /dev/vda   disk        VirtIO Block Device\n");
        if (!class_filter || strcmp_simple(class_filter, "network") == 0)
            write_str(1, "/0/3            eth0       network     VirtIO Ethernet\n");
        if (!class_filter || strcmp_simple(class_filter, "display") == 0)
            write_str(1, "/0/4            /dev/fb0   display     VirtIO GPU\n");
        return;
    }
    write_str(1, "futura\n");
    write_str(1, "    description: Computer\n");
    write_str(1, "    product: Futura Virtual Machine\n");
    write_str(1, "    width: 64 bits\n");
    if (!class_filter || strcmp_simple(class_filter, "processor") == 0) {
        write_str(1, "  *-cpu\n");
        write_str(1, "       description: CPU\n");
        write_str(1, "       product: QEMU Virtual CPU\n");
        write_str(1, "       vendor: Futura\n");
        /* Read nproc from /proc/cpuinfo */
        write_str(1, "       width: 64 bits\n");
    }
    if (!class_filter || strcmp_simple(class_filter, "memory") == 0) {
        write_str(1, "  *-memory\n");
        write_str(1, "       description: System memory\n");
        int fd = sys_open("/proc/meminfo", O_RDONLY, 0);
        if (fd >= 0) {
            char buf[256]; ssize_t n = sys_read(fd, buf, sizeof(buf)-1);
            sys_close(fd);
            if (n > 0) {
                buf[n] = '\0';
                write_str(1, "       ");
                /* Print just the MemTotal line */
                char *p = buf;
                while (*p && *p != '\n') { write_char(1, *p); p++; }
                write_str(1, "\n");
            }
        } else {
            write_str(1, "       size: 128MiB\n");
        }
    }
    if (!class_filter || strcmp_simple(class_filter, "disk") == 0) {
        write_str(1, "  *-disk\n");
        write_str(1, "       description: VirtIO Block Device\n");
        write_str(1, "       logical name: /dev/vda\n");
        write_str(1, "       capabilities: partitioned\n");
    }
    if (!class_filter || strcmp_simple(class_filter, "network") == 0) {
        write_str(1, "  *-network\n");
        write_str(1, "       description: Ethernet interface\n");
        write_str(1, "       logical name: eth0\n");
        write_str(1, "       configuration: driver=virtio_net\n");
    }
    if (!class_filter || strcmp_simple(class_filter, "display") == 0) {
        write_str(1, "  *-display\n");
        write_str(1, "       description: VGA compatible controller\n");
        write_str(1, "       logical name: /dev/fb0\n");
        write_str(1, "       configuration: driver=virtio_gpu\n");
    }
}

/* ---- sensors: hardware sensor readings ---- */
static void cmd_sensors(int argc, char *argv[]) {
    (void)argc; (void)argv;
    /* Try reading from /sys/class/thermal */
    int fd = sys_open("/sys/class/thermal/thermal_zone0/temp", O_RDONLY, 0);
    if (fd >= 0) {
        char buf[32]; ssize_t n = sys_read(fd, buf, sizeof(buf)-1);
        sys_close(fd);
        if (n > 0) {
            buf[n] = '\0';
            int temp = simple_atoi(buf);
            write_str(1, "coretemp-isa-0000\n");
            write_str(1, "Adapter: ISA adapter\n");
            char tmp[32];
            int deg = temp / 1000;
            int frac = (temp % 1000) / 100;
            int_to_str(deg, tmp, sizeof(tmp));
            write_str(1, "Core 0:        +");
            write_str(1, tmp);
            write_str(1, ".");
            int_to_str(frac, tmp, sizeof(tmp));
            write_str(1, tmp);
            write_str(1, " C  (high = +80.0 C, crit = +100.0 C)\n");
            return;
        }
    }
    /* Simulated output */
    write_str(1, "coretemp-isa-0000\n");
    write_str(1, "Adapter: ISA adapter\n");
    write_str(1, "Core 0:        +42.0 C  (high = +80.0 C, crit = +100.0 C)\n");
    write_str(1, "Core 1:        +40.0 C  (high = +80.0 C, crit = +100.0 C)\n");
    write_str(1, "\n");
    write_str(1, "acpitz-acpi-0\n");
    write_str(1, "Adapter: ACPI interface\n");
    write_str(1, "temp1:         +43.0 C  (crit = +103.0 C)\n");
    write_str(1, "\n");
    write_str(1, "fan-virtual-0\n");
    write_str(1, "Adapter: Virtual device\n");
    write_str(1, "fan1:          2800 RPM\n");
}

/* ---- acpi: ACPI information ---- */
static void cmd_acpi(int argc, char *argv[]) {
    int show_battery = 0, show_thermal = 0, show_ac = 0;
    int show_all = 1;
    for (int i = 1; i < argc; i++) {
        if (strcmp_simple(argv[i], "-b") == 0) { show_battery = 1; show_all = 0; }
        else if (strcmp_simple(argv[i], "-t") == 0) { show_thermal = 1; show_all = 0; }
        else if (strcmp_simple(argv[i], "-a") == 0) { show_ac = 1; show_all = 0; }
        else if (strcmp_simple(argv[i], "-V") == 0) { show_all = 1; }
        else if (strcmp_simple(argv[i], "--help") == 0) {
            write_str(1, "Usage: acpi [options]\n");
            write_str(1, "  -b  Show battery information\n");
            write_str(1, "  -t  Show thermal information\n");
            write_str(1, "  -a  Show AC adapter information\n");
            write_str(1, "  -V  Show all (verbose)\n");
            return;
        }
    }
    if (show_all || show_battery) {
        /* Try /sys/class/power_supply */
        int fd = sys_open("/sys/class/power_supply/BAT0/capacity", O_RDONLY, 0);
        if (fd >= 0) {
            char buf[32]; ssize_t n = sys_read(fd, buf, sizeof(buf)-1);
            sys_close(fd);
            if (n > 0) {
                buf[n] = '\0';
                write_str(1, "Battery 0: ");
                write_str(1, buf);
                write_str(1, "%\n");
            }
        } else {
            write_str(1, "Battery 0: Full, 100%\n");
        }
    }
    if (show_all || show_thermal) {
        int fd = sys_open("/sys/class/thermal/thermal_zone0/temp", O_RDONLY, 0);
        if (fd >= 0) {
            char buf[32]; ssize_t n = sys_read(fd, buf, sizeof(buf)-1);
            sys_close(fd);
            if (n > 0) {
                buf[n] = '\0';
                int temp = simple_atoi(buf);
                char tmp[32];
                int_to_str(temp / 1000, tmp, sizeof(tmp));
                write_str(1, "Thermal 0: ok, ");
                write_str(1, tmp);
                write_str(1, ".0 degrees C\n");
            }
        } else {
            write_str(1, "Thermal 0: ok, 43.0 degrees C\n");
        }
    }
    if (show_all || show_ac) {
        write_str(1, "AC Adapter 0: on-line\n");
    }
}

/* ---- udevadm: udev device manager ---- */
static void cmd_udevadm(int argc, char *argv[]) {
    if (argc < 2) {
        write_str(1, "Usage: udevadm <command> [options]\n");
        write_str(1, "Commands:\n");
        write_str(1, "  info [--name=DEVICE]   - Query device information\n");
        write_str(1, "  monitor                - Monitor udev events\n");
        write_str(1, "  trigger                - Request device events from the kernel\n");
        write_str(1, "  settle                 - Wait for pending udev events\n");
        return;
    }
    if (strcmp_simple(argv[1], "info") == 0) {
        const char *devname = NULL;
        for (int i = 2; i < argc; i++) {
            /* Check for --name=X */
            const char *p = argv[i];
            if (p[0] == '-' && p[1] == '-' && p[2] == 'n' && p[3] == 'a' && p[4] == 'm' && p[5] == 'e' && p[6] == '=') {
                devname = p + 7;
            } else if (strcmp_simple(argv[i], "--name") == 0 && i + 1 < argc) {
                devname = argv[++i];
            } else {
                devname = argv[i];
            }
        }
        if (!devname) devname = "/dev/vda";
        write_str(1, "P: /devices/pci0000:00/0000:00:01.0/virtio0/block/");
        /* Extract basename */
        const char *base = devname;
        const char *s = devname;
        while (*s) { if (*s == '/') base = s + 1; s++; }
        write_str(1, base);
        write_str(1, "\n");
        write_str(1, "N: ");
        write_str(1, base);
        write_str(1, "\n");
        write_str(1, "S: disk/by-path/pci-0000:00:01.0-virtio-pci\n");
        write_str(1, "E: DEVNAME=/dev/");
        write_str(1, base);
        write_str(1, "\n");
        write_str(1, "E: DEVTYPE=disk\n");
        write_str(1, "E: SUBSYSTEM=block\n");
        write_str(1, "E: ID_VENDOR=virtio\n");
        write_str(1, "E: ID_MODEL=VirtIO_Block\n");
    } else if (strcmp_simple(argv[1], "monitor") == 0) {
        write_str(1, "monitor will print the received events for:\n");
        write_str(1, "UDEV - the event which udev sends out after rule processing\n");
        write_str(1, "KERNEL - the kernel uevent\n\n");
        write_str(1, "KERNEL[1.234567] add      /devices/pci0000:00/0000:00:01.0 (pci)\n");
        write_str(1, "KERNEL[1.234890] add      /devices/pci0000:00/0000:00:01.0/virtio0 (virtio)\n");
        write_str(1, "UDEV  [1.235012] add      /devices/pci0000:00/0000:00:01.0 (pci)\n");
        write_str(1, "UDEV  [1.235234] add      /devices/pci0000:00/0000:00:01.0/virtio0 (virtio)\n");
    } else if (strcmp_simple(argv[1], "trigger") == 0) {
        write_str(1, "udevadm trigger: requesting device events from kernel\n");
    } else if (strcmp_simple(argv[1], "settle") == 0) {
        write_str(1, "udevadm settle: all pending events processed\n");
    } else {
        write_str(2, "udevadm: unknown command '");
        write_str(2, argv[1]);
        write_str(2, "'\n");
    }
}

/* ---- blkzone: block device zone operations ---- */
static void cmd_blkzone(int argc, char *argv[]) {
    if (argc < 2) {
        write_str(1, "Usage: blkzone <command> [options] <device>\n");
        write_str(1, "Commands:\n");
        write_str(1, "  report [device]  - Report zone information\n");
        write_str(1, "  reset  [device]  - Reset write pointer of zones\n");
        write_str(1, "  open   [device]  - Explicitly open zones\n");
        write_str(1, "  close  [device]  - Close zones\n");
        write_str(1, "  finish [device]  - Finish zones\n");
        return;
    }
    const char *device = (argc > 2) ? argv[2] : "/dev/vda";
    if (strcmp_simple(argv[1], "report") == 0) {
        write_str(1, "  start: 0x000000000, len 0x080000, cap 0x080000, wptr 0x000000 reset:0 non-seq:0, zcond: 1(em) [type: 2(SEQ_WRITE_REQUIRED)]\n");
        write_str(1, "  start: 0x000080000, len 0x080000, cap 0x080000, wptr 0x000000 reset:0 non-seq:0, zcond: 1(em) [type: 2(SEQ_WRITE_REQUIRED)]\n");
        write_str(1, "  start: 0x000100000, len 0x080000, cap 0x080000, wptr 0x000000 reset:0 non-seq:0, zcond: 1(em) [type: 2(SEQ_WRITE_REQUIRED)]\n");
        write_str(1, "  start: 0x000180000, len 0x080000, cap 0x080000, wptr 0x000000 reset:0 non-seq:0, zcond: 1(em) [type: 2(SEQ_WRITE_REQUIRED)]\n");
    } else if (strcmp_simple(argv[1], "reset") == 0) {
        write_str(1, "blkzone: reset zones on ");
        write_str(1, device);
        write_str(1, ": Operation completed\n");
    } else if (strcmp_simple(argv[1], "open") == 0) {
        write_str(1, "blkzone: open zones on ");
        write_str(1, device);
        write_str(1, ": Operation completed\n");
    } else if (strcmp_simple(argv[1], "close") == 0) {
        write_str(1, "blkzone: close zones on ");
        write_str(1, device);
        write_str(1, ": Operation completed\n");
    } else if (strcmp_simple(argv[1], "finish") == 0) {
        write_str(1, "blkzone: finish zones on ");
        write_str(1, device);
        write_str(1, ": Operation completed\n");
    } else {
        write_str(2, "blkzone: unknown command '");
        write_str(2, argv[1]);
        write_str(2, "'\n");
    }
}

/* ---- nvme: NVMe management ---- */
